-- Poems batch 129
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('9dbcbfd0-072e-4300-bb04-fad4204793e0','題湘中館二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','江欲浮秋去，山能渡水來。',48,'全唐诗/poet.song.138000.json','["江欲浮秋去，山能渡水來。", "娵隅蠻語雜，欵乃楚聲哀。", "寒早當緣閏，詩成未費才。", "愁邊正無奈，歡伯一相開。"]'),
('a53ce09a-5f39-494b-8eb0-110671d7c299','送施少才赴試南宮二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','我豈登名晚，今仍作吏卑。',48,'全唐诗/poet.song.138000.json','["我豈登名晚，今仍作吏卑。", "文能追古作，子未要人知。", "取第真成漫，危言良獨奇。", "新知誰不樂，所要白頭期。"]'),
('0e178bca-af44-4fe3-a98b-3f52f0643490','送施少才赴試南宮二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','十日九奔命，同行半倦游。',48,'全唐诗/poet.song.138000.json','["十日九奔命，同行半倦游。", "出城愁不早，思子悔何由。", "脚底已衡嶽，眼中猶橘洲。", "似嫌疎過子，吾過更誰尤。"]'),
('e31acf86-79bf-4d32-888e-291364b2fac5','野菊','楊萬里','宋','宋诗','song-poetry','','[]','未與騷人當糗糧，況隨流俗作重陽。',64,'全唐诗/poet.song.138000.json','["未與騷人當糗糧，況隨流俗作重陽。", "政緣在野有幽色，肯爲無人減妙香。", "已晚相逢半山碧，便忙也折一枝黄。", "花應冷笑東籬族，猶向陶翁覓寵光。"]'),
('d9806b29-3486-4a55-8e1b-fa305447b399','衡山值雨','楊萬里','宋','宋诗','song-poetry','','["\u8861\u5c71"]','稍喜歸塗中半程，猶愁泥潦未知晴。',32,'全唐诗/poet.song.138000.json','["稍喜歸塗中半程，猶愁泥潦未知晴。", "雨來也不憐行客，風過何須作許聲。"]'),
('de5bccec-d1fb-47ce-935a-a0d2ffc6bed1','至永州城外','楊萬里','宋','宋诗','song-poetry','','[]','戀戀庭闈竟北征，槐花喚我試諸生。',64,'全唐诗/poet.song.138000.json','["戀戀庭闈竟北征，槐花喚我試諸生。", "了知歸近猶看堠，更有愁來即入城。", "愚水端能勤入夢，崳峯何得嬾相迎。", "只應白髮持環久，見我跫然笑未成。"]'),
('9e477398-a7be-47fc-af9d-d083f4e2ab75','寄別何運判德獻移閩憲二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','再歲三移節，千山一據鞍。',48,'全唐诗/poet.song.138000.json','["再歲三移節，千山一據鞍。", "梅花錦囊古，霜月繡衣寒。", "民欲刑幾措，公於此豈難。", "誰令清廟器，未著侍臣冠。"]'),
('8a57f49a-22cd-47c7-ae74-1902b78adffb','寄別何運判德獻移閩憲二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','薄技工奚取，知音一已多。',48,'全唐诗/poet.song.138000.json','["薄技工奚取，知音一已多。", "從公日幾許，去我意如何。", "夢裏閩山月，吟邊楚水波。", "門闌萬珠履，更試歲寒柯。"]'),
('802aa495-dead-4077-b812-805ed0d56cbd','視旱憩鏡田店','楊萬里','宋','宋诗','song-poetry','','[]','走檄堪頻捧，嚴程敢少徐。',48,'全唐诗/poet.song.138000.json','["走檄堪頻捧，嚴程敢少徐。", "雖晴恐非久，猶熱未全無。", "憩息翻增倦，馳驅減壯圖。", "詩成兼利害，失悶得清臞。"]'),
('096fbb10-6b17-4e3e-84b0-c52f3c9bfdef','視旱過雨','楊萬里','宋','宋诗','song-poetry','','[]','已旱何秋雨，無禾始水聲。',48,'全唐诗/poet.song.138000.json','["已旱何秋雨，無禾始水聲。", "病民豈天意，致此定誰生。", "湯爪寧須翦，桑羊可緩烹。", "小儒空自嘆，得到鳳凰城。"]'),
('ca774c83-4ea6-4c32-a3f3-d7e633044d28','水西野店皆不著宿夜抵石山虛','楊萬里','宋','宋诗','song-poetry','','[]','不著官人宿，無如野店何。',48,'全唐诗/poet.song.138000.json','["不著官人宿，無如野店何。", "見容幸有此，雖陋更嫌它。", "頭蝨妨歸夢，鄰雞伴寤歌。", "此生眠食爾，行路總蹉跎。"]'),
('25f2c54f-18ed-42b3-8fae-b06d27bc0576','明發石山','楊萬里','宋','宋诗','song-poetry','','[]','明發愁仍集，寒雲又作屯。',48,'全唐诗/poet.song.138000.json','["明發愁仍集，寒雲又作屯。", "懸知今定雨，正坐夜來暄。", "便恐禾生耳，寧論客斷魂。", "山深更須入，聞有早梅村。"]'),
('645efea6-fe59-4494-8a4c-f02a60924531','涉小溪宿淡山','楊萬里','宋','宋诗','song-poetry','','[]','徑仄愁斜步，溪深怯正看。',48,'全唐诗/poet.song.138000.json','["徑仄愁斜步，溪深怯正看。", "破船能不渡，晴色敢辭寒。", "白退山雲細，青還玉宇寬。", "險艱明已濟，魂夢未渠安。"]'),
('07ce75fd-1b88-4573-bdcf-9a6739bd5f24','題龍歸寺壁','楊萬里','宋','宋诗','song-poetry','','[]','題字纔前歲，衝寒又此行。',48,'全唐诗/poet.song.138000.json','["題字纔前歲，衝寒又此行。", "竹能知雨至，窗不隔江清。", "走檄還曾了，禁人未肯晴。", "息肩更須喜，問路可憐生。"]'),
('13979d23-1a0c-47a0-9cf3-fd33bed61b46','董主簿正道壁間作水墨老梅一枝宿鵲縮脰合半眼栖焉','楊萬里','宋','宋诗','song-poetry','','[]','斜枝飽風雪，疎花淡冰玉。',24,'全唐诗/poet.song.138000.json','["斜枝飽風雪，疎花淡冰玉。", "一鵲忍清寒，居然伴幽獨。"]'),
('5605a651-c918-4e29-a90b-51b5afbaea63','普明寺見梅','楊萬里','宋','宋诗','song-poetry','','[]','城中忙失探梅期，初見僧窗一兩枝。',64,'全唐诗/poet.song.138000.json','["城中忙失探梅期，初見僧窗一兩枝。", "猶喜相看那恨晚，故應更好半開時。", "今冬不雪何關事，作伴孤芳却欠伊。", "月落山空正幽獨，慰存無酒且新詩。"]'),
('a2a3b548-4b33-4454-98a8-824ef47469fc','寄周子充察院二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','鄉者豺當路，如今虎在山。',48,'全唐诗/poet.song.138000.json','["鄉者豺當路，如今虎在山。", "百年諸老盡，一段好風還。", "誰謂永嘉末，人猶慶曆間。", "班心公定可，更可押廷班。"]'),
('eb16edf6-253b-4baa-b8e3-227b483c2cdf','寄周子充察院二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','跡遠公猶記，情親勢使疎。',48,'全唐诗/poet.song.138000.json','["跡遠公猶記，情親勢使疎。", "忽思參研席，如許遽龍豬。", "雲步知無那，文盟肯棄予。", "只哦五箇字，不愈一行書。"]'),
('2a62baf4-0a01-4d4b-b4a4-abf48f83465b','自音聲巖泛小舟下高溪','楊萬里','宋','宋诗','song-poetry','','[]','晚日黄猶暖，寒江白更清。',48,'全唐诗/poet.song.138000.json','["晚日黄猶暖，寒江白更清。", "遠山衝岸出，釣艇背人行。", "舟穩何妨小，波恬爾許平。", "大魚不相報，撥剌得吾驚。"]'),
('1e83178a-947c-4598-8871-fabe92830db0','臘夜普明寺睡覺二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','旅夢忘爲客，簷聲忽喚愁。',48,'全唐诗/poet.song.138000.json','["旅夢忘爲客，簷聲忽喚愁。", "親庭未差遠，佛屋不勝秋。", "只麽功名是，如今悟解不。", "十年行路飽，誰不遣吾休。"]'),
('3ad77086-bfd4-430e-b165-b0c7fb9cb6b1','臘夜普明寺睡覺二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','作臘聊村酒，依人只短檠。',48,'全唐诗/poet.song.138000.json','["作臘聊村酒，依人只短檠。", "略無更可數，聽到雨無聲。", "犬吠知何苦，雞寒肯更鳴。", "生來眠不足，老去夢難成。"]'),
('6ba34af1-978d-442d-a837-36a4c94c443c','臘後二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','待臘驚還過，留年惜欲除。',48,'全唐诗/poet.song.138000.json','["待臘驚還過，留年惜欲除。", "雨纔三日有，雪更一冬無。", "遊屐妨緣濘，寒威戀爲爐。", "未須排旅悶，猶足助詩娛。"]'),
('18f4016a-d285-4416-a66d-8c6f855d83e7','臘後二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','雲暗虛疑暮，江空分外寒。',48,'全唐诗/poet.song.138000.json','["雲暗虛疑暮，江空分外寒。", "如何山雨過，便爾岸沙乾。", "奈此詩愁得，懷哉歲事闌。", "梅殘吾更忍，不折一枝看。"]'),
('db782305-3f2a-4ec4-bf87-3f665f512c93','夜坐','楊萬里','宋','宋诗','song-poetry','','[]','欲雪天還惜，不風寒自生。',48,'全唐诗/poet.song.138000.json','["欲雪天還惜，不風寒自生。", "燈摇無定影，火作始然聲。", "又遣庭闈訊，懸知骨肉情。", "履端猶幾日，有夢未歸程。"]'),
('c13f8351-caf8-44cf-a71a-f3110989b92f','東寺詩僧照上人訪予於普明寺贈以詩','楊萬里','宋','宋诗','song-poetry','','[]','故人深住白雲隈，欲到何因只寄梅。',64,'全唐诗/poet.song.138000.json','["故人深住白雲隈，欲到何因只寄梅。", "歲晚觀山吾獨立，泥中騎馬子能來。", "轉頭不覺三年別，病眼相看一笑開。", "說似少陵真句法，未應言下更空回。"]'),
('5eb2006d-520d-41dc-9b7f-27a662c62861','題照上人迎翠軒二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','寺外秋山觸眼明，寺根秋水洗心清。',32,'全唐诗/poet.song.138000.json','["寺外秋山觸眼明，寺根秋水洗心清。", "晴嵐暖翠來未了，不用高人倒屣迎。"]'),
('3461844f-2d5f-4d3f-a613-76de24eb44e2','題照上人迎翠軒二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','參寥癩可去無還，誰踏詩僧最上關。',32,'全唐诗/poet.song.138000.json','["參寥癩可去無還，誰踏詩僧最上關。", "欲具江西句中眼，猶須作禮問雲山。"]'),
('dd6038ab-4d9d-4790-9bde-5ba37e005b84','得親老家問二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','節裏難爲客，家中數有書。',48,'全唐诗/poet.song.138000.json','["節裏難爲客，家中數有書。", "慈親問歸否，意緒各何如。", "强酒那能盡，添愁不更除。", "舊來貧未仕，父子豈相疎。"]'),
('689551a3-995b-46d5-9658-33ee459451ac','得親老家問二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','濟世吾無策，迎親仕屢驚。',48,'全唐诗/poet.song.138000.json','["濟世吾無策，迎親仕屢驚。", "乾坤裂未補，簪笏達何榮。", "三徑猶須祿，羣飛不復情。", "山林早回首，詩酒且平生。"]'),
('cc404162-75c3-469c-abe9-2333d4c23a10','立春前一夕二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','春忽明朝是，冬將半夜非。',48,'全唐诗/poet.song.138000.json','["春忽明朝是，冬將半夜非。", "年華只不住，客子未能歸。", "微霰疎還密，寒簷滴又稀。", "撚鬚真浪苦，呵筆更成揮。"]'),
('403fea0c-6bb7-4bba-a830-2ead2164de28','立春前一夕二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','臘盡春還好，朝暄暮復寒。',48,'全唐诗/poet.song.138000.json','["臘盡春還好，朝暄暮復寒。", "雨晴終日異，衣著一冬難。", "生菜知無分，殘梅不用看。", "本憑書遣睡，轉更睡相干。"]'),
('bee65e51-37fd-4959-8b15-8e0f94ea0a1f','霰','楊萬里','宋','宋诗','song-poetry','','[]','雪花遣霰作前鋒，勢頗張皇欲暗空。',64,'全唐诗/poet.song.138000.json','["雪花遣霰作前鋒，勢頗張皇欲暗空。", "篩瓦巧尋疎處漏，跳階誤到暖邊融。", "寒聲带雨山難白，冷氣侵人火失紅。", "方訝一冬暄較甚，今宵敢歎卧如弓。"]'),
('c3ffb65f-901c-431a-a085-76806cdd0662','立春日有懷二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','飄蓬敢恨一年遲，客裏春光也自宜。',32,'全唐诗/poet.song.138000.json','["飄蓬敢恨一年遲，客裏春光也自宜。", "白玉青絲那得說，一杯嚥下少陵詩。"]'),
('875f3de0-66c3-4c21-8166-fc7a7d71db71','立春日有懷二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','玉堂著句轉春風，諸老從前亦寓忠。',32,'全唐诗/poet.song.138000.json','["玉堂著句轉春風，諸老從前亦寓忠。", "誰爲君王供帖子，丁寧綺語不須工。"]'),
('efe0aefb-f76c-4ba5-b094-c5c114cdda37','立春新晴','楊萬里','宋','宋诗','song-poetry','','[]','宿雲送臘曉仍開，日動江光度竹來。',64,'全唐诗/poet.song.138000.json','["宿雲送臘曉仍開，日動江光度竹來。", "春到更晴誰不喜，時遷不道老相催。", "山村敢惜身猶遠，邊地應憐戰未回。", "春鳥豈知人意緒，新聲只欲勸銜杯。"]'),
('cb7aa1d8-e035-4b41-b1e7-d639823bdfb0','晚立普明寺門時已過立春去除夕三日爾將歸有歎','楊萬里','宋','宋诗','song-poetry','','[]','蕭蕭淅淅荻花風，慘慘澹澹雲物容。',96,'全唐诗/poet.song.138000.json','["蕭蕭淅淅荻花風，慘慘澹澹雲物容。", "欲雪不雪關得儂，得歸未歸一莞中。", "年華縱留春已換，半生作客今何恨。", "夜來飛霰打僧窗，便恐雪真數尺强。", "催科不拙亦安出，吾民瀝髓不濡骨。", "邊頭犀渠未晏眠，天不雨粟地流錢。"]'),
('67330d69-49ca-4bf2-abcf-fabb264df5cf','除夕前一日歸舟夜泊曲渦市宿治平寺','楊萬里','宋','宋诗','song-poetry','','[]','江寬風緊折綿寒，灘多岸少上水船。',96,'全唐诗/poet.song.138000.json','["江寬風緊折綿寒，灘多岸少上水船。", "市何曾遠船不近，意已先到燈明邊。", "夜投古寺衝泥入，濕薪燒作蟲聲泣。", "冷窗凍筆更成眠，也勝疎篷仰見天。", "市人歌呼作時節，詩人兩膝高於頰。", "還家兒女問何如，明日此懷猶忍說。"]'),
('5a088a99-5834-4050-bef8-963471f6d31f','癸未上元後永州夜飲趙敦禮竹亭聞蛙醉吟','楊萬里','宋','宋诗','song-poetry','','[]','茅亭夜集俯萬竹，初月未光讓高燭。',96,'全唐诗/poet.song.138000.json','["茅亭夜集俯萬竹，初月未光讓高燭。", "主人酒令來無窮，恍然墮我醉鄉中。", "草間蛙聲忽三兩，似笑吾人慳酒量。", "只作蛙聽故自佳，何須更作鼓吹想。", "尚憶同登萬石亭，倚欄垂手望寒青。", "只今真到寒青裏，吾人不飲竹不喜。"]'),
('1ba66852-76a7-40a9-9637-997a1a0269e4','過百家渡四絕句  其一','楊萬里','宋','宋诗','song-poetry','','[]','出得城來事事幽，涉湘半濟值漁舟。',32,'全唐诗/poet.song.138000.json','["出得城來事事幽，涉湘半濟值漁舟。", "也知漁父趁魚急，翻著春衫不裹頭。"]'),
('ece3fd7a-1d66-407a-b036-0923e899ffea','過百家渡四絕句  其二','楊萬里','宋','宋诗','song-poetry','','[]','園花落盡路花開，白白紅紅各自媒。',32,'全唐诗/poet.song.138000.json','["園花落盡路花開，白白紅紅各自媒。", "莫問早行奇絕處，四方八面野香來。"]'),
('46dbcaba-40be-4167-a108-63ee22ba3eb3','過百家渡四絕句  其三','楊萬里','宋','宋诗','song-poetry','','[]','柳子祠前春已殘，新晴特地却春寒。',32,'全唐诗/poet.song.138000.json','["柳子祠前春已殘，新晴特地却春寒。", "疎籬不與花爲護，只爲蛛絲作網竿。"]'),
('794c1236-8170-4c0b-92de-489edd4b190c','過百家渡四絕句  其四','楊萬里','宋','宋诗','song-poetry','','[]','一晴一雨路乾濕，半淡半濃山疊重。',32,'全唐诗/poet.song.138000.json','["一晴一雨路乾濕，半淡半濃山疊重。", "遠草平中見牛背，新秧疎處有人蹤。"]'),
('c9657a1c-0a35-4098-86c8-1e87ef4af37c','武岡李簿回多問蕭判官東夫','楊萬里','宋','宋诗','song-poetry','','[]','客有來從天一隅，相逢喜問子何如。',64,'全唐诗/poet.song.138000.json','["客有來從天一隅，相逢喜問子何如。", "橘洲各自分馬首，湘水更曾烹鯉魚。", "心近人遐長作惡，離多合少可無書。", "得知安穩猶差慰，敢道韋郎跡也疎。"]'),
('62cf144e-3932-4314-b48d-573e3a4914d7','迓新守值雨','楊萬里','宋','宋诗','song-poetry','','[]','春雨不大又不晴，只與行人禁送迎。',96,'全唐诗/poet.song.138000.json','["春雨不大又不晴，只與行人禁送迎。", "小溪綠漲竟何曾，官路黄泥滑不勝。", "今年送迎乃爾苦，去年送迎正如許。", "風嚴火滅未五更，暗行十里雞三鳴。", "行路最難仍最惡，平生歷盡今更覺。", "前人失脚後人笑，後人失脚那可料。"]'),
('dff2d3a6-71f0-44b4-a667-fd4ac3cfc2a0','負丞零陵更盡而代者未至家君携老幼先歸追送出城正值泥雨萬感驟集','楊萬里','宋','宋诗','song-poetry','','[]','吾父先歸吾未可，吾母已行猶顧我。',96,'全唐诗/poet.song.138000.json','["吾父先歸吾未可，吾母已行猶顧我。", "兒女喜歸未解悲，我愁安得似兒癡。", "牆頭人看不須羨，居者那知行者嘆。", "昨日幸晴今又雨，天公管得行人苦。", "吾母病肺生怯寒，晚風鳴屋正無端。", "人家養子要作官，吾親此行誰使然。"]'),
('ed9d7aec-dd4f-4af9-b954-8f410f59f742','送別呂令聖與','楊萬里','宋','宋诗','song-poetry','','["\u897f\u6e56"]','一門三相千子孫，後有公家前諸袁。',96,'全唐诗/poet.song.138000.json','["一門三相千子孫，後有公家前諸袁。", "有治國譜無縣譜，種愛在堂銘在門。", "誰能不徼鬻爵恩，民乃不識田畝錢。", "姓名墮在諸公口，去去雲霄穩著鞭。", "三年爲寮無間然，公行何得攙吾先。", "取別當愁今更喜，定知同醉西湖蓮。"]'),
('5c6a6473-6a0a-4bf8-b45c-5df03f97f80e','和司法張仲良醉中論詩二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','醉語醒猶記，來詩讀轉新。',48,'全唐诗/poet.song.138000.json','["醉語醒猶記，來詩讀轉新。", "不緣朋好密，其奈客居貧。", "無乃陽秋誤，云何鼠朴珍。", "端令和者寡，敢以速爲神。"]'),
('266a67e4-9813-4f66-a312-ff75f9d0022f','和司法張仲良醉中論詩二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','相過寧嫌數，未行先畏辭。',48,'全唐诗/poet.song.138000.json','["相過寧嫌數，未行先畏辭。", "要寬千里別，猶費幾篇詩。", "意得翻難售，聲希只自奇。", "此生詩社裏，三折或知醫。"]'),
('fdb86dbb-4461-4d31-a075-178dc841e648','題唐德明秀才玉立齋','楊萬里','宋','宋诗','song-poetry','','[]','坡云無竹令人俗，我云俗人正累竹。',96,'全唐诗/poet.song.138000.json','["坡云無竹令人俗，我云俗人正累竹。", "玉立齋前一萬竿，能與主人相對寒。", "看竹哦詩筆生力，山童怪予遽忘食。", "不但不可一日無，斯須無此看何如。", "詩成欲寫且復歇，恐竹嫌詩未清絕。", "丁寧一竿不可除，竹亦何曾減風月。"]'),
('833dc39d-0939-4c36-8433-fc10b3b1180e','張仲良久約出郊以詩督之二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','百花亭下花如海，子厚宅前溪似油。',32,'全唐诗/poet.song.138000.json','["百花亭下花如海，子厚宅前溪似油。", "幕下風流法曹掾，坐窗猶未作遨頭。"]'),
('6c55771b-f48a-400b-bb33-316ea2854964','張仲良久約出郊以詩督之二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','只道今春不肯晴，已晴誰遣不郊行。',32,'全唐诗/poet.song.138000.json','["只道今春不肯晴，已晴誰遣不郊行。", "忍違花底提壺語，不慮屋頭鳩婦鳴。"]'),
('c66b77bb-b270-4676-9a62-c0faa8ed13e3','和仲良催看黄才叔秀才南園牡丹','楊萬里','宋','宋诗','song-poetry','','[]','愁雨留花花已闌，作晴猶喜兩朝寒。',32,'全唐诗/poet.song.138000.json','["愁雨留花花已闌，作晴猶喜兩朝寒。", "山城春事無多子，可緩黄園探牡丹。"]'),
('b8d5cd04-c83f-4682-a1cc-1503a4f4aa5b','謝唐德明惠笋','楊萬里','宋','宋诗','song-poetry','','[]','高人愛笋如愛玉，忍口不餐要添竹。',80,'全唐诗/poet.song.138000.json','["高人愛笋如愛玉，忍口不餐要添竹。", "云何又遣十輩來，昏花兩眼爲渠開。", "販夫束縛向市賣，外强中乾美安在。", "錦紋猶带落花泥，不論燒煮兩皆奇。", "豬肝累人真可怍，以笋累公端不惡。"]'),
('cbe6de29-1699-4579-b5f8-bd521dc91214','別吳教授景衡','楊萬里','宋','宋诗','song-poetry','','[]','道合從人笑，情親覺別難。',48,'全唐诗/poet.song.138000.json','["道合從人笑，情親覺別難。", "得朋何恨晚，到老幾相看。", "世路今逾窄，吾徒却自寬。", "此心各相勉，不但道加餐。"]'),
('2612d78d-dbe9-4998-a264-431ffdff7ce6','謁張安國','楊萬里','宋','宋诗','song-poetry','','[]','帝苑花穠記並遊，萬人回首看鼇頭。',64,'全唐诗/poet.song.138000.json','["帝苑花穠記並遊，萬人回首看鼇頭。", "也知旬月應顓面，已逼雲霄又作州。", "別後聞公非故我，學林著脚到前修。", "登門猶說同年話，未覺紅鸞映白鷗。"]'),
('a72b2a78-4c42-4d2a-9b0e-7f9e676cd4e0','龔令國英約小集感冷暴下歸卧感而賦焉二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','客裏何煩病，春餘不謂寒。',48,'全唐诗/poet.song.138000.json','["客裏何煩病，春餘不謂寒。", "併來無計奈，那得有懷寬。", "憎藥猶須强，耽書更暇看。", "兩親問消息，敢道不平安。"]'),
('4d0d8224-54ce-4f42-aaa1-a1b5566934b4','龔令國英約小集感冷暴下歸卧感而賦焉二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','吏卒稀仍散，僮奴野自親。',48,'全唐诗/poet.song.138000.json','["吏卒稀仍散，僮奴野自親。", "問吾適無恙，遽病此何因。", "初覺身爲客，還疑老逼人。", "焚香發深省，一笑對殘春。"]'),
('e6c6e1b4-5245-4bb3-b879-c8afd7e952a6','仲良見和再和謝焉四首  其一','楊萬里','宋','宋诗','song-poetry','','[]','未惜詩脾苦，端令鬼膽寒。',48,'全唐诗/poet.song.138000.json','["未惜詩脾苦，端令鬼膽寒。", "吾才三鼓竭，君思九江寬。", "作者今猶古，燈前捲又看。", "不辭鬚撚斷，只苦句難安。"]'),
('da527394-f75f-49e6-bac3-9bd0c18afa5f','仲良見和再和謝焉四首  其二','楊萬里','宋','宋诗','song-poetry','','[]','誰謂陳三遠，髯張下筆親。',48,'全唐诗/poet.song.138000.json','["誰謂陳三遠，髯張下筆親。", "夫何此意合，恐有宿生因。", "我豈慵開眼，年來寡見人。", "更煩彫好句，割取楚江春。"]'),
('0bcde62b-f75b-4089-bb35-8dbedf8931a3','仲良見和再和謝焉四首  其三','楊萬里','宋','宋诗','song-poetry','','[]','健論開仍闔，清規高更寒。',48,'全唐诗/poet.song.138000.json','["健論開仍闔，清規高更寒。", "抗章胡未報，憂世可能寬。", "收用今寧晚，飛鶱尚會看。", "自憐千慮短，所願一枝安。"]'),
('9e169dce-ea91-4685-9ff0-c542d9bd7030','仲良見和再和謝焉四首  其四','楊萬里','宋','宋诗','song-poetry','','[]','豈不爲寮久，茲焉獨愈親。',48,'全唐诗/poet.song.138000.json','["豈不爲寮久，茲焉獨愈親。", "卜居如不近，同志竟何因。", "山鳥頻招飲，江花解笑人。", "風顛仍雨急，枉却一年春。"]'),
('1e24e61e-99bb-421b-a6cd-a520bcb74264','晚寒','楊萬里','宋','宋诗','song-poetry','','[]','莫道今晨熱，東風未得欺。',48,'全唐诗/poet.song.138000.json','["莫道今晨熱，東風未得欺。", "晚來作惡甚，寒似禁煙時。", "約雨斜還整，吹花合且離。", "不應如許峭，故故惱吾衰。"]'),
('ee508cc0-a77f-4878-9034-6748ab5e5b22','和仲良病中耽睡','楊萬里','宋','宋诗','song-poetry','','[]','居士何曾病，羣兒錯見憐。',48,'全唐诗/poet.song.138000.json','["居士何曾病，羣兒錯見憐。", "對床正風雨，落紙忽雲煙。", "欲夏花全退，猶寒柳尚眠。", "如何睡鄉裏，只是著詩仙。"]'),
('1a1baa59-5968-4860-ac4a-8cda47cb3ce9','和仲良春晚即事五首  其一','楊萬里','宋','宋诗','song-poetry','','[]','幾許春纔好，誰令綠遽深。',48,'全唐诗/poet.song.138000.json','["幾許春纔好，誰令綠遽深。", "風光曾著眼，時序只驚心。", "永日便甘寢，羈懷怯苦吟。", "春歸猶作客，晴少更多陰。"]'),
('8cce780d-15b4-40a5-992c-021bd2564588','和仲良春晚即事五首  其二','楊萬里','宋','宋诗','song-poetry','','[]','春在已愁熱，夏來還解涼。',48,'全唐诗/poet.song.138000.json','["春在已愁熱，夏來還解涼。", "一年又如許，萬事更須忙。", "情薄忘花減，心危願歲穰。", "平生只坐嬾，何藥療嵇康。"]'),
('7ab34dc1-4006-430b-bc89-99214bacf1ae','和仲良春晚即事五首  其三','楊萬里','宋','宋诗','song-poetry','','[]','欲與東風說，休吹墮絮飛。',48,'全唐诗/poet.song.138000.json','["欲與東風說，休吹墮絮飛。", "吾行正無定，魂夢豈忘歸。", "花暖能醺眼，山濃欲染衣。", "只嫌春已老，此景也應稀。"]'),
('ef3e5c70-1f1b-4d12-b7b6-cb6faf2801f6','和仲良春晚即事五首  其四','楊萬里','宋','宋诗','song-poetry','','[]','貧難聘歡伯，病敢跨連錢。',48,'全唐诗/poet.song.138000.json','["貧難聘歡伯，病敢跨連錢。", "夢豈花邊到，春俄雨裏遷。", "一犁關五秉，百箔候三眠。", "只有書生拙，窮年墾紙田。"]'),
('e788393c-92e0-43bd-9fb5-a5299d3a48af','和仲良春晚即事五首  其五','楊萬里','宋','宋诗','song-poetry','','[]','笋改齋前路，蔬眠雨後畦。',48,'全唐诗/poet.song.138000.json','["笋改齋前路，蔬眠雨後畦。", "晴江明處動，遠樹看來齊。", "我語真彫朽，君詩妙斲泥。", "殷勤報春去，恰恰一鶑啼。"]'),
('9c0ef719-028b-4a47-9710-7fa97810156a','題潘彥政叔姪濯纓齋','楊萬里','宋','宋诗','song-poetry','','[]','愚溪之口湘江左，茅齋不小亦不大。',96,'全唐诗/poet.song.138000.json','["愚溪之口湘江左，茅齋不小亦不大。", "齋前看江江只流，江中望齋齋更幽。", "兩潘讀書韻清壯，湘妃出聽魚吹浪。", "大潘皎如鶴出林，小潘不減在沙金。", "向來姓名到天府，市人莫笑渠塵土。", "濯纓當屬最閑人，兩潘且彈冠上塵。"]'),
('58f09280-7a73-4b39-8a8a-7a91d737167d','和仲良分送柚花沉三首  其一','楊萬里','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','薰然真臘水沉片，烝以洞庭春雪花。',32,'全唐诗/poet.song.138000.json','["薰然真臘水沉片，烝以洞庭春雪花。", "只得掾曹作南董，國香未向俗人誇。"]'),
('6103f105-e6bf-4ec1-b298-3fdb72711fe8','和仲良分送柚花沉三首  其二','楊萬里','宋','宋诗','song-poetry','','[]','鋸沉百疊糝瓊英，一日三薰更九烝。',32,'全唐诗/poet.song.138000.json','["鋸沉百疊糝瓊英，一日三薰更九烝。", "却悔香成太清絕，龍涎生妬木犀憎。"]'),
('3fc96178-91a3-41eb-8d44-3ef75b1467db','和仲良分送柚花沉三首  其三','楊萬里','宋','宋诗','song-poetry','','[]','鶴骨龍筋金玉相，詩人十襲幾年藏。',32,'全唐诗/poet.song.138000.json','["鶴骨龍筋金玉相，詩人十襲幾年藏。", "已驚好手奪天巧，更遣餘芬惱楚狂。"]'),
('320957aa-5cec-43d6-ab02-3c6d93f5a416','再病書懷呈仲良四首  其一','楊萬里','宋','宋诗','song-poetry','','[]','病身誰伴亦誰憐，贏得昏昏幾覺眠。',32,'全唐诗/poet.song.138000.json','["病身誰伴亦誰憐，贏得昏昏幾覺眠。", "睡起不知身是病，踞床看盡水沉煙。"]'),
('d6946439-ecfc-46a2-aa23-05a2e7155e2c','再病書懷呈仲良四首  其二','楊萬里','宋','宋诗','song-poetry','','[]','病中嫌雨又嫌晴，自是情懷未苦平。',32,'全唐诗/poet.song.138000.json','["病中嫌雨又嫌晴，自是情懷未苦平。", "兩日雨多端不惡，市聲洗盡只簷聲。"]'),
('831adcd6-9c32-4e2c-ac99-f7c3d359a450','再病書懷呈仲良四首  其三','楊萬里','宋','宋诗','song-poetry','','[]','功名銷盡向來心，詩酒從今也不禁。',32,'全唐诗/poet.song.138000.json','["功名銷盡向來心，詩酒從今也不禁。", "夜雨遣人歸思動，不知湘水幾篙深。"]'),
('a3bc932a-5167-48c2-a271-02638178bc8f','再病書懷呈仲良四首  其四','楊萬里','宋','宋诗','song-poetry','','[]','方外詩豪張仲良，義風今日更誰雙。',32,'全唐诗/poet.song.138000.json','["方外詩豪張仲良，義風今日更誰雙。", "絕憐病客無半眼，粥飯隨宜到小窗。"]'),
('97c141fb-2d0f-496b-a647-4a1a0a7e36f1','贈蜀中相士范思齊往全州見萬先之教授','楊萬里','宋','宋诗','song-poetry','','[]','兩脚那解上金鑾，兩手只合把釣竿。',96,'全唐诗/poet.song.138000.json','["兩脚那解上金鑾，兩手只合把釣竿。", "比身管樂兒時態，已翻九河洗我肝。", "范生來自浣花里，眼中之人定誰貴。", "百鍊未必賢繞指，貴人正要老於事。", "斜風細雨又春休，落花啼鳥總春愁。", "試問談間立封侯，何如百錢挂杖頭。"]'),
('97e8511f-7483-4937-887f-34dda9a3061c','和唐德明問病二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','罷却微官且客居，庭闈不近信全疎。',32,'全唐诗/poet.song.138000.json','["罷却微官且客居，庭闈不近信全疎。", "更無竹下子唐子，誰與過逢說異書。"]'),
('53e6bb74-53da-4d55-981c-53649618dd28','和唐德明問病二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','俟命循天更不疑，朶頤那可換靈龜。',32,'全唐诗/poet.song.138000.json','["俟命循天更不疑，朶頤那可換靈龜。", "逍遥豈在榆枋外，問著扶摇總不知。"]'),
('a3b6d996-0e82-4b75-8f83-44f039c57880','又和梅雨','楊萬里','宋','宋诗','song-poetry','','[]','管得天公雨更晴，何關客子病心情。',32,'全唐诗/poet.song.138000.json','["管得天公雨更晴，何關客子病心情。", "得歸此意良不惡，且住微軀也自輕。"]'),
('4582af2b-8381-45bb-b583-9664d81254a6','又和見喜病間','楊萬里','宋','宋诗','song-poetry','','[]','初病楊花猶亂飛，即今梅子已黄稀。',64,'全唐诗/poet.song.138000.json','["初病楊花猶亂飛，即今梅子已黄稀。", "卧驚節物遽如許，起得沉緜更解肥。", "雲寺耶溪招布襪，斜風細雨欠蓑衣。", "半生不結脩門夢，只夢家山喚早歸。"]'),
('e856056b-edb4-414c-b02d-230d0c87f401','罷丞零陵忽病傷寒謁醫兩旬如負擔者日遠日重改謁唐醫公亮九日而無病矣謝以長句','楊萬里','宋','宋诗','song-poetry','','[]','料病如料敵，用藥如中的。',124,'全唐诗/poet.song.138000.json','["料病如料敵，用藥如中的。", "淮陰百戰有百勝，由基百發無一失。", "老唐脈法明更高，閲人二豎可得逃。", "探囊起死無德色，掉臂不爲曳裾客。", "但使鄉鄰少卧痾，眼底名醫麻竹多。", "嗟予詩瘦仍多病，兩旬進尺退不寸。", "逢君已晚亦未恨，掃除何曾費餘刃。", "長句藉手聊爾耳，真成不直一杯水。"]'),
('2923f630-c8c1-459c-9563-1ac3029ce83c','題黄才叔看山亭','楊萬里','宋','宋诗','song-poetry','','[]','春山華潤秋山瘦，雨山點黯晴山秀。',64,'全唐诗/poet.song.138000.json','["春山華潤秋山瘦，雨山點黯晴山秀。", "湖湘山色天下稀，零陵乃復白其眉。", "作亭不爲俗人好，箇竹把茅吾事了。", "朝來看山佳有餘，爲渠更盡一編書。"]'),
('8b035f11-56b1-4f05-aeca-386e82ad2239','送張倅','楊萬里','宋','宋诗','song-poetry','','[]','山西勁氣何曾歇，秦漢迄今幾奇傑。',80,'全唐诗/poet.song.138000.json','["山西勁氣何曾歇，秦漢迄今幾奇傑。", "張公長身鬚鬢蒼，斜飛不入鵷鷺行。", "狂卒叫讙民震擾，不勞談笑斯須了。", "皇上方披輿地圖，煩公赤手繫單于。", "捕逐虎豹公則老，坐運籌策公尚少。"]'),
('2a502e4a-e2e5-46ee-aa39-66fdaf790f55','題所寓唐德明書齋','楊萬里','宋','宋诗','song-poetry','','[]','鳬鶩行中脫病身，竹林深處得幽人。',32,'全唐诗/poet.song.138000.json','["鳬鶩行中脫病身，竹林深處得幽人。", "只言官滿渾無事，也被詩愁攪一春。"]'),
('c41c4dbe-8654-4997-a89b-a299d79547fc','白含笑','楊萬里','宋','宋诗','song-poetry','','[]','薰風曉破碧蓮莟，花意猶低白玉顔。',32,'全唐诗/poet.song.138000.json','["薰風曉破碧蓮莟，花意猶低白玉顔。", "一粲不曾容易發，清香何自遍人間。"]'),
('840feb59-1d20-4f80-bf2a-203a97fba876','題唐德明建一齋','楊萬里','宋','宋诗','song-poetry','','[]','城南前江後山趾，竹齋正對寒江啟。',64,'全唐诗/poet.song.138000.json','["城南前江後山趾，竹齋正對寒江啟。", "不嫌漁火亂書燈，只苦櫓聲驚睡美。", "平生刺頭鑽故紙，晚知此道無多子。", "從渠散漫汗牛書，笑倚江楓弄江水。"]'),
('b232e2d2-be40-4860-9fc9-1a0d5847c16d','夜離零陵以避同僚追送之勞留二絕簡諸友  其一','楊萬里','宋','宋诗','song-poetry','','[]','已坐詩臞病更羸，諸公剛欲餞湘湄。',32,'全唐诗/poet.song.138000.json','["已坐詩臞病更羸，諸公剛欲餞湘湄。", "夜浮一葉逃盟去，已被沙鷗聖得知。"]'),
('3f6548f4-2265-4475-8703-9939c2f3407e','夜離零陵以避同僚追送之勞留二絕簡諸友  其二','楊萬里','宋','宋诗','song-poetry','','[]','思歸日日只空言，一棹今真水月間。',32,'全唐诗/poet.song.138000.json','["思歸日日只空言，一棹今真水月間。", "半夜猶聞郡樓鼓，明朝應失永州山。"]'),
('962f009f-7246-41ed-a840-5ee94a90201a','泊冷水浦','楊萬里','宋','宋诗','song-poetry','','[]','前夕放船湘口步，約到衡州來日午。',64,'全唐诗/poet.song.138000.json','["前夕放船湘口步，約到衡州來日午。", "五程一減作三程，謝渠江漲半篙清。", "今日雨來三四五，又閉疎篷聽暮雨。", "長年商量泊船所，雨外青山更青處。"]'),
('305e4683-7e59-4d34-94be-e7e4ac9ad8bc','憩連嶺店','楊萬里','宋','宋诗','song-poetry','','[]','此館初明眼，前山正接眉。',48,'全唐诗/poet.song.138000.json','["此館初明眼，前山正接眉。", "熱嫌連日甚，涼惜兩朝遲。", "雨竹何其重，風鷗不自持。", "庭闈猶百里，早已豁愁思。"]'),
('e97ca729-bf93-400b-984b-d28fabe418ff','早行見螢','楊萬里','宋','宋诗','song-poetry','','[]','淺草時雙起，深叢忽獨明。',48,'全唐诗/poet.song.138000.json','["淺草時雙起，深叢忽獨明。", "情知曉月淡，意欲照人行。", "扇撲高無奈，風斜半欲橫。", "書帷吾已嬾，不擬著囊盛。"]'),
('e2761966-782b-4dc6-8f57-2338631a5d7f','和人七夕','楊萬里','宋','宋诗','song-poetry','','[]','愛月斜仍細，占星久未過。',48,'全唐诗/poet.song.138000.json','["愛月斜仍細，占星久未過。", "浪傳商用事，正苦汗成河。", "蛛喜今宵綴，蠅憎昨日多。", "吾文那乞巧，詩或擬陰何。"]'),
('d7eb4456-1705-4969-915c-a531952e89c3','送抹利花與慶長','楊萬里','宋','宋诗','song-poetry','','[]','江梅去去木犀晚，萱草石榴刺人眼。',64,'全唐诗/poet.song.138000.json','["江梅去去木犀晚，萱草石榴刺人眼。", "抹利獨立幽更佳，龍涎避香雪避花。", "朝來無熱夜涼甚，急遣山童問花信。", "一枝带雨折來歸，走送詩人覓好詩。"]'),
('07023842-4865-438e-94c7-8babe408614f','新居翦茅','楊萬里','宋','宋诗','song-poetry','','[]','小築初開一畝基，晚風散策已相宜。',32,'全唐诗/poet.song.138000.json','["小築初開一畝基，晚風散策已相宜。", "山童何急催歸去，正是涼生月上時。"]'),
('2d95d846-be42-4ecf-bb2a-155ef66489dc','讀罪己詔時有符離之潰  其一','楊萬里','宋','宋诗','song-poetry','','[]','莫讀輪臺詔，令人淚點垂。',48,'全唐诗/poet.song.138000.json','["莫讀輪臺詔，令人淚點垂。", "天乎容此虜，帝者渴非羆。", "何罪良家子，知它大將誰。", "願懲危度口，儻復雁門踦。"]'),
('5629a05b-f7e5-4dc8-acb7-1adc05bbc7c6','讀罪己詔時有符離之潰  其二','楊萬里','宋','宋诗','song-poetry','','[]','亂起吾降日，吾將强仕年。',48,'全唐诗/poet.song.138000.json','["亂起吾降日，吾將强仕年。", "中原仍夢裏，南紀且愁邊。", "陛下非常主，羣公莫自賢。", "金臺尚未築，乃至羨强燕。"]'),
('81ae369f-3ecf-47c4-89c9-847cbf56b35d','讀罪己詔時有符離之潰  其三','楊萬里','宋','宋诗','song-poetry','','[]','只道六朝窄，渠猶數百春。',48,'全唐诗/poet.song.138000.json','["只道六朝窄，渠猶數百春。", "國家祖宗澤，天地發生仁。", "歷服端傳遠，君王但側身。", "楚人要能懼，周命正惟新。"]'),
('38da0575-4f79-4c3b-a823-2e1768ab591d','題代度寺','楊萬里','宋','宋诗','song-poetry','','[]','一別重來十五年，殘僧半在寺依然。',32,'全唐诗/poet.song.138000.json','["一別重來十五年，殘僧半在寺依然。", "黄楊當日絕低小，已過危簷也可憐。"]'),
('60b407cc-2b52-4905-851a-6a8727a2ec7a','又題寺後竹亭','楊萬里','宋','宋诗','song-poetry','','[]','行盡空房忽畫欄，竹光和月入亭寒。',32,'全唐诗/poet.song.138000.json','["行盡空房忽畫欄，竹光和月入亭寒。", "壁間題字知誰句，醉把殘燈子細看。"]'),
('c90d331e-b4c2-4714-930f-7a4380bd194a','中秋前兩日別劉彥純彭仲莊於白馬山下','楊萬里','宋','宋诗','song-poetry','','[]','匆匆離合夢非夢，續續談諧眠不眠。',64,'全唐诗/poet.song.138000.json','["匆匆離合夢非夢，續續談諧眠不眠。", "莫道對床容易著，試思分手幾何年。", "長亭更放金荷淺，後夜誰同璧月圓。", "要得長隨二三友，不知由我定由天。"]'),
('2c69571b-3b4c-459f-963f-2ee57c2636b3','早發建安寺過大櫟虛','楊萬里','宋','宋诗','song-poetry','','[]','睡美那能動，朝涼强作行。',48,'全唐诗/poet.song.138000.json','["睡美那能動，朝涼强作行。", "吾方犯星起，人已趁虛聲。", "近路還如許，長途作麽生。", "兩親今正老，三釜又須營。"]'),
('160d76b0-c63d-417e-8631-201fab76c649','中秋前一夕翫月','楊萬里','宋','宋诗','song-poetry','','[]','月擬來宵好，吾先今夕遭。',48,'全唐诗/poet.song.138000.json','["月擬來宵好，吾先今夕遭。", "纔升半壁許，已復一輪高。", "遷坐明相就，羣飛影得逃。", "望秋惟有此，徹夜敢辭勞。"]'),
('adb299bf-7a47-4533-8497-5edbd88ed2c0','赴調宿白沙渡族叔文遠携酒追送走筆取別','楊萬里','宋','宋诗','song-poetry','','[]','扁舟斜纜白沙虛，欲行未發小踟躕。',64,'全唐诗/poet.song.138000.json','["扁舟斜纜白沙虛，欲行未發小踟躕。", "吾家子雲來得得，爲携碧酒買白魚。", "誼風多年冷似鐵，非公其誰主風月。", "尊前醉倒定不嗔，同來多半箇中人。"]'),
('9cedbf08-a697-4f91-ad0c-45d055de767d','醉後題壁','楊萬里','宋','宋诗','song-poetry','','[]','夜寒星斗挂屋椽，我輩把酒不問天。',32,'全唐诗/poet.song.138000.json','["夜寒星斗挂屋椽，我輩把酒不問天。", "語聲未怕驚天上，只愁驚起白鷗眠。"]'),
('a54ab969-e1f6-419b-b975-a43d7509c252','夜雨泊新淦','楊萬里','宋','宋诗','song-poetry','','[]','亂眼纔迷樹，回頭已濕沙。',48,'全唐诗/poet.song.138000.json','["亂眼纔迷樹，回頭已濕沙。", "蕭蕭打篷急，點點入船斜。", "此夕初爲客，何時却到家。", "餘樽曾卧否，喚取作生涯。"]'),
('9ee958e1-62e5-4ed3-9cce-0fc8675f9d6a','明發新淦晴快風順約泊樟鎮','楊萬里','宋','宋诗','song-poetry','','[]','雨到中宵歇，心知逗曉晴。',48,'全唐诗/poet.song.138000.json','["雨到中宵歇，心知逗曉晴。", "排雲數峰出，漏日半江明。", "風借輕帆便，天催嬾客行。", "不應樟鎮酒，無意待人傾。"]'),
('739daafa-bfdd-4039-921f-0cc2aad3f28a','泊樟鎮','楊萬里','宋','宋诗','song-poetry','','[]','北地三接淅，重來四肅霜。',48,'全唐诗/poet.song.138000.json','["北地三接淅，重來四肅霜。", "日斜秋樹轉，市散暮船忙。", "波捲清中白，霞翻紫外黄。", "汀沙渾換却，不記舊圜方。"]'),
('c344df39-f8c9-4fcf-a477-bac3738efdba','午憩堆錢嶺','楊萬里','宋','宋诗','song-poetry','','[]','蚤作難爲飯，前途又苦饑。',48,'全唐诗/poet.song.138000.json','["蚤作難爲飯，前途又苦饑。", "塵勞正未了，眠食且隨宜。", "小憩那思去，追程得更遲。", "館人只冷眼，還爲惜奔馳。"]'),
('fb4f8c05-8965-4996-a1e3-59bca441d2eb','路逢故將軍李顯忠以符離之役私其府庫士怨而潰謫居長沙','楊萬里','宋','宋诗','song-poetry','','[]','貪將如中使，兵書不誤今。',48,'全唐诗/poet.song.138000.json','["貪將如中使，兵書不誤今。", "只悲熊耳甲，誰怨褭蹄金。", "賈傅奚同郡，朱游獨折心。", "書生何處說，詩罷自長吟。"]'),
('9860f309-0823-4d3d-b46d-ab627a52de0b','宿楊塘店','楊萬里','宋','宋诗','song-poetry','','[]','吾生行路何時了，舊館重來身漸老。',64,'全唐诗/poet.song.138000.json','["吾生行路何時了，舊館重來身漸老。", "路旁松桂只十年，如今脩脩舊小小。", "昨宵宿處又雲邊，來宵還似今宵然。", "陳迹更待俛仰間，有酒不飲要稱賢。"]'),
('9aa7b266-4f58-4561-b2ce-ebcab8143032','宿長林','楊萬里','宋','宋诗','song-poetry','','[]','霧月撩人白，風燈惱客青。',24,'全唐诗/poet.song.138000.json','["霧月撩人白，風燈惱客青。", "倦多資美睡，酒薄免遲醒。"]'),
('068e0179-547e-469c-a304-adc9a1f41505','午憩東塘近白干江西地盡於此','楊萬里','宋','宋诗','song-poetry','','[]','日以秋還短，塗緣熱故長。',48,'全唐诗/poet.song.138000.json','["日以秋還短，塗緣熱故長。", "也知茅店小，奈此竹風涼。", "更遠終然到，而吾有底忙。", "欲行猶小駐，咫尺便它鄉。"]'),
('7d455a4a-01b1-4e5b-b813-ce06fc04b997','初寒','楊萬里','宋','宋诗','song-poetry','','[]','欲雨還晴又作陰，添衣已減却重尋。',32,'全唐诗/poet.song.138000.json','["欲雨還晴又作陰，添衣已減却重尋。", "絕知不晚新寒到，更用先來破客心。"]'),
('8027b1cc-13e0-4f7e-ba7c-c5ad97740545','沙溪江亭','楊萬里','宋','宋诗','song-poetry','','[]','漁舟竟日不知還，水碓無人也不閑。',32,'全唐诗/poet.song.138000.json','["漁舟竟日不知還，水碓無人也不閑。", "斫却江頭一叢柳，當愁無地著江山。"]'),
('b489777a-1723-48c6-a8a5-86173dcf00c2','宿張家店壁間有趙民則一絕句云舍策投床睡便濃覺來凉葉動西風驚秋念遠無窮意客裏知誰此夜同因次其韵','楊萬里','宋','宋诗','song-poetry','','[]','督郵不敵客愁濃，那更秋宵一笛風。',32,'全唐诗/poet.song.138000.json','["督郵不敵客愁濃，那更秋宵一笛風。", "公子何曾知許事，曠懷也解與人同。"]'),
('9479ddb6-1f79-4a14-bb0c-ad3f1fccca1c','蔣蓮店有書柳子厚寄吳武陵琴詩三讀敬哦五言','楊萬里','宋','宋诗','song-poetry','','[]','秋晴得涼行，壁閲遇佳讀。',60,'全唐诗/poet.song.138000.json','["秋晴得涼行，壁閲遇佳讀。", "已咽猶餘滋，將燼忽剩馥。", "語妙古未多，聽難今良獨。", "追誦惜去眼，信步遑擬足。", "驚心一鳥鳴，隔溪兩峰綠。"]'),
('c6257c8b-4795-493f-b1b1-38b85a4c66f1','道逢王元龜閣學','楊萬里','宋','宋诗','song-poetry','','[]','秋日纔昇却霧中，先生更去恐羣空。',64,'全唐诗/poet.song.138000.json','["秋日纔昇却霧中，先生更去恐羣空。", "古誰云遠今猶古，公亦安知世重公。", "軒冕何緣關此老，江山所過總清風。", "我行安用相逢得，不得趨隅又北東。"]'),
('aa859a41-7714-4c9c-a4b0-1a18e50c9805','宿楓平','楊萬里','宋','宋诗','song-poetry','','[]','休說江西西路行，東來骨瘦却詩清。',32,'全唐诗/poet.song.138000.json','["休說江西西路行，東來骨瘦却詩清。", "恐緣桂玉疎雲子，敢對溪山喚麴生。"]'),
('589a5143-6a56-4865-8e7e-adc0ec0c307e','發楓平','楊萬里','宋','宋诗','song-poetry','','[]','谷暗迷窗曉，山鳴報雨來。',48,'全唐诗/poet.song.138000.json','["谷暗迷窗曉，山鳴報雨來。", "畦丁絕須喜，菜甲正新栽。", "倦路愁何那，衝泥慣豈纔。", "吾詩未大好，也辱片雲催。"]'),
('ad99057e-609d-47e4-97b8-d7ef01a8e59d','過下梅','楊萬里','宋','宋诗','song-poetry','','[]','不特山盤水亦回，溪山信美暇徘徊。',32,'全唐诗/poet.song.138000.json','["不特山盤水亦回，溪山信美暇徘徊。", "行人自趁斜陽急，關得歸鴉更苦催。"]'),
('d7c1ddfb-d73b-4961-bc50-a0bc55a500b7','九日落莫憶同施少才集長沙','楊萬里','宋','宋诗','song-poetry','','[]','九月九日今朝是，五里十里正未已。',112,'全唐诗/poet.song.138000.json','["九月九日今朝是，五里十里正未已。", "良辰美景只自美，不如且著黑棋子。", "濁醪不賤有如無，黄花新寄絕交書。", "三年客裏兩重九，去年却得登高友。", "醉吟嶽麓道林間，天風吹帽挂君山。", "倒騎蹇馿下絕頂，眼花幾落賈誼井。", "如今悔狂亦嬾游，不嫌清坐獨醒休。"]'),
('5007b200-1ec8-49df-84e9-f1ace43c6f92','宿度息','楊萬里','宋','宋诗','song-poetry','','[]','薄雲翳佳月，風爲作金篦。',60,'全唐诗/poet.song.138000.json','["薄雲翳佳月，風爲作金篦。", "我行以事役，雲行亦忙爲。", "如何今夕寒，只與客子期。", "忘情豈我輩，能禁秋興悲。", "短檠不解事，喚我哦新詩。"]'),
('22c24e18-5ce4-4e16-a117-661cc389d95d','曉泊舟廟山','楊萬里','宋','宋诗','song-poetry','','[]','平水長先曉，無風也自濤。',48,'全唐诗/poet.song.138000.json','["平水長先曉，無風也自濤。", "煙昏山易遠，岸闊樹難高。", "去雁鳴相報，游魚冷總逃。", "輕寒容可忍，清眺得辭勞。"]'),
('a7554825-5d7b-4eee-a7a1-7ba5a3adda4a','到龍山頭','楊萬里','宋','宋诗','song-poetry','','[]','影靜長安道，涼風響轡銜。',48,'全唐诗/poet.song.138000.json','["影靜長安道，涼風響轡銜。", "海天低到水，江日晚明帆。", "潮遣先驅壯，聲吞絕島巉。", "黄塵征袖滿，却愧著朝衫。"]'),
('71cde543-d440-405e-bb59-3008afa434b6','見澹庵胡先生舍人','楊萬里','宋','宋诗','song-poetry','','[]','澹翁家近醉翁家，二老風流莫等差。',64,'全唐诗/poet.song.138000.json','["澹翁家近醉翁家，二老風流莫等差。", "黄帽朱耶飽煙雨，白頭紫禁判鶑花。", "補天老手何須石，行地新堤早著沙。", "三歲別公千里見，端能解榻瀹春芽。"]'),
('ed9ef7f2-dace-4503-896f-fa7c78c18fb8','爲王監簿先生求近詩','楊萬里','宋','宋诗','song-poetry','','[]','林下詩中第一仙，西風吹到日輪邊。',64,'全唐诗/poet.song.138000.json','["林下詩中第一仙，西風吹到日輪邊。", "杜陵野客還驚市，國子先生小著鞭。", "拈出老謀開宇宙，本來清尚只雲泉。", "新篇未許兒童誦，但得真傳敢浪傳。"]'),
('599126db-c92f-49ae-a3f0-d4886615f345','宿徐元達小樓','楊萬里','宋','宋诗','song-poetry','','[]','樓迥眠曾著，秋寒夜更加。',48,'全唐诗/poet.song.138000.json','["樓迥眠曾著，秋寒夜更加。", "市聲先曉動，窗月傍人斜。", "役役名和利，憧憧馬又車。", "如何泉石耳，禁得許諠譁。"]'),
('a2d1fd36-7113-4827-b27c-a9a879ef6523','贈相士蓑衣道人杜需二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','與子生疎有底仇，談間容易說封侯。',32,'全唐诗/poet.song.138000.json','["與子生疎有底仇，談間容易說封侯。", "病身更遣冰山倚，野鶴孤雲也替愁。"]'),
('c2d7272c-ad88-410c-bbf4-71dda1b32e02','贈相士蓑衣道人杜需二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','坐來小歇過眉拄，客裏那能滿眼酤。',32,'全唐诗/poet.song.138000.json','["坐來小歇過眉拄，客裏那能滿眼酤。", "肯脫蓑衣借儂著，鷗邊雨外且江湖。"]'),
('615e02bc-e4b8-4ea2-95c8-db4c9cfb62ff','跋馬公弼省幹出示山谷草聖浣花醉圖歌','楊萬里','宋','宋诗','song-poetry','','[]','涪翁浣花醉圖歌，歌詞自作復自寫。',104,'全唐诗/poet.song.138000.json','["涪翁浣花醉圖歌，歌詞自作復自寫。", "少陵無人張顛死，此翁奄有二子者。", "不論釵股與錐沙，更數旱蛟及驚蛇。", "詩仙不合兼草聖，鬼妬天嗔教薄命。", "人言愛書緣愛賢，紫眉未必勝青編。", "舊時鬼門關外客，如今一字抵尺璧，何須千載空相憶。"]'),
('b04de810-a4be-4819-999a-e8aeb482168c','送王監簿民瞻南歸','楊萬里','宋','宋诗','song-poetry','','[]','潮頭打雲雲不留，月波潑窗窗欲流。',96,'全唐诗/poet.song.138000.json','["潮頭打雲雲不留，月波潑窗窗欲流。", "夜寒報晴豈待曉，天公端爲盧溪老。", "盧溪在山不知年，盧溪出山即日還。", "黄紙苦催得高卧，青霞成癖誰能那。", "詔謂先生式國人，掉頭已復煙林深。", "路旁莫作兩疎看，老儒不用橐中金。"]'),
('4ada0c2b-6baa-4666-8e9b-f1f575fdbba3','澹庵坐上觀顯上人分茶','楊萬里','宋','宋诗','song-poetry','','[]','分茶何似煎茶好，煎茶不似分茶巧。',160,'全唐诗/poet.song.138000.json','["分茶何似煎茶好，煎茶不似分茶巧。", "蒸水老禪弄泉手，隆興元春新玉爪。", "二者相遭兔甌面，怪怪奇奇真善幻。", "紛如擘絮行太空，影落寒江能萬變。", "銀瓶首下仍尻高，注湯作字勢嫖姚。", "不須更師屋漏法，只問此瓶當響答。", "紫微仙人烏角巾，喚我起看清風生。", "京塵滿袖思一洗，病眼生花得再明。", "漢鼎難調要公理，策勳茗椀非公事。", "不如回施與寒儒，歸續茶經傳衲子。"]'),
('cd0e067b-35a9-4256-a8a5-f0f7835af8f4','謝趙茂甫惠浙曹中筆蜀越薄牋二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','公子平生無長物，几研生涯敵玉冰。',32,'全唐诗/poet.song.138000.json','["公子平生無長物，几研生涯敵玉冰。", "二妙端能并送似，便呼毛穎試谿藤。"]'),
('5c985d1d-dc4c-4ac1-891b-45aea0ed344d','謝趙茂甫惠浙曹中筆蜀越薄牋二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','百楮先生十兔尖，心知奇絕敢言貪。',32,'全唐诗/poet.song.138000.json','["百楮先生十兔尖，心知奇絕敢言貪。", "詩無好語書仍俗，喜氣多多抵得慚。"]'),
('dcf18e49-aac5-47b2-984b-0e3124760a1f','和馬公弼夜雨','楊萬里','宋','宋诗','song-poetry','','[]','一雨未辭泥至腰，新寒癘氣喜全消。',64,'全唐诗/poet.song.138000.json','["一雨未辭泥至腰，新寒癘氣喜全消。", "都人得此正希闊，遠客幡然成寂寥。", "聲在疎簷與黄葉，夢聽禁漏近丹霄。", "愁心却被詩勾引，始覺君家我里遥。"]'),
('81b5ca0f-eb9e-43f9-9ea2-e7dba48480e2','再和錯綜其韻','楊萬里','宋','宋诗','song-poetry','','[]','家書希到恐緣遥，豈有全無雁拂霄。',64,'全唐诗/poet.song.138000.json','["家書希到恐緣遥，豈有全無雁拂霄。", "屈指大刀違破鏡，負渠縮項及長腰。", "何當竹外扁舟去，趁取梅梢未雪消。", "頼有可人同舍客，破愁得句似參寥。"]'),
('3bedbe69-6bb9-4026-9e91-3d946fb6aae9','和趙彥德旅懷是夕渠誦詩鼓琴','楊萬里','宋','宋诗','song-poetry','','[]','客間眼暗可逢人，公子詩琴却有神。',64,'全唐诗/poet.song.138000.json','["客間眼暗可逢人，公子詩琴却有神。", "頻掉烏紗知得句，快揮綠綺更留塵。", "飄零不問今何夕，邂逅相歡意便親。", "作許生涯渾不惡，只愁我輩轉須貧。"]'),
('bb56acfc-c3dd-453f-b65e-f1bcab92f068','至日前思親','楊萬里','宋','宋诗','song-poetry','','[]','節近親庭遠，天寒日暮時。',24,'全唐诗/poet.song.138000.json','["節近親庭遠，天寒日暮時。", "未風窗已報，欲雪脚先知。"]'),
('da95853b-77ce-4e8c-b85b-3960b28c61f3','和湯叔度雪','楊萬里','宋','宋诗','song-poetry','','[]','道得閑來儘未閑，頗緣幽事攪心間。',64,'全唐诗/poet.song.138000.json','["道得閑來儘未閑，頗緣幽事攪心間。", "卧聽雪作披衣起，不待天明带月看。", "更覺梅枝殊摘索，只驚蓬鬢却羈單。", "飛花豈解知人意，風裏時時戲作團。"]'),
('49b9129d-6230-4ec4-8c64-16b38f07b2fa','和馬公弼雪','楊萬里','宋','宋诗','song-poetry','','[]','灑竹穿梅湖更山，客間得此未嫌寒。',64,'全唐诗/poet.song.138000.json','["灑竹穿梅湖更山，客間得此未嫌寒。", "髯疎也被輕輕點，齒冷猶禁細細餐。", "晴了還成三日凍，銷餘留得半庭看。", "憑誰說似王郎婦，鹽絮吟來總未安。"]'),
('b6e0f2ca-1c92-40a1-91e2-95fe4aa749fe','中書胡舍人玉堂夜直用萬里所和湯君雪韻和寄逆旅再和謝焉','楊萬里','宋','宋诗','song-poetry','','[]','紫禁仙人視草閑，宮雲低到綺疏間。',64,'全唐诗/poet.song.138000.json','["紫禁仙人視草閑，宮雲低到綺疏間。", "玉妃爲作回風舞，金炬高燒带笑看。", "得句却嫌椽筆小，衝泥遣慰客氈單。", "夜哦妙語鏘鸞鶴，不覺梅梢霽日團。"]'),
('5c32df0f-d6bf-477c-8241-907006258e46','和符君俞卜鄰','楊萬里','宋','宋诗','song-poetry','','[]','朱崖柳色欲春風，庾嶺梅花尚雪容。',64,'全唐诗/poet.song.138000.json','["朱崖柳色欲春風，庾嶺梅花尚雪容。", "念子南歸騎瘦馬，只今誰解好真龍。", "吾鄉端是山水窟，何日來同丘壑胸。", "白鷺青原不妨揀，誅茅結屋看何從。"]'),
('89376210-3b04-4c7d-82eb-6c988bfe5f10','引見前一夕寓宿徐元達小樓元達招符君俞胡季永小集走筆和君俞韻','楊萬里','宋','宋诗','song-poetry','','[]','主賓呼酒卷滄溟，我亦何人與德星。',64,'全唐诗/poet.song.138000.json','["主賓呼酒卷滄溟，我亦何人與德星。", "高閣連雲壓潮白，前山倒影入杯青。", "細哦秀句清無底，匹似疎梅寒更馨。", "不惜坐間作頹玉，只愁宮漏又須聽。"]'),
('1ad52e3d-0f3d-4e3c-a596-a0400f5657d6','同君俞季永步至普濟寺晚泛西湖以歸得四絕句  其一','楊萬里','宋','宋诗','song-poetry','','["\u897f\u6e56"]','閣日微陰不礙晴，杖藜小倦且須行。',32,'全唐诗/poet.song.138000.json','["閣日微陰不礙晴，杖藜小倦且須行。", "湖山有意留儂款，約束疎鐘未要聲。"]'),
('bab27c2c-1f71-4ec6-9d07-1da62f36c56a','同君俞季永步至普濟寺晚泛西湖以歸得四絕句  其二','楊萬里','宋','宋诗','song-poetry','','["\u897f\u6e56"]','煙艇橫斜柳港灣，雲山出沒柳行間。',32,'全唐诗/poet.song.138000.json','["煙艇橫斜柳港灣，雲山出沒柳行間。", "登山得似遊湖好，却是湖心看盡山。"]'),
('a5ba6067-e454-465a-a399-1b35d808a101','同君俞季永步至普濟寺晚泛西湖以歸得四絕句  其三','楊萬里','宋','宋诗','song-poetry','','["\u897f\u6e56"]','西湖雖老爲人容，不必花時十里紅。',32,'全唐诗/poet.song.138000.json','["西湖雖老爲人容，不必花時十里紅。", "卷取郭熙真水墨，枯荷折葦小霜風。"]'),
('6b1a2d00-41d2-4cc6-96fe-4c854158c8f2','同君俞季永步至普濟寺晚泛西湖以歸得四絕句  其四','楊萬里','宋','宋诗','song-poetry','','["\u897f\u6e56"]','曲曲都城繚翠微，鱗鱗湖浪動斜暉。',32,'全唐诗/poet.song.138000.json','["曲曲都城繚翠微，鱗鱗湖浪動斜暉。", "天寒日暮遊人少，兩岸輕舟星散歸。"]'),
('e382875b-1512-4f96-a365-46bccdc30e37','同岳大用甫撫幹雪後游西湖早飯顯明寺步至四聖觀訪林和靖故居觀鶴聽琴得四絕句時去除夕二日  其一','楊萬里','宋','宋诗','song-poetry','','["\u897f\u6e56"]','湖暖開冰已借春，山晴留雪要娛人。',32,'全唐诗/poet.song.138000.json','["湖暖開冰已借春，山晴留雪要娛人。", "昨遊未當清奇在，踏凍重來眼却新。"]'),
('b741b7e0-db2a-4e29-a497-6cb720eb94bd','同岳大用甫撫幹雪後游西湖早飯顯明寺步至四聖觀訪林和靖故居觀鶴聽琴得四絕句時去除夕二日  其二','楊萬里','宋','宋诗','song-poetry','','["\u897f\u6e56"]','紫陌微乾未放塵，青鞋不惜涴泥痕。',32,'全唐诗/poet.song.138000.json','["紫陌微乾未放塵，青鞋不惜涴泥痕。", "春風已入寒蒲節，殘雪猶依古柳根。"]'),
('fbd86c3c-823e-43bb-b699-22926c2ae902','同岳大用甫撫幹雪後游西湖早飯顯明寺步至四聖觀訪林和靖故居觀鶴聽琴得四絕句時去除夕二日  其三','楊萬里','宋','宋诗','song-poetry','','["\u897f\u6e56"]','冰壺底裏步金沙，真到林逋處士家。',32,'全唐诗/poet.song.138000.json','["冰壺底裏步金沙，真到林逋處士家。", "未辦寒泉薦秋菊，且將瘦句了梅花。"]'),
('c20d7713-3b3f-42f9-975a-688ff1139b87','同岳大用甫撫幹雪後游西湖早飯顯明寺步至四聖觀訪林和靖故居觀鶴聽琴得四絕句時去除夕二日  其四','楊萬里','宋','宋诗','song-poetry','','["\u897f\u6e56"]','道堂高絕俯空明，上下躋攀取意行。',32,'全唐诗/poet.song.138000.json','["道堂高絕俯空明，上下躋攀取意行。", "浄閣虛廊人寂寂，鶴聲斷處忽琴聲。"]'),
('fe8614d0-1303-45b5-8d08-13686659650e','甲申上元前聞家君不快西歸見梅有感二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','官路桐江西復西，野梅千樹壓疎籬。',32,'全唐诗/poet.song.138000.json','["官路桐江西復西，野梅千樹壓疎籬。", "昨來都下筠籃底，三百青錢買一枝。"]'),
('e6bc1c0a-b19a-4c6c-8c1b-492f2cac74a9','甲申上元前聞家君不快西歸見梅有感二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','千里來爲五斗謀，老親望望且歸休。',32,'全唐诗/poet.song.138000.json','["千里來爲五斗謀，老親望望且歸休。", "春光儘好關儂事，細雨梅花只做愁。"]'),
('16c2d253-a94a-4d36-9fe9-c57dbe57b675','晚春行田南原','楊萬里','宋','宋诗','song-poetry','','[]','西疇前日塵作霧，南村今日波生路。',96,'全唐诗/poet.song.138000.json','["西疇前日塵作霧，南村今日波生路。", "雲子從來疎廣文，衝雨學稼當辭勤。", "農言秧好殊勝麥，其如綠針未堪喫。", "吾生十指不拈泥，毛錐便得傲蓑衣。", "只願邊頭長無事，把耒耕雲且吾志。", "不愁官馬送還官，借牛騎歸不用鞍。"]'),
('441fc861-c463-49cf-8d52-f076fa0c0e4d','聞鶑','楊萬里','宋','宋诗','song-poetry','','[]','過雨溪山浄，新晴花柳明。',48,'全唐诗/poet.song.138000.json','["過雨溪山浄，新晴花柳明。", "來穿兩好樹，別作一家聲。", "故欲撩詩興，仍添懷友情。", "驚飛苦難見，那更綠陰成。"]'),
('68aa9d8b-f08f-43b9-8d46-0a3642a70dbf','初夏日出且雨','楊萬里','宋','宋诗','song-poetry','','[]','笑憶唐人句，無晴還有晴。',48,'全唐诗/poet.song.138000.json','["笑憶唐人句，無晴還有晴。", "斜陽白鷗影，疎雨子規聲。", "臺閣非吾事，溪山且此生。", "詩成何用好，詩好却難成。"]'),
('d1b52580-e0a5-43cd-a172-1a7c007bd5cd','和文遠以作醮相疎','楊萬里','宋','宋诗','song-poetry','','[]','涉夏天勤雨，今年定有秋。',48,'全唐诗/poet.song.138000.json','["涉夏天勤雨，今年定有秋。", "試思衝熱出，何似带泥遊。", "軒冕關莊子，江湖著魏牟。", "高人香火裏，也到酒邊不。"]'),
('219b5707-45e3-4a89-9f5a-71eb2b4ff924','族叔祖彥通所居宛在水中央名之曰小蓬萊爲作長句','楊萬里','宋','宋诗','song-poetry','','[]','儂愛南溪不減公，南溪親公却疎儂。',96,'全唐诗/poet.song.138000.json','["儂愛南溪不減公，南溪親公却疎儂。", "爲儂只作一兩曲，爲公繞盡雲邊屋。", "屋後有竹前有花，斷橋纔整已半斜。", "客來不惡去亦好，莫將汗脚涴瑶草。", "俗子只道無蓬萊，請渠且洗睫上埃。", "蓬萊不大亦不小，作詩示公公一笑。"]'),
('233b7437-f240-4040-ae6d-1d5d6c19a40c','彥通以詩送石菖蒲和謝之','楊萬里','宋','宋诗','song-poetry','','[]','笑拂孤芳旋汲泉，忽如身墮曉霜天。',32,'全唐诗/poet.song.138000.json','["笑拂孤芳旋汲泉，忽如身墮曉霜天。", "一生寒瘦知何用，只得清名垂萬年。"]'),
('f3e8b963-1b91-42c0-86be-1730aaf545c8','清曉出城別王宣子舍人','楊萬里','宋','宋诗','song-poetry','','[]','月細惟愁落，陽昇未要忙。',48,'全唐诗/poet.song.138000.json','["月細惟愁落，陽昇未要忙。", "出門雞未覺，夾路稻初香。", "涉世寧容嬾，侵星幸稍涼。", "病來詩久廢，覓句費商量。"]'),
('16a4e37f-7594-4f0e-b52f-4e15d91351e2','送王吉州宣子舍人知明州二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','滿聽除書好，明州勝吉州。',48,'全唐诗/poet.song.138000.json','["滿聽除書好，明州勝吉州。", "又爲邦伯去，政坐治聲優。", "過闕端能遇，居中定作留。", "新民莫漫喜，竹馬不須休。"]'),
('e7cb2d63-8aed-4c87-ba96-bf7e77c7f9f6','送王吉州宣子舍人知明州二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','碧海翻詞筆，清霜逼誼風。',48,'全唐诗/poet.song.138000.json','["碧海翻詞筆，清霜逼誼風。", "不應盛名下，未著玉堂中。", "剩欲公留此，其如帝望公。", "從今摩病眼，看到火城紅。"]'),
('5f8b403d-ad40-47a5-9f96-1d587159b441','題王宣子新作吉州學前詠歸亭','楊萬里','宋','宋诗','song-poetry','','[]','使君見處我何言，且上斯亭一笑還。',64,'全唐诗/poet.song.138000.json','["使君見處我何言，且上斯亭一笑還。", "便有醒然新氣象，何曾改却舊江山。", "詠歸風味誰知點，克己工夫未減顔。", "箇裏諸生高著眼，仕和不仕得相關。"]'),
('b2fc4fb1-bd20-46bc-9a61-707cf1454e17','夜同文遠禱雨老岡祠','楊萬里','宋','宋诗','song-poetry','','[]','秋熱常年無此例，今宵有月不能涼。',32,'全唐诗/poet.song.138000.json','["秋熱常年無此例，今宵有月不能涼。", "槁苗似妬詩人嬾，作意催成禱雨章。"]'),
('5d3fee8d-8439-4739-9bb1-9c3c5f45f110','霜露','楊萬里','宋','宋诗','song-poetry','','[]','落照紅猶剩，初星白未真。',48,'全唐诗/poet.song.138000.json','["落照紅猶剩，初星白未真。", "霜威能奪月，寒力故欺人。", "哀雁知誰怨，吟蛩獨我親。", "老來憂患裏，忍淚已霑巾。"]'),
('70a6263e-9999-4e6d-913b-1439948ebb44','理蔬','楊萬里','宋','宋诗','song-poetry','','[]','小摘吾猶惜，頻來逕自成。',48,'全唐诗/poet.song.138000.json','["小摘吾猶惜，頻來逕自成。", "青蟲捕仍有，蠹葉病還生。", "貧裏猶存竈，霜餘正可羹。", "窺園未妨學，抱甕更須營。"]'),
('534d87db-800e-4a5a-a067-ae009e24d923','送傅山人二絕句  其一','楊萬里','宋','宋诗','song-poetry','','[]','江山有約未應疎，浪自忙中白却鬚。',32,'全唐诗/poet.song.138000.json','["江山有約未應疎，浪自忙中白却鬚。", "我昔屬官今屬我，子能略伴瘦藤無。"]'),
('4c06f5a4-2a64-4d40-a396-de14c0c4b5bc','送傅山人二絕句  其二','楊萬里','宋','宋诗','song-poetry','','[]','談天渠外更誰先，聊復憐渠與酒錢。',32,'全唐诗/poet.song.138000.json','["談天渠外更誰先，聊復憐渠與酒錢。", "富貴不愁天不管，不應丘壑也關天。"]'),
('9987343f-9cb3-4f60-8880-74604338fcf1','憫農','楊萬里','宋','宋诗','song-poetry','','[]','稻雲不雨不多黄，蕎麥空花早著霜。',32,'全唐诗/poet.song.138000.json','["稻雲不雨不多黄，蕎麥空花早著霜。", "已分忍饑度殘歲，更堪歲裏閏添長。"]'),
('f2e668e0-cf80-492d-b333-cfa24facf2c4','絕句','楊萬里','宋','宋诗','song-poetry','','[]','楓老顔方少，山晴氣反昏。',24,'全唐诗/poet.song.138000.json','["楓老顔方少，山晴氣反昏。", "舊貧今更甚，已冷幸猶暄。"]'),
('021f1b5d-d40e-4a2d-8004-38019f281016','故少師張魏公挽詞三章  其一','楊萬里','宋','宋诗','song-poetry','','[]','出晝民猶望，回軍敵尚疑。',48,'全唐诗/poet.song.138000.json','["出晝民猶望，回軍敵尚疑。", "時非不吾以，天未勝人爲。", "自別知何恙，從誰話許悲。", "一生長得忌，千載却空思。"]'),
('3f8043d1-9ec1-44b6-b056-b1d05f59f0c3','故少師張魏公挽詞三章  其二','楊萬里','宋','宋诗','song-poetry','','[]','手麾日三舍，身馭月重輪。',48,'全唐诗/poet.song.138000.json','["手麾日三舍，身馭月重輪。", "始是岷峨秀，前無社稷臣。", "向來元破斧，何用更洪鈞。", "只使江淮草，明年不作春。"]'),
('c14c1409-3631-4a36-85b1-f18272eb5c1f','故少師張魏公挽詞三章  其三','楊萬里','宋','宋诗','song-poetry','','[]','讀易堂邊路，曾聞赤舄聲。',48,'全唐诗/poet.song.138000.json','["讀易堂邊路，曾聞赤舄聲。", "心從畫前到，身在易中行。", "憂國何緣壽，思親豈欲生。", "不應永州月，猶傍兩窗明。"]'),
('e3e7821e-f070-4fec-9d36-9868ef3803d8','和周仲覺三首  其一','楊萬里','宋','宋诗','song-poetry','','[]','書嬾聊遮眼，詩窮只掉頭。',48,'全唐诗/poet.song.138000.json','["書嬾聊遮眼，詩窮只掉頭。", "寒醒非不睡，薄醉奈何愁。", "火細霜還重，風停葉自投。", "半生災疾裏，誰遣未休休。"]'),
('f559562d-cd45-4f49-8e7a-13f01a458423','和周仲覺三首  其二','楊萬里','宋','宋诗','song-poetry','','[]','月淡猶明樹，霜嚴不剩雲。',48,'全唐诗/poet.song.138000.json','["月淡猶明樹，霜嚴不剩雲。", "天寒一雁叫，夜半幾人聞。", "詩只令吾瘦，清聊與子分。", "頻來仍恨少，此去更離羣。"]'),
('5044eeb5-03c3-4b13-96f5-55d80b1300cf','和周仲覺三首  其三','楊萬里','宋','宋诗','song-poetry','','[]','春在梅邊動，寒從月外來。',48,'全唐诗/poet.song.138000.json','["春在梅邊動，寒從月外來。", "貧於螢不暖，心與燭俱灰。", "此意悠悠著，從誰細細開。", "病來更憂患，淚盡只餘哀。"]'),
('88cea604-73b4-4ef1-a2c0-129c610eefdf','雪用歐陽公白戰律仍禁用映雪訪戴等故事賦三首示同社  其一','楊萬里','宋','宋诗','song-poetry','','[]','夜映非真曉，山明不覺遥。',48,'全唐诗/poet.song.138000.json','["夜映非真曉，山明不覺遥。", "儘寒無奈爽，且落未須銷。", "體怯心仍愛，顔衰酒强潮。", "毛錐自堪戰，寸鐵亦何消。"]'),
('236a8f9e-9d59-4d3d-865e-e1eb71aacf0f','雪用歐陽公白戰律仍禁用映雪訪戴等故事賦三首示同社  其二','楊萬里','宋','宋诗','song-poetry','','[]','是雨還堪拾，非花却解飛。',48,'全唐诗/poet.song.138000.json','["是雨還堪拾，非花却解飛。", "兒童最無頼，摶弄肯言歸。", "向樹翻投竹，欺人故點衣。", "肩寒未妨聳，筆凍可能揮。"]'),
('7a6c1efe-2fde-4715-8e3d-02479a830405','雪用歐陽公白戰律仍禁用映雪訪戴等故事賦三首示同社  其三','楊萬里','宋','宋诗','song-poetry','','[]','細聽無仍有，貪看立又行。',48,'全唐诗/poet.song.138000.json','["細聽無仍有，貪看立又行。", "落時晨却暗，積處夜還明。", "幸自漫山好，何如到夏清。", "似知吾黨意，未遣日華晴。"]'),
('a1ae2ef2-d3d4-4bc0-bc97-90c45c763cd5','劉公佐親家奉議挽詞二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','已病身猶健，云瘳訃却聞。',48,'全唐诗/poet.song.138000.json','["已病身猶健，云瘳訃却聞。", "告存非不壽，有子更能文。", "嗟我何多難，喪親又哭君。", "兩家兩翁好，作麽併丘墳。"]'),
('13420f69-6b04-467c-baa0-b70b02a34b08','劉公佐親家奉議挽詞二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','一命華其老，諸昆半作官。',48,'全唐诗/poet.song.138000.json','["一命華其老，諸昆半作官。", "相高仍孝悌，不但盛衣冠。", "近別那云訣，臨喪獨忍看。", "心知公不恨，我自淚難乾。"]'),
('225b103c-62bf-43bc-b405-e49c0883b286','送盧山人二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','行盡千山又萬山，山真何好子能然。',32,'全唐诗/poet.song.138000.json','["行盡千山又萬山，山真何好子能然。", "青烏縱妙儂曾問，著眼煙雲也自賢。"]'),
('dff497f6-771c-4ae4-8957-799b3a84e5a2','送盧山人二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','有欠牛眠子爲尋，剩將朽胔換華簪。',32,'全唐诗/poet.song.138000.json','["有欠牛眠子爲尋，剩將朽胔換華簪。", "家阡只免牛羊到，此外窮通得上心。"]'),
('f154baf9-41bb-4276-b046-7d75f2c10f4b','往安福宿代度寺','楊萬里','宋','宋诗','song-poetry','','[]','春前臘後暖還寒，陌上泥中濕更乾。',32,'全唐诗/poet.song.138000.json','["春前臘後暖還寒，陌上泥中濕更乾。", "野寺鳴鐘招我宿，遠峰留雪待誰看。"]'),
('9fd41af5-4157-4692-9306-82a7b739ccae','歸途轎中讀參寥詩','楊萬里','宋','宋诗','song-poetry','','[]','車中無作惟生睡，卷裏何佳却勝閑。',32,'全唐诗/poet.song.138000.json','["車中無作惟生睡，卷裏何佳却勝閑。", "會意貪看三五句，回頭悔失數重山。"]'),
('0a943c5e-920c-4114-9cbe-14c0fbfebda1','挽封州太守趙次公二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','國爾懷孤憤，麟兮嗣古風。',48,'全唐诗/poet.song.138000.json','["國爾懷孤憤，麟兮嗣古風。", "謂宜空冀北，何意召河東。", "榕葉烝山祲，梨花慘殯宮。", "傳家今有子，身後未應窮。"]'),
('1e877327-8ce9-4a48-89ea-35fd1946108d','挽封州太守趙次公二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','雁峰三徑古，融水貳車新。',48,'全唐诗/poet.song.138000.json','["雁峰三徑古，融水貳車新。", "自此相從後，還成永別晨。", "只今耆舊傳，誰是老成人。", "剩欲書遺德，心悲語不真。"]'),
('dc40c348-3b38-482d-bc10-e14b350bbeab','和元舉叔見謝載酒之韻二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','雪久自消猶半在，雨來正密更無休。',32,'全唐诗/poet.song.138000.json','["雪久自消猶半在，雨來正密更無休。", "硬黄字裏真添瘦，重碧杯中且避愁。"]'),
('f8538a6b-3af9-441c-bbf8-c5552c1b7021','和元舉叔見謝載酒之韻二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','南溪溪北北山邊，風月公何得獨專。',32,'全唐诗/poet.song.138000.json','["南溪溪北北山邊，風月公何得獨專。", "挈榼慚無桑落酒，贈詩如得漢陰鯿。"]'),
('96dc32a6-c3d6-419f-bb0e-331c2f967083','雪後晚晴四山皆青惟東山全白賦最愛東山晴後雪二絕句  其一','楊萬里','宋','宋诗','song-poetry','','[]','只知逐勝忽忘寒，小立春風夕照間。',32,'全唐诗/poet.song.138000.json','["只知逐勝忽忘寒，小立春風夕照間。", "最愛東山晴後雪，軟紅光裏湧銀山。"]'),
('e17ba7b7-5896-4dcf-993b-afc9b5a63873','雪後晚晴四山皆青惟東山全白賦最愛東山晴後雪二絕句  其二','楊萬里','宋','宋诗','song-poetry','','[]','羣山雪不到新晴，多作泥融少作冰。',32,'全唐诗/poet.song.138000.json','["羣山雪不到新晴，多作泥融少作冰。", "最愛東山晴後雪，却愁宜看不宜登。"]'),
('c0b40640-893a-4814-adac-830de3371bc8','寄題郭漢卿琴堂','楊萬里','宋','宋诗','song-poetry','','[]','著眼飛鴻外，欹巾韻磬邊。',48,'全唐诗/poet.song.138000.json','["著眼飛鴻外，欹巾韻磬邊。", "半忘今古操，豈校有無絃。", "自適何須妙，能聽也則賢。", "如何劃然裏，猶露祖生鞭。"]'),
('43d63a67-c160-4679-92b1-58f821f47120','乙酉社日偶題','楊萬里','宋','宋诗','song-poetry','','[]','愁邊節裏兩相關，茶罷呼兒檢曆看。',64,'全唐诗/poet.song.138000.json','["愁邊節裏兩相關，茶罷呼兒檢曆看。", "社日雨多晴較少，春風晚暖曉猶寒。", "也思散策郊行去，其奈緣溪路未乾。", "綠暗紅明非我事，且尋野蕨作蔬盤。"]'),
('5254a097-6680-4920-b101-4306bb544175','和昌英主簿叔社雨','楊萬里','宋','宋诗','song-poetry','','[]','愁已春相背，詩仍債未還。',48,'全唐诗/poet.song.138000.json','["愁已春相背，詩仍債未還。", "雨聲宜小睡，竹戶且深關。", "夢釣鷗邊雪，衰忘鏡裏顔。", "起來聊覓句，句在眼中山。"]'),
('4c6510b5-9298-4964-b042-3d8a0c4ab45e','送談星辰吳山人','楊萬里','宋','宋诗','song-poetry','','[]','牙籌入手風前快，玉李行天鏡裏看。',32,'全唐诗/poet.song.138000.json','["牙籌入手風前快，玉李行天鏡裏看。", "紫闥青規吾不夢，子言欲試故應難。"]'),
('665f4a53-0cc3-4931-a478-9041d14e2f2d','寒食上冢','楊萬里','宋','宋诗','song-poetry','','["\u601d\u5ff5", "\u6e05\u660e", "\u5199\u666f", "\u5bd2\u98df\u8282"]','逕直夫何細，橋危可免扶。',48,'全唐诗/poet.song.138000.json','["逕直夫何細，橋危可免扶。", "遠山楓外淡，破屋麥邊孤。", "宿草春風又，新阡去歲無。", "梨花自寒食，時節只愁予。"]'),
('d5435f75-9c96-4ece-8dfa-7bef83cd8579','和昌英主簿叔送花','楊萬里','宋','宋诗','song-poetry','','[]','去歲歸時正牡丹，親庭上壽撚花看。',64,'全唐诗/poet.song.138000.json','["去歲歸時正牡丹，親庭上壽撚花看。", "共知春好毋虛擲，更復盃深肯剩殘。", "誰料今茲千萬感，强從叔也兩相寬。", "風顛雨急關儂事，時序撩人只暗嘆。"]'),
('0ce5116a-e500-46aa-9870-4e4e60270889','和蕭伯振見贈','楊萬里','宋','宋诗','song-poetry','','[]','愁裏真成日似年，嬾邊覓句此何緣。',64,'全唐诗/poet.song.138000.json','["愁裏真成日似年，嬾邊覓句此何緣。", "雨荒山谷江西社，苔卧曹瞞臺底甎。", "頓有珠璣開病眼，旋生羽翼欲俱仙。", "車斜韻險難爲繼，聊復酬公莫浪傳。"]'),
('ab2d87b4-0328-4aee-8bd8-7bba0b7408ce','春晚往永和','楊萬里','宋','宋诗','song-poetry','','[]','春事已如許，山居殊未知。',48,'全唐诗/poet.song.138000.json','["春事已如許，山居殊未知。", "綠光風度麥，白碎日翻池。", "景好懷翻惡，人嬉我獨悲。", "郊行聊著眼，興到漫成詩。"]'),
('85e87428-41b2-4072-8914-4fd6445e0db8','轎中風翻書卷','楊萬里','宋','宋诗','song-poetry','','[]','挾冊登車强出山，展來未讀眼先昏。',32,'全唐诗/poet.song.138000.json','["挾冊登車强出山，展來未讀眼先昏。", "無端又被春風妬，葉葉吹開更揭翻。"]'),
('30fc45c6-4af4-4476-b030-ade6c86eb240','農家嘆','楊萬里','宋','宋诗','song-poetry','','[]','兩月春霖三日晴，久寒初暖稍秧青。',32,'全唐诗/poet.song.138000.json','["兩月春霖三日晴，久寒初暖稍秧青。", "春工只要花遲著，愁損農家管得星。"]'),
('aa35ce51-4f62-4ea6-b8e2-988c0beaf7fc','三江小渡','楊萬里','宋','宋诗','song-poetry','','["\u53e4\u8bd7\u4e09\u767e\u9996", "\u9001\u522b", "\u5b8b\u8bd7", "\u53cb\u60c5", "\u5199\u666f"]','溪水將橋不復回，小舟猶倚短篙開。',32,'全唐诗/poet.song.138000.json','["溪水將橋不復回，小舟猶倚短篙開。", "交情得似山溪渡，不管風波去又來。"]'),
('1b2fcdb0-17b9-484e-9003-bf5919c8138c','薄晚絕句二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','春氣吹人不作醒，病身感物底心情。',32,'全唐诗/poet.song.138000.json','["春氣吹人不作醒，病身感物底心情。", "斜陽也不藏人老，偏照霜髭一兩莖。"]'),
('84f21d4f-1570-4bbf-9e89-1625cd261fe6','薄晚絕句二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','暫出嫌喧可得除，漫游久廢未全無。',32,'全唐诗/poet.song.139000.json','["暫出嫌喧可得除，漫游久廢未全無。", "路逢鹽裹知城近，店有雞聲覺日晡。"]'),
('b72ebd37-0107-4c8a-a1be-0e19801d0021','與主簿叔蔬飲聯句','楊萬里','宋','宋诗','song-poetry','','[]','蕨含春味紫如椽，酒入春風浪似山。',32,'全唐诗/poet.song.139000.json','["蕨含春味紫如椽，酒入春風浪似山。", "未信乾坤非細物，小吞螺浦半杯間。"]'),
('f5628651-839a-4e50-869b-2e963869fd0b','永和遇風','楊萬里','宋','宋诗','song-poetry','','[]','未嫌春晚不多花，只愛青原綠似瓜。',64,'全唐诗/poet.song.139000.json','["未嫌春晚不多花，只愛青原綠似瓜。", "剩欲開懷納巖壑，可堪病眼著風沙。", "待船小立看鷗沒，倚杖微吟儘帽斜。", "客裏更無詩遣悶，不愁兩鬢不成華。"]'),
('98622bd2-073b-4597-a23c-b05122bc4864','金罌花聯句','楊萬里','宋','宋诗','song-poetry','','[]','兩日風狂雨更顛，取將暖去正衣單。',32,'全唐诗/poet.song.139000.json','["兩日風狂雨更顛，取將暖去正衣單。", "金罌花發關誰事，何用夜來如許寒。"]'),
('dfa0c8e9-2137-48e1-9703-432c55cdccd4','彥通叔祖約游雲水寺二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','出門天色陰晴半，著雨途間進退難。',32,'全唐诗/poet.song.139000.json','["出門天色陰晴半，著雨途間進退難。", "知得招提在何許，只憑田父指林間。"]'),
('a83e5dfe-0c9a-411f-935c-35104168efc2','彥通叔祖約游雲水寺二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','竹深草長綠冥冥，有路如無又斷行。',32,'全唐诗/poet.song.139000.json','["竹深草長綠冥冥，有路如無又斷行。", "風亦恐吾愁寺遠，殷勤隔雨送鐘聲。"]'),
('049554d3-c941-4be7-b209-c652ae021fb3','和昌英主簿叔久雨','楊萬里','宋','宋诗','song-poetry','','[]','積雨今晨也解休，殷勤日脚傍花流。',64,'全唐诗/poet.song.139000.json','["積雨今晨也解休，殷勤日脚傍花流。", "半明衣桁烘梅潤，全爲農家放麥秋。", "更著好風墮清句，不知何地頓閑愁。", "新晴佳處無人會，隔柳一聲黄栗留。"]'),
('2ec1ba2c-8a4b-42f1-ab30-c95e2655a2e1','憫旱','楊萬里','宋','宋诗','song-poetry','','[]','鳴鳩喚雨知喚晴，水車夜啼聲徹明。',136,'全唐诗/poet.song.139000.json','["鳴鳩喚雨知喚晴，水車夜啼聲徹明。", "乖龍嬾睡未渠醒，阿香推熱呼不應。", "下田半濕高全坼，幼秧欲焦老差碧。", "書生所向便四壁，賣漿逢寒步逢棘。", "還家浪作飽飯謀，買田三歲兩無秋。", "一門手指百二十，萬斛量不盡窮愁。", "小兒察我慘不樂，旋沽村酒聊相酌。", "更哦子美醉時歌，焉知餓死填溝壑。", "水車啞啞止復作。"]'),
('63f2664d-5c20-4478-9b1c-32412da89860','和蕭伯振禱雨','楊萬里','宋','宋诗','song-poetry','','[]','雲氣微昇又霍然，虛疑數點長三川。',64,'全唐诗/poet.song.139000.json','["雲氣微昇又霍然，虛疑數點長三川。", "渚東秔稻今無雨，社曲桑麻莫問天。", "餓死何愁更平糴，野夫半去只荒田。", "未辭託命長鑱柄，黄獨那能支一年。"]'),
('48c8c325-0719-43ac-afbe-cedd562e0883','旱後郴寇又作','楊萬里','宋','宋诗','song-poetry','','[]','自憐秋蝶生不早，只與夜蛩聲共悲。',64,'全唐诗/poet.song.139000.json','["自憐秋蝶生不早，只與夜蛩聲共悲。", "眼邊未覺天地寬，身後更用文章爲。", "去秋今夏旱相繼，淮江未浄郴江沸。", "餓夫相語死不愁，今年官免和糴不。"]'),
('7658c076-82d6-442d-9ed8-44ebaf8b6bc7','旱後喜雨四首  其一','楊萬里','宋','宋诗','song-poetry','','[]','雲頭造次便能開，雨脚商量半欲來。',32,'全唐诗/poet.song.139000.json','["雲頭造次便能開，雨脚商量半欲來。", "舊日催詩元要雨，如今雨却索詩催。"]'),
('4683d64e-9ff0-451a-a289-be95a9ccdf80','旱後喜雨四首  其二','楊萬里','宋','宋诗','song-poetry','','[]','檢校西疇首忍回，雨佳小恨較遲來。',32,'全唐诗/poet.song.139000.json','["檢校西疇首忍回，雨佳小恨較遲來。", "抄雲淅玉何曾夢，只擬禾孫作粥材。"]'),
('79b7e24c-13f7-453b-a130-26ea3b2ee8ae','旱後喜雨四首  其三','楊萬里','宋','宋诗','song-poetry','','[]','竟夏興雲只苦風，入秋今雨稍宜農。',32,'全唐诗/poet.song.139000.json','["竟夏興雲只苦風，入秋今雨稍宜農。", "怪來霹靂轟枯樹，知向前山起卧龍。"]'),
('6ce26878-2428-43a1-9ced-5ff03613a23b','旱後喜雨四首  其四','楊萬里','宋','宋诗','song-poetry','','[]','密灑疎飄儘自由，通宵到曉未須休。',32,'全唐诗/poet.song.139000.json','["密灑疎飄儘自由，通宵到曉未須休。", "平生愁聽芭蕉雨，何事今來聽不愁。"]'),
('61c1f617-7de6-41b3-b90a-dc908bc06efd','秋日見橘花二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','花浄何須艷，林深不隔香。',48,'全唐诗/poet.song.139000.json','["花浄何須艷，林深不隔香。", "初聞無處覓，小摘莫令長。", "春落秋仍發，梅兼雪未强。", "縹瓷汲寒甃，淺浸一枝涼。"]'),
('0d6d6084-db5a-4c67-9a35-c90c153e2668','秋日見橘花二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','不夜非關月，舞風也自香。',48,'全唐诗/poet.song.139000.json','["不夜非關月，舞風也自香。", "著花能許細，落子不多長。", "玉糝開猶半，金鬚撚更强。", "得秋何恨晚，映暑却生涼。"]'),
('8bf152f4-7e51-48f0-be34-c3c8449d9892','題吉水余端蒙明府縣門飛鳧閣','楊萬里','宋','宋诗','song-poetry','','[]','塵外塵中儘靜喧，閣前閣後且山川。',64,'全唐诗/poet.song.139000.json','["塵外塵中儘靜喧，閣前閣後且山川。", "秋生疎雨微雲處，月仄青原白鷺邊。", "眼冷庾樓聊復此，人如葉令更差賢。", "從公欲往其如嬾，著句無佳莫浪傳。"]'),
('17b8e6d8-0381-41c2-aa8f-8350b2bac058','題周鯁臣浩齋','楊萬里','宋','宋诗','song-poetry','','[]','浩翁曲肱一浩齋，焉知廊廟與蒿萊。',96,'全唐诗/poet.song.139000.json','["浩翁曲肱一浩齋，焉知廊廟與蒿萊。", "此翁定復死不死，舊齋又新有賢子。", "齋前種樹初如椽，如今過雲欲造天。", "作人誰無半點氣，草動風驚便心醉。", "回山倒海不關身，古人與我各何人。", "杉溪老人是翁友，拈出問渠渠領否。"]'),
('36ec2281-18b0-4aab-81d9-338b9168192c','送胡季永赴漕試','楊萬里','宋','宋诗','song-poetry','','[]','兔目著花官樣黄，冰輪飄子秋風香。',128,'全唐诗/poet.song.139000.json','["兔目著花官樣黄，冰輪飄子秋風香。", "誰騎瘦馬踏詞場，澹翁庭階玉雪郎。", "天於賢佞真不省，不應阿翁有阿永。", "景升兒子漫谷量，未識一丁惟啗餠。", "阿永胸中幾許書，石渠奄有仍更餘。", "毛錐半點不籧篨，羽鏃一脫無犀渠。", "當家衣鉢更誰付，鎖廳小借梯雲路。", "澹翁嚴冷縱不嬉，歸來膝上安文度。"]'),
('a05639e3-c2a0-42ea-93de-6904a132c7fb','送瀛洲先生元舉叔談命郡城','楊萬里','宋','宋诗','song-poetry','','[]','誰遣談天太逼真，取憎造物得辭貧。',32,'全唐诗/poet.song.139000.json','["誰遣談天太逼真，取憎造物得辭貧。", "不妨小隠君平肆，戲與人間閲貴人。"]'),
('7dace4be-384b-4c61-a8f2-f0f43f73fbe1','四十二叔祖母劉氏太孺人挽詞','楊萬里','宋','宋诗','song-poetry','','[]','夫人自七十，有母尚期頤。',48,'全唐诗/poet.song.139000.json','["夫人自七十，有母尚期頤。", "不遣千山訃，猶應一病遲。", "孝留天下口，身立女中師。", "到得君羹美，翻令潁谷悲。"]'),
('019616c7-f5e1-449b-9e56-71ce3600f7e5','四十九叔祖母朱氏孺人挽詞','楊萬里','宋','宋诗','song-poetry','','[]','憶哭清湘掾，諸孤未裹頭。',48,'全唐诗/poet.song.139000.json','["憶哭清湘掾，諸孤未裹頭。", "盛年能素節，凜氣却清秋。", "眼底生芻奠，身前汎柏舟。", "無齡還有德，此母不應愁。"]'),
('9e587a2b-4491-4d20-b1f7-03b83384e479','黄太守元授挽詞二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','五馬新通貴，千牛舊不全。',48,'全唐诗/poet.song.139000.json','["五馬新通貴，千牛舊不全。", "豈渠才作祟，從古命懸天。", "半世風波裏，清名玉雪邊。", "諸郎俱偉器，樞屬更人先。"]'),
('91c471da-fdb3-403a-9af6-adba778976ae','黄太守元授挽詞二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','我忝通家子，公如父行親。',48,'全唐诗/poet.song.139000.json','["我忝通家子，公如父行親。", "一書雖不欠，半面遂無因。", "旅櫬千江遠，銘旌兩竹新。", "慶門寧有此，造物豈其仁。"]'),
('7703fb33-ac72-44f1-b2bb-1432a98cb28d','夢亡友黄世永夢中猶喜談佛既覺感念不已因和夢李白韻以記焉二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','子在人每憎，子亡憎者惻。',96,'全唐诗/poet.song.139000.json','["子在人每憎，子亡憎者惻。", "自吾失此友，但覺生意息。", "猶解夢裏來，豈子餘此憶。", "死生知有無，賢聖或未測。", "渾作白日看，不記夜許黑。", "尚憐紫鸞姿，未舉先折翼。", "只驚玉雪容，冷面带古色。", "夢淚覺猶濕，悲罷喜有得。"]'),
('f12d7105-2c25-4885-a027-23080fac09e2','夢亡友黄世永夢中猶喜談佛既覺感念不已因和夢李白韻以記焉二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','去年客京都，子去我未至。',96,'全唐诗/poet.song.139000.json','["去年客京都，子去我未至。", "得書不得面，安用殷勤意。", "猶矜各未老，相見當亦易。", "不知此蹉跎，交道遽云墜。", "一抔胡不仁，埋此經世志。", "絃絕諒何益，蕙歎庸不顇。", "吾聞佛者流，正以生作累。", "夢中尚微言，子豈悲世事。"]'),
('0c8b6673-8c8c-48ca-89ea-961e5f091778','次主簿昌英叔鑷白韻','楊萬里','宋','宋诗','song-poetry','','[]','滴盡思親淚，猶殘影弔形。',48,'全唐诗/poet.song.139000.json','["滴盡思親淚，猶殘影弔形。", "眼花渾作黑，頷底更能青。", "少也投三賦，今焉忽一星。", "此生成底事，有脚不曾停。"]'),
('e3d1d82f-5d81-4a92-a546-6af00d6d40ff','次昌英主簿叔晴望韻','楊萬里','宋','宋诗','song-poetry','','[]','秋水冬全落，寒梅暖向榮。',48,'全唐诗/poet.song.139000.json','["秋水冬全落，寒梅暖向榮。", "煙林明又滅，風雁仄還平。", "老豈愁能避，貧非嬾不營。", "猶須鏟千嶂，剩與放雙明。"]'),
('ce0a00cb-a218-4168-8606-aee8189a9a47','次出門韻','楊萬里','宋','宋诗','song-poetry','','[]','有酒何須富，無車却好行。',48,'全唐诗/poet.song.139000.json','["有酒何須富，無車却好行。", "眼中長得句，身外豈關情。", "遠嶺寒逾瘦，乾楓落更聲。", "好懷非自閟，且道向誰傾。"]'),
('8aa9d0e8-25d2-4416-99ec-335c0bbc3a93','次霜月韻','楊萬里','宋','宋诗','song-poetry','','[]','銀浦寒無浪，金星澹不芒。',48,'全唐诗/poet.song.139000.json','["銀浦寒無浪，金星澹不芒。", "初看霜是月，併愛月和霜。", "萬里除纖翳，雙清作一光。", "詩窮只欠許，窮我未渠央。"]'),
('ac4b2335-881f-4c7e-8b26-679fbcc8d8a3','同主簿叔暮立','楊萬里','宋','宋诗','song-poetry','','[]','旋旋前山沒，駸駸半臂寒。',48,'全唐诗/poet.song.139000.json','["旋旋前山沒，駸駸半臂寒。", "鷗歸勢何嬾，林近意先安。", "待月遲云麽，煩公小立看。", "未知立玉笋，何似立江干。"]'),
('7ec63c97-9733-46a8-9679-0fa362acbb7b','晚望二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','月是小春春未生，節名大雪雪何曾。',32,'全唐诗/poet.song.139000.json','["月是小春春未生，節名大雪雪何曾。", "夕陽不管西山暗，只照東山八九稜。"]'),
('4772d8b5-9f62-4692-ab5f-40704a79a842','晚望二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','萬松不掩一楓丹，煙怕山狂約住山。',32,'全唐诗/poet.song.139000.json','["萬松不掩一楓丹，煙怕山狂約住山。", "却被沙鷗惱人損，作行飛去略無還。"]'),
('f996750c-1331-416d-878d-9e6ea7a74aaa','次主簿叔晚霞','楊萬里','宋','宋诗','song-poetry','','["\u897f\u6e56"]','病眼何愁未苦佳，曉看霜了晚看霞。',64,'全唐诗/poet.song.139000.json','["病眼何愁未苦佳，曉看霜了晚看霞。", "只驚天上三冬月，那得西湖十里花。", "景與詩爭酣未退，興如水湧去難遮。", "却嫌醉墨欹傾甚，整整斜斜半似鴉。"]'),
('6b262526-dd32-4870-9dd7-cb60d515c842','次乞米韻','楊萬里','宋','宋诗','song-poetry','','[]','魯公尚有粥爲食，盧老今無僧作鄰。',64,'全唐诗/poet.song.139000.json','["魯公尚有粥爲食，盧老今無僧作鄰。", "文字借令真可煮，吾曹從古不應貧。", "詩腸幸自無煙火，句眼何愁著點塵。", "俗子豈知貧亦好，未須容易向渠陳。"]'),
('fae0c971-e4fe-4e51-958a-f30c9a52448d','夜雨不寐','楊萬里','宋','宋诗','song-poetry','','[]','雨急點不疎，瓦乾聲可數。',48,'全唐诗/poet.song.139000.json','["雨急點不疎，瓦乾聲可數。", "滴破江湖夢，合眼無復補。", "更長酒力短，睡甜詩思苦。", "已自不成眠，如何更遭許。"]'),
('edddad01-edf0-47b9-987d-4234e606a70a','新寒','楊萬里','宋','宋诗','song-poetry','','[]','寒力欺誰得，知儂典却衣。',24,'全唐诗/poet.song.139000.json','["寒力欺誰得，知儂典却衣。", "暮禽差慰眼，不作一行歸。"]'),
('2f9e2734-6060-49b2-9e22-d7ae53534329','和羅巨濟教授雪二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','天慳聊爾落，地暖未教深。',48,'全唐诗/poet.song.139000.json','["天慳聊爾落，地暖未教深。", "猶放遥岑碧，偏鳴密竹林。", "似供愁裏眼，小惱客邊心。", "詩卷開還闔，清寒溢素襟。"]'),
('4306be23-e3c4-4685-94ba-7ee078e85db5','和羅巨濟教授雪二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','飛來須面旋，欲墮更橫斜。',48,'全唐诗/poet.song.139000.json','["飛來須面旋，欲墮更橫斜。", "不遣詩人嬾，惟禁酒力加。", "鏤冰初試手，翦水便成花。", "誰會歐蘇律，吟邊別一家。"]'),
('a907402a-6a3f-45da-b5b1-f5c5fa15a0af','次主簿叔雪韻','楊萬里','宋','宋诗','song-poetry','','[]','向來一雪亦草草，天知詩人眼未飽。',176,'全唐诗/poet.song.139000.json','["向來一雪亦草草，天知詩人眼未飽。", "相傳南風爲雪骨，此言未試吾不曉。", "昨日忽驚冬作春，暖氣吹人軟欲倒。", "惟餘桃李未著花，便恐蟄蟲偷出窖。", "南風未了却北風，一夜吹翻青玉昊。", "今晨冷傍筆管生，似妬吟邊事幽討。", "司寒作意欲再雪，凍雀求哀不容禱。", "令人還憶柳柳州，解道千山絕飛鳥。", "誰教愛雪却嫌寒，歡喜十分九煩惱。", "詩人凍死不足憐，凍死猶應談雪好。", "寄聲滕六何似休，浄盡將雲爲儂掃。"]'),
('42b8f4af-0b9a-4821-adf9-43e1afbfb407','次秦少游梅韻','楊萬里','宋','宋诗','song-poetry','','[]','南枝外槁中不槁，未葉先花笑人倒。',128,'全唐诗/poet.song.139000.json','["南枝外槁中不槁，未葉先花笑人倒。", "已從寒裏著詩愁，可復溪邊被花惱。", "非渠攙出百卉前，爾許清寒誰敢早。", "有花無雪花只俗，有雪無梅雪何好。", "冷蕊不風元自香，瘦柯寫月真如掃。", "但令一壑蒔橫斜，便挂竹皮爲渠老。", "秦七蘇二冰玉詞，絕唱寒盟幾秋草。", "梅邊尚有句可搜，更撚衰髯仰清昊。"]'),
('9cadc00b-3a40-479d-b752-6d7402cbeb8b','次東坡先生蠟梅韻','楊萬里','宋','宋诗','song-poetry','','[]','梅花已自不是花，冰魂謫墮玉皇家。',128,'全唐诗/poet.song.139000.json','["梅花已自不是花，冰魂謫墮玉皇家。", "不餐煙火更餐蠟，化作黄姑瞞造物。", "后山未覺坡先知，東坡勾引后山詩。", "金花勸飲金荷葉，兩公醉吟許孤絕。", "人間姚魏漫如山，令人眼暗只欲眠。", "此花寒香來又去，惱損詩人難覓句。", "月兼花影恰三人，欠箇文同作墨君。", "吾詩無復古清越，萬水千山一瓶鉢。"]'),
('0568fe16-85e4-4187-8451-72d8263c895e','次東坡先生用六一先生雪詩律令龜字二十韻舊禁玉月梨梅練絮白舞鵝鶴等字新添訪戴映雪高卧齧氈之類一切禁之','楊萬里','宋','宋诗','song-poetry','','["\u897f\u6e56"]','病身柴立手亦龜，不要人憐天得知。',323,'全唐诗/poet.song.139000.json','["病身柴立手亦龜，不要人憐天得知。", "一寒度夕抵度歲，惡風更將乾雨吹。", "作祥只解誑饑腹，催老偏工欺短髭。", "透屋旋生衾裏鐵，隔窗也送硯中澌。", "攬衣起看端不惡，兩耳已作凍菌危。", "似明還暗靜復響，索我黄絹揮烏絲。", "誤喜家貧屋驟富，不道天巧人能爲。", "忽思向來旅京國，瘦馬斷鞭包袖持。", "紅金何曾夢得見，繭生脚底粟生肌。", "殘杯冷炙自無分，不是不肯叩富兒。", "獨立西湖望東海，海神駕雪初來時。", "眼花只怪失天地，風橫併作翻簾幃。", "飛來峰在水仙國，九里松無塵土姿。", "只欠杖頭聘歡伯，安得醉倒衣淋漓。", "猶遭天子呼野客，催班聲裏趨丹墀。", "如今四壁一破褐，雪花密密巾披披。", "詩肩渾作遠嶺瘦，詩思浪與春江馳。", "茅柴乞暖却得冷，聊復爾耳三兩巵。", "東坡逸足電雹去，天馬肯放氂牛隨。", "君不見溧陽縣裏一老尉，一句曾饒韓退之。"]'),
('817abfad-1e0c-4fba-ab42-b382987e5f5f','丙戌上元後和昌英叔李花','楊萬里','宋','宋诗','song-poetry','','[]','春暖何緣雪壓山，香來初認李花繁。',64,'全唐诗/poet.song.139000.json','["春暖何緣雪壓山，香來初認李花繁。", "露酣月蕊蒼茫外，梅與山礬伯仲間。", "剩雨殘風底無頼，明朝後日不堪看。", "泥深小忍春遊脚，猶遣青童去一攀。"]'),
('578b6f4f-3abb-4565-89d9-11cdaf43d97c','又和春雨','楊萬里','宋','宋诗','song-poetry','','[]','向來一旱鬢成絲，敢道新年雨脚垂。',64,'全唐诗/poet.song.139000.json','["向來一旱鬢成絲，敢道新年雨脚垂。", "未必催詩真强管，端令學稼失愁思。", "只今且莫傾三峽，此後時須示一犁。", "未愛少陵紅濕句，可人却是道知時。"]'),
('20d9da24-8a1e-41f7-b4af-772688c00c81','和周仲容春日二絕句  其一','楊萬里','宋','宋诗','song-poetry','','[]','春半花全退，詩人尚道遲。',24,'全唐诗/poet.song.139000.json','["春半花全退，詩人尚道遲。", "惟應讀書苦，聲調作吾伊。"]'),
('73d8235a-9212-4bed-aab7-11dc0517255b','和周仲容春日二絕句  其二','楊萬里','宋','宋诗','song-poetry','','[]','端憂更貧病，不分又花時。',24,'全唐诗/poet.song.139000.json','["端憂更貧病，不分又花時。", "只說春何好，猶堪入小詩。"]'),
('a93747e0-2269-41e8-be54-ec9c7ae6aaf7','和周仲容春日二律句  其一','楊萬里','宋','宋诗','song-poetry','','[]','饑民日夜去，也有不荒田。',48,'全唐诗/poet.song.139000.json','["饑民日夜去，也有不荒田。", "舊雨仍新雨，今年勝去年。", "未嫌詩得瘦，只苦茗妨眠。", "花氣薰人醉，來從若箇邊。"]'),
('1fd67130-891c-42a2-8deb-9a0afb40af89','和周仲容春日二律句  其二','楊萬里','宋','宋诗','song-poetry','','[]','今晨晴頗嬾，昨夜雨猶聲。',48,'全唐诗/poet.song.139000.json','["今晨晴頗嬾，昨夜雨猶聲。", "欲社燕先覺，半春鶑未鳴。", "詩非一字苦，句豈十分清。", "參透江西社，無燈眼亦明。"]'),
('4b98b131-7c8a-40a9-8765-b8ec06c30229','和王才臣','楊萬里','宋','宋诗','song-poetry','','[]','新詩不但不饒儂，便恐陰何立下風。',64,'全唐诗/poet.song.139000.json','["新詩不但不饒儂，便恐陰何立下風。", "每與勝談千古事，不知撥盡一爐紅。", "生兒底巧翁何恨，得子銷愁我未窮。", "剩欲苛留老三逕，念渠何罪亦山中。"]'),
('40b858c5-f983-46a8-acde-f5c1e3597d98','得省榜見羅仲謀曾無逸策名夜歸喜甚通夕不寐得二絕句  其一','楊萬里','宋','宋诗','song-poetry','','[]','淡墨高垂兩客名，夜歸到曉睡難成。',32,'全唐诗/poet.song.139000.json','["淡墨高垂兩客名，夜歸到曉睡難成。", "却緣二喜添三喜，聽得黄鸝第一聲。"]'),
('86c5e0e4-80ac-4a8d-ae96-fbb5759aa0d2','得省榜見羅仲謀曾無逸策名夜歸喜甚通夕不寐得二絕句  其二','楊萬里','宋','宋诗','song-poetry','','[]','兩日陰晴較不常，嫩寒輕暖雜花香。',32,'全唐诗/poet.song.139000.json','["兩日陰晴較不常，嫩寒輕暖雜花香。", "今晨天色休休問，卧看紅光點屋梁。"]'),
('6919390c-f942-4e09-a8e1-cd551dca9f62','和蕭伯和韻','楊萬里','宋','宋诗','song-poetry','','[]','桃李何忙開又零，老懷易感掃還生。',64,'全唐诗/poet.song.139000.json','["桃李何忙開又零，老懷易感掃還生。", "略無花片經人眼，誰道春風不世情。", "睡去恐遭詩作祟，愁來當遣酒行成。", "子能覓句庸非樂，未必胸中有不平。"]'),
('620097a4-1831-4eef-b91b-fdb7315fde79','又和風雨二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','東風未得顛如許，定被春光引得顛。',32,'全唐诗/poet.song.139000.json','["東風未得顛如許，定被春光引得顛。", "晚雨何妨略彈壓，不應猶自借渠權。"]'),
('dab5ee5c-9eaa-4ad1-864d-dd4405df506b','又和風雨二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','風風雨雨又春窮，白白朱朱已眼空。',32,'全唐诗/poet.song.139000.json','["風風雨雨又春窮，白白朱朱已眼空。", "拚却老紅一萬點，換將新綠百千重。"]'),
('337d5b30-2a28-4ff6-86ec-826f635d2883','和文遠叔行春','楊萬里','宋','宋诗','song-poetry','','[]','行脚宜晴翠，看雲恐夕黄。',48,'全唐诗/poet.song.139000.json','["行脚宜晴翠，看雲恐夕黄。", "何村不花柳，此社要柴桑。", "一笑當誰領，同來得許忙。", "老懷翻作惡，不剩半分狂。"]'),
('08cf8bb4-666d-4a2d-bd0a-089681294c19','和子上弟春雹','楊萬里','宋','宋诗','song-poetry','','[]','雹子何孤竹屋聲，只於花事較無情。',32,'全唐诗/poet.song.139000.json','["雹子何孤竹屋聲，只於花事較無情。", "青春已在殘紅裏，更著渠儂何似生。"]'),
('3cc9dd21-f3b9-4bd5-8858-fb860d79e6c1','和蕭伯和春興','楊萬里','宋','宋诗','song-poetry','','[]','只道韶華不到儂，不妨軟日媚柔風。',64,'全唐诗/poet.song.139000.json','["只道韶華不到儂，不妨軟日媚柔風。", "愁心自對春無味，老面可能花似紅。", "逢著詩狂兼酒聖，又忘人厄或天窮。", "聖人枉索方兄價，我與賢人也一中。"]'),
('318f8a7d-e5c5-481a-aee9-df3094f09206','又和聞蛙','楊萬里','宋','宋诗','song-poetry','','[]','春來真底好，此輩政縱橫。',48,'全唐诗/poet.song.139000.json','["春來真底好，此輩政縱橫。", "身作泥中計，聲從雨後增。", "北人餐未慣，南食眼猶生。", "灰灑知虛實，於渠似可行。"]'),
('b7b9e724-ea7a-461d-aacc-a22d942226e9','又和二絕句  其一','楊萬里','宋','宋诗','song-poetry','','[]','一冬寒不到深山，豈有春來更會寒。',32,'全唐诗/poet.song.139000.json','["一冬寒不到深山，豈有春來更會寒。", "幸自趁晴行脚好，却嫌沙入破鞋間。"]'),
('734a5f3f-c9eb-42a5-86bd-d98cf7a42504','又和二絕句  其二','楊萬里','宋','宋诗','song-poetry','','[]','翦翦輕風未是輕，猶吹花片作紅聲。',32,'全唐诗/poet.song.139000.json','["翦翦輕風未是輕，猶吹花片作紅聲。", "一生情重嫌春淺，老去與春無點情。"]'),
('6c731157-78a0-45fe-a688-11ebffbd1e08','三月三日雨作遣悶十絕句  其一','楊萬里','宋','宋诗','song-poetry','','[]','行春莫放一日一，修禊仍逢三月三。',32,'全唐诗/poet.song.139000.json','["行春莫放一日一，修禊仍逢三月三。", "忍遣晴光作陰雨，更將急濺涴春衫。"]'),
('249f0671-63d6-4427-ae34-b1e15719dbbd','三月三日雨作遣悶十絕句  其二','楊萬里','宋','宋诗','song-poetry','','[]','出門著雨不能歸，借得青蓑著片時。',32,'全唐诗/poet.song.139000.json','["出門著雨不能歸，借得青蓑著片時。", "春染萬花知了未，雲偷千嶂忽何之。"]'),
('4042f879-87dc-484d-90f2-0843455a6416','三月三日雨作遣悶十絕句  其三','楊萬里','宋','宋诗','song-poetry','','[]','歸得茅齋松竹邊，看風看雨亦欣然。',32,'全唐诗/poet.song.139000.json','["歸得茅齋松竹邊，看風看雨亦欣然。", "空簷知與階何故，須把青苔滴似穿。"]'),
('c146e14f-65a3-44ca-813d-f71506e5a9fb','三月三日雨作遣悶十絕句  其四','楊萬里','宋','宋诗','song-poetry','','[]','舊與酴醾頗不疎，今春半朶未逢渠。',32,'全唐诗/poet.song.139000.json','["舊與酴醾頗不疎，今春半朶未逢渠。", "千花一雨俱紅雨，問訊孤芳小住無。"]'),
('9fe9eb35-e3c1-4b5e-9963-fcb3e1799fa1','三月三日雨作遣悶十絕句  其五','楊萬里','宋','宋诗','song-poetry','','[]','今年春事底匆匆，雨急風顛惱得儂。',32,'全唐诗/poet.song.139000.json','["今年春事底匆匆，雨急風顛惱得儂。", "不見一林如許笋，猶嫌三日向來風。"]'),
('20e7b431-c6bf-40af-a163-debc438faad1','三月三日雨作遣悶十絕句  其六','楊萬里','宋','宋诗','song-poetry','','[]','荒餘只怪不愁聲，好語煩君細細聽。',32,'全唐诗/poet.song.139000.json','["荒餘只怪不愁聲，好語煩君細細聽。", "秧早不由田父懶，蠶遲端待柘陰成。"]'),
('9c1c9c86-9a38-4b94-beb1-c11a02c2a3b7','三月三日雨作遣悶十絕句  其七','楊萬里','宋','宋诗','song-poetry','','[]','遲日何緣似箇長，睡鄉未苦怯茶槍。',32,'全唐诗/poet.song.139000.json','["遲日何緣似箇長，睡鄉未苦怯茶槍。", "春風解惱詩人鼻，非葉非花只是香。"]'),
('605ffa4a-00b1-4e0c-8fcf-fe94cee1cd68','三月三日雨作遣悶十絕句  其八','楊萬里','宋','宋诗','song-poetry','','[]','村落尋花特地無，有花亦自只愁予。',32,'全唐诗/poet.song.139000.json','["村落尋花特地無，有花亦自只愁予。", "不如卧聽春山雨，一陣繁聲一陣疎。"]'),
('63f4ffa3-8426-4531-8d9c-4fda983a2056','三月三日雨作遣悶十絕句  其九','楊萬里','宋','宋诗','song-poetry','','[]','報答春光酒一巵，貧中無酒著春欺。',32,'全唐诗/poet.song.139000.json','["報答春光酒一巵，貧中無酒著春欺。", "作詩細與東風道，未必東風肯要詩。"]'),
('ccd73d35-cef9-402c-a6a3-255e7a0bde69','三月三日雨作遣悶十絕句  其一○','楊萬里','宋','宋诗','song-poetry','','[]','却是春殘景更佳，詩人須記許生涯。',32,'全唐诗/poet.song.139000.json','["却是春殘景更佳，詩人須記許生涯。", "平田漲綠村村麥，嫩水浮紅岸岸花。"]'),
('3d25fe19-c749-429f-b111-f92a3ac2fae2','和羅武岡欽若酴醾長句','楊萬里','宋','宋诗','song-poetry','','[]','花飛十不啻五六，青子團枝失紅簇。',160,'全唐诗/poet.song.139000.json','["花飛十不啻五六，青子團枝失紅簇。", "江南桃李總成陰，不論少城與韋曲。", "酴醾珍重不浪開，晚堆綠雲點冰玉。", "體薰山麝非一臍，水洗銀河費千斛。", "滴成小蓓密於糝，亂走長條柔可束。", "醉眸須及月下來，破鼻細從風處觸。", "先生未必被花惱，偶與門人暮春浴。", "爲憐壓架十萬枝，小立傍邊領新馥。", "剩拚妙語寵瓊蕤，更掇清英釀酃淥。", "先生何得便杜門，霜鬢猶煩玉堂宿。"]'),
('9455d5c1-8417-4de3-a587-9ea1b5b0498d','再和','楊萬里','宋','宋诗','song-poetry','','[]','春風一夜吹滕六，旋落旋銷不成簇。',160,'全唐诗/poet.song.139000.json','["春風一夜吹滕六，旋落旋銷不成簇。", "只餘架上萬天花，照影清池三兩曲。", "江東詩仙花下飲，小摘繁枝篸醉玉。", "驚飛雪片萬許點，亂落酒船百餘斛。", "舊枝掠削自縈回，新枝奔迸無拘束。", "詩仙詩滿雲夢胸，那更相逢此花觸。", "只愁毛穎倦驅使，一日屢向陶泓浴。", "兩章洗盡眼底塵，箇字亦带花邊馥。", "憑誰說與柳柳州，休道一聲山水淥。", "願參佳句法如何，夜雨何時對床宿。"]'),
('2029f6c3-da97-43ca-82a4-84e014111d1b','賀澹庵先生胡侍郎新居落成二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','清廟欹斜一笑扶，歸來四壁亦元無。',64,'全唐诗/poet.song.139000.json','["清廟欹斜一笑扶，歸來四壁亦元無。", "可憐拙計輸餘子，住破僧房始結廬。", "三逕非遥人自遠，萬間不惡我何須。", "冥搜善頌終難好，賀厦真成燕不如。"]'),
('a2429831-6ebc-4053-a801-813c4f471d54','賀澹庵先生胡侍郎新居落成二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','眼高不肯住清都，夢繞江南水竹居。',64,'全唐诗/poet.song.139000.json','["眼高不肯住清都，夢繞江南水竹居。", "却入青原更青處，飽看黄本硬黄書。", "翦裁風月聊堪醉，拆洗乾坤正要渠。", "賜宅不應公得免，未知北第似林廬。"]'),
('27637459-1e66-4b8a-9abe-5ac2cceaa2f7','見周子充舍人敘懷','楊萬里','宋','宋诗','song-poetry','','[]','三年再謁一番逢，兩舍相望幾訊通。',64,'全唐诗/poet.song.139000.json','["三年再謁一番逢，兩舍相望幾訊通。", "便有好懷安得盡，不知造物底相窮。", "公今貧賤庸非福，我更清愁惡似公。", "誤辱相期千載事，雲泥政自未應同。"]'),
('d10e25bd-a4bd-4b15-b58d-821347c26761','和易公立投贈之句','楊萬里','宋','宋诗','song-poetry','','[]','日者論文各少年，中間歲月似風旋。',64,'全唐诗/poet.song.139000.json','["日者論文各少年，中間歲月似風旋。", "老來書冊惟生睡，裏許生涯未苦賢。", "好句撩人那得嬾，勝流覓紙便爭傳。", "詩壇正欠風騷將，君合爲真不用權。"]'),
('fbf77f7d-fcfe-4f11-8e3a-c3fc643a3503','和昌英主簿叔求潘墨','楊萬里','宋','宋诗','song-poetry','','[]','頗怯冥搜惱藏神，却思瘞硯學元賓。',64,'全唐诗/poet.song.139000.json','["頗怯冥搜惱藏神，却思瘞硯學元賓。", "墨家何以得公重，詩債又來欺我貧。", "鏡面松身紛楚楚，金華笏樣本陳陳。", "嬾邊此寶端無用，送似草玄揚子雲。"]'),
('551cc08d-aa36-47e9-9a6f-00cd6df49c2d','之永和小憩資壽寺','楊萬里','宋','宋诗','song-poetry','','[]','石子密鋪逕，竹莖疎作行。',48,'全唐诗/poet.song.139000.json','["石子密鋪逕，竹莖疎作行。", "不緣憩騶僕，幾失此山房。", "佛像看都好，林花靜自香。", "未須清興盡，歸更借僧床。"]'),
('eb353536-4009-4ed4-81c8-aef275ddf8e3','過神助橋亭','楊萬里','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','下轎渾將野店看，只驚脚底水聲寒。',32,'全唐诗/poet.song.139000.json','["下轎渾將野店看，只驚脚底水聲寒。", "不知竹外長江近，忽有高桅出寸竿。"]'),
('a4dda9ac-16c6-4b2c-9f83-7290042b2b00','過大皋渡','楊萬里','宋','宋诗','song-poetry','','[]','隔岸橫州十里青，黄牛無數放春晴。',32,'全唐诗/poet.song.139000.json','["隔岸橫州十里青，黄牛無數放春晴。", "船行非與牛相背，何事黄牛却倒行。"]'),
('cac2bb56-3a9d-45e1-aad3-a5b4791f21fd','至永和','楊萬里','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','出城即便見青原，正在長江出處天。',32,'全唐诗/poet.song.139000.json','["出城即便見青原，正在長江出處天。", "却到青原望城裏，樓臺些子水雲邊。"]'),
('3524c9a2-c180-444c-9bb6-d5699bfab2d3','自值夏小溪泛舟出大江','楊萬里','宋','宋诗','song-poetry','','[]','放溜山溪一葉輕，山溪盡處大江橫。',32,'全唐诗/poet.song.139000.json','["放溜山溪一葉輕，山溪盡處大江橫。", "舟中寂寂無人語，只有波聲及雨聲。"]'),
('95c70ac9-80c8-445b-8059-c1c2592c9bc6','和文明主簿叔見寄之韻二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','古聲彈九寡，妙學足三多。',48,'全唐诗/poet.song.139000.json','["古聲彈九寡，妙學足三多。", "十載纔重見，百年當幾何。", "入州非不肯，出伏即相過。", "安得看雲語，金盆仄白河。"]'),
('48edbcfe-6f7c-458d-b125-81fe2cfccb27','和文明主簿叔見寄之韻二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','黄九陳三外，諸人總解詩。',48,'全唐诗/poet.song.139000.json','["黄九陳三外，諸人總解詩。", "甘心休作許，苦語竟何爲。", "所向公同我，何緣樣入時。", "從來大小阮，一笑更誰知。"]'),
('91a0502b-6b2c-495c-82d6-2603624cc8ad','和濟翁見寄之韻二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','只有高爲累，元無俗可離。',48,'全唐诗/poet.song.139000.json','["只有高爲累，元無俗可離。", "正緣隔少面，添得許多詩。", "杜老吟邊樹，山公醉處池。", "猶須謀一笑，天許又何時。"]'),
('374941b9-ee05-4560-b657-9cc1b2b153f0','和濟翁見寄之韻二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','四海皆兄弟，何如真弟兄。',48,'全唐诗/poet.song.139000.json','["四海皆兄弟，何如真弟兄。", "吾今有弟在，眼只爲渠橫。", "剩欲驅濤壯，猶應倒峽清。", "青春不可又，未欲傍長檠。"]'),
('ff120892-0649-4cff-8b98-9db8b12e9e7d','和王才臣再病二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','燕外將心遠，鶑邊與耳謀。',48,'全唐诗/poet.song.139000.json','["燕外將心遠，鶑邊與耳謀。", "如何再卧病，對此兩添愁。", "赤壁還坡老，黄樓只子由。", "二蘇三賦在，一覽病應休。"]'),
('0def6599-95f5-41cf-9e19-4611561a8323','和王才臣再病二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','詩瘦知春瘦，時乖抑命乖。',48,'全唐诗/poet.song.139000.json','["詩瘦知春瘦，時乖抑命乖。", "病過三日雨，門掩半扉柴。", "不面何曾久，於心便有懷。", "端能暮出否，溪水減南涯。"]'),
('6b00cd95-bdc2-42f6-80b7-7525c9a51c21','閑居初夏午睡起二絕句  其一','楊萬里','宋','宋诗','song-poetry','','["\u513f\u7ae5", "\u590f\u5929"]','梅子留酸軟齒牙，芭蕉分綠與窗紗。',32,'全唐诗/poet.song.139000.json','["梅子留酸軟齒牙，芭蕉分綠與窗紗。", "日長睡起無情思，閑看兒童捉柳花。"]'),
('603d0bd7-6fec-494a-bb04-876bb74fb7cb','閑居初夏午睡起二絕句  其二','楊萬里','宋','宋诗','song-poetry','','["\u751f\u6d3b", "\u590f\u5929", "\u559c\u7231"]','松陰一架半弓苔，偶欲看書又嬾開。',32,'全唐诗/poet.song.139000.json','["松陰一架半弓苔，偶欲看書又嬾開。", "戲掬清泉灑蕉葉，兒童誤認雨聲來。"]'),
('265e5588-5d0a-4dab-85c2-1203af6c10f8','携酒夜餞羅季周','楊萬里','宋','宋诗','song-poetry','','[]','夜深未要掩柴門，且放清風入綠尊。',32,'全唐诗/poet.song.139000.json','["夜深未要掩柴門，且放清風入綠尊。", "淡月輕雲相映著，淺黄帊子裹金盆。"]'),
('93724eef-f965-4d0b-97d4-bb9b00867cff','雨後獨登舍北山頂','楊萬里','宋','宋诗','song-poetry','','[]','山下生愁熱不除，山頭小立氣全蘇。',32,'全唐诗/poet.song.139000.json','["山下生愁熱不除，山頭小立氣全蘇。", "自緣著脚高低別，萬壑清風豈是無。"]'),
('1ac4bc7c-ad9d-4871-a768-69430cf76364','題羅巨濟教授蓬山堂','楊萬里','宋','宋诗','song-poetry','','[]','蓬萊藏室盛東都，只著古書并老儒。',136,'全唐诗/poet.song.139000.json','["蓬萊藏室盛東都，只著古書并老儒。", "後來許事曉星疎，登車不落問何如。", "廣文先生自有飯，諸公衮衮端無羨。", "著脚金坡不作難，問津木天何足辦。", "作堂聊爾題蓬山，此豈有意亦偶然。", "登瀛仙人多姓許，未必先生肯爲伍。", "書生饒舌定可憎，此話姑置莫葛藤。", "先生諸孫皆玉冰，誦書已作鸞鶴聲，請來欹枕細細聽。"]'),
('fcd86c6a-0e93-40f9-ae63-9a7ee2e22866','和昌英叔夏至喜雨','楊萬里','宋','宋诗','song-poetry','','[]','清酣暑雨不緣求，猶似梅黄麥欲秋。',64,'全唐诗/poet.song.139000.json','["清酣暑雨不緣求，猶似梅黄麥欲秋。", "去歲如今禾半死，吾曹遍禱汗交流。", "此生未用慍三已，一飽便應哦四休。", "花外綠畦深沒鶴，來看莫惜下邳侯。"]'),
('3e864ff1-2678-4a3f-9126-daf24de3e210','和昌英叔覓松枝作日棚  其一','楊萬里','宋','宋诗','song-poetry','','[]','先人手種一川松，爲棟爲杗似未中。',32,'全唐诗/poet.song.139000.json','["先人手種一川松，爲棟爲杗似未中。", "只合茅齋聽驅使，爲公六月喚秋風。"]'),
('7fca6d01-803c-4dbc-b8de-0d1c52f9d4d7','和昌英叔覓松枝作日棚  其二','楊萬里','宋','宋诗','song-poetry','','[]','欲和新詩且撚髯，岸巾百匝繞前簷。',32,'全唐诗/poet.song.139000.json','["欲和新詩且撚髯，岸巾百匝繞前簷。", "茅齋或恐清陰薄，更遣蒼官去一添。"]'),
('e8693818-aef5-4504-8d97-389f2eb19770','秋夜不寐','楊萬里','宋','宋诗','song-poetry','','[]','秋氣侵人冷欲冰，不由老境不愁生。',32,'全唐诗/poet.song.139000.json','["秋氣侵人冷欲冰，不由老境不愁生。", "雨聲已遣儂無睡，更著寒蛩泣到明。"]'),
('e3a194c9-f178-4162-b9ba-ba742ffba061','元舉叔蓮花','楊萬里','宋','宋诗','song-poetry','','[]','不著芙蓉近路栽，菰蒲深處却花開。',32,'全唐诗/poet.song.139000.json','["不著芙蓉近路栽，菰蒲深處却花開。", "晚香特地清人骨，多謝西風得得來。"]'),
('1fd807ce-b37e-4fb9-90cd-546890879664','昌英叔門外小樹木犀早開','楊萬里','宋','宋诗','song-poetry','','[]','觸鼻無從覓，看林小綴黄。',48,'全唐诗/poet.song.139000.json','["觸鼻無從覓，看林小綴黄。", "旋開三兩粟，已作十分香。", "入夜偏相惱，攙先有底忙。", "移床月枝下，坐對略傳觴。"]'),
('5f70d4a4-8080-48ad-a05f-522256a94489','寄題張商弼葵堂堂下元不種葵花但取面勢向陽二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','行盡葵堂西復東，葵花元自不曾逢。',32,'全唐诗/poet.song.139000.json','["行盡葵堂西復東，葵花元自不曾逢。", "客來問訊名堂意，雪裏芭蕉笑殺儂。"]'),
('561a0f26-be9e-45e7-8f0d-1a89943b86dd','寄題張商弼葵堂堂下元不種葵花但取面勢向陽二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','主人未肯便山林，賞月吟風酒更琴。',32,'全唐诗/poet.song.139000.json','["主人未肯便山林，賞月吟風酒更琴。", "每一登堂一揩眼，誰知半點向陽心。"]'),
('e64dd060-60c7-4dff-bb27-aac750d84a6f','南溪暮立','楊萬里','宋','宋诗','song-poetry','','[]','溪影明霞新月底，水聲亂石嫩沙間。',32,'全唐诗/poet.song.139000.json','["溪影明霞新月底，水聲亂石嫩沙間。", "欲歸小爲魚兒住，更看跳波玉一環。"]'),
('b4ae57f0-5a64-4a60-a3f7-e617d90973c5','晚望','楊萬里','宋','宋诗','song-poetry','','[]','病身似怯暮來風，老眼還驚霽後虹。',32,'全唐诗/poet.song.139000.json','["病身似怯暮來風，老眼還驚霽後虹。", "落日偏明松表裏，好山分占水西東。"]'),
('acc429df-6a0c-4946-a6e5-2db7b96fbc5b','秋夜','楊萬里','宋','宋诗','song-poetry','','[]','挑落寒燈一點青，方知斜月半窗明。',32,'全唐诗/poet.song.139000.json','["挑落寒燈一點青，方知斜月半窗明。", "無端一陣秋聲起，喚作銅瓶蟹眼鳴。"]'),
('6c00a01f-45cf-48ab-aba7-0969dc092a85','夜聞蕭伯和與子上弟讀書','楊萬里','宋','宋诗','song-poetry','','[]','少日耽書病得臞，何曾燈火稍相疎。',32,'全唐诗/poet.song.139000.json','["少日耽書病得臞，何曾燈火稍相疎。", "如今老懶那能許，卧聽鄰齋夜讀書。"]'),
('893df53e-ad0f-4cad-a516-c8361c1bd505','中秋雨過月出','楊萬里','宋','宋诗','song-poetry','','[]','欲遣清風掃亂雲，先將一雨浄游塵。',64,'全唐诗/poet.song.139000.json','["欲遣清風掃亂雲，先將一雨浄游塵。", "今年大作中秋事，月色何孤我輩人。", "照却八方還剩在，看來千古許清新。", "不眠不惜明朝補，報答孤光醉是真。"]'),
('ead208c9-bc62-40fa-b7d8-c05a2ca6014f','和李天麟二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','學詩須透脫，信手自孤高。',48,'全唐诗/poet.song.139000.json','["學詩須透脫，信手自孤高。", "衣鉢無千古，丘山只一毛。", "句中池有草，子外目俱蒿。", "可口端何似，霜螯略带糟。"]'),
('84d7a4d4-07bf-471e-9484-15711a1294b9','和李天麟二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','句法天難秘，工夫子但加。',48,'全唐诗/poet.song.139000.json','["句法天難秘，工夫子但加。", "參時且柏樹，悟罷豈桃花。", "要共東西王，其如南北涯。", "肯來談箇事，分坐白鷗沙。"]'),
('5c73f3f9-18d5-4f6d-b857-905919d95811','寄題劉元明環翠閣二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','閣在青圍翠繞中，何時我輩略搘筇。',32,'全唐诗/poet.song.139000.json','["閣在青圍翠繞中，何時我輩略搘筇。", "亦聞佳處無多子，只有千峰與萬峰。"]'),
('29bbc73d-4824-4c0c-b07f-da2ccfe29edc','寄題劉元明環翠閣二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','一夜秋聲惱井桐，夢回得句寄西風。',32,'全唐诗/poet.song.139000.json','["一夜秋聲惱井桐，夢回得句寄西風。", "詩成却問題詩處，正在東山東復東。"]'),
('01182520-86ca-49a4-be54-81a57c57b7fa','濠原路中','楊萬里','宋','宋诗','song-poetry','','[]','長亭短亭三復五，總是兒時行底路。',64,'全唐诗/poet.song.139000.json','["長亭短亭三復五，總是兒時行底路。", "尚憶天寒日小黄，先君前行我後顧。", "如今悲不爲塗窮，病雁孤飛失老鴻。", "三年閉戶松風裏，行路又還從此始。"]'),
('72f4aef5-04f1-437b-9bd0-1cbb108143e9','小雨','楊萬里','宋','宋诗','song-poetry','','["\u5199\u96e8", "\u96e8", "\u6292\u60c5"]','雨來細細復疎疎，縱不能多不肯無。',32,'全唐诗/poet.song.139000.json','["雨來細細復疎疎，縱不能多不肯無。", "似妬詩人山入眼，千峰故隔一簾珠。"]'),
('25598d33-4793-407a-b5cd-abf01aa1185b','連嶺遇雨','楊萬里','宋','宋诗','song-poetry','','[]','肩輿正好看山色，雨裏兩窗開不得。',64,'全唐诗/poet.song.139000.json','["肩輿正好看山色，雨裏兩窗開不得。", "此外只有書可觀，斜點又來濕書冊。", "一月秋晴一月泥，南翁此諺似可疑。", "山寒却要日暴背，吾衰不用雨催詩。"]'),
('c7e44384-9de5-446c-84ed-0754d435a8df','題赤孤同亭館','楊萬里','宋','宋诗','song-poetry','','[]','數菊能令客眼明，三峰端爲此堂橫。',32,'全唐诗/poet.song.139000.json','["數菊能令客眼明，三峰端爲此堂橫。", "僕夫不敢催儂去，只道長沙尚八程。"]'),
('53eafab8-0cfc-41dc-819a-0d69b5d4371e','分宜逆旅逢同郡客子','楊萬里','宋','宋诗','song-poetry','','[]','在家兒女亦心輕，行路逢人總弟兄。',32,'全唐诗/poet.song.139000.json','["在家兒女亦心輕，行路逢人總弟兄。", "未問後來相憶否，其如臨別不勝情。"]'),
('b071e566-51db-47d5-a29b-9bcee2c90817','袁州路遇晴','楊萬里','宋','宋诗','song-poetry','','[]','晴意久不果，天容今一新。',48,'全唐诗/poet.song.139000.json','["晴意久不果，天容今一新。", "如何半輪日，銷却許多雲。", "積雨還休雨，小春真似春。", "客心君莫問，山鳥亦欣欣。"]'),
('4c170fd4-c895-40fb-b10a-883fb51381e9','將至萍鄉欲宿爲重客據館乃出西郊','楊萬里','宋','宋诗','song-poetry','','[]','哦詩渾忘路高低，忽怪松梢與路齊。',32,'全唐诗/poet.song.139000.json','["哦詩渾忘路高低，忽怪松梢與路齊。", "準擬醉眠萍實驛，驛西西去更山西。"]'),
('9e083e04-7f38-4f19-a483-ce178cdbe62f','將至醴陵','楊萬里','宋','宋诗','song-poetry','','[]','行盡崎嶇峽，初逢熨帖坡。',48,'全唐诗/poet.song.139000.json','["行盡崎嶇峽，初逢熨帖坡。", "寒從平野有，雨傍遠山多。", "也自長沙近，其如此路何。", "披文渾不惡，凍手奈頻呵。"]'),
('2aec0456-f4d1-43ca-bb18-30eeb8bcce33','見張欽夫二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','克己今顔子，承家小呂申。',48,'全唐诗/poet.song.139000.json','["克己今顔子，承家小呂申。", "只愁無好手，不道欠斯人。", "一別時飛幾，重來事總新。", "祥琴聲尚苦，可更話酸辛。"]'),
('e9afe36b-cf1e-4893-b2b1-bc8208152b01','見張欽夫二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','不見所知久，有懷何許開。',48,'全唐诗/poet.song.139000.json','["不見所知久，有懷何許開。", "百書終作惡，千里爲渠來。", "鄒魯期程遠，風霜鬢髮催。", "不應師友地，只麽遣空回。"]'),
('8e374a79-26f7-4c86-9ce8-f1f26afbc779','見張定叟','楊萬里','宋','宋诗','song-poetry','','[]','蜀士冠朝士，最談蘇與張。',48,'全唐诗/poet.song.139000.json','["蜀士冠朝士，最談蘇與張。", "少公今是似，相國未應亡。", "黄閣如寒素，青春已老蒼。", "新功知更進，餘事出文章。"]'),
('7e3b7a67-51c2-422a-b17f-06cdcd59d0a5','宿龍回','楊萬里','宋','宋诗','song-poetry','','[]','大熟虛成喜，微生亦可嗟。',48,'全唐诗/poet.song.139000.json','["大熟虛成喜，微生亦可嗟。", "禾頭已生耳，雨脚尚如麻。", "頃者官收米，精於玉絕瑕。", "四山雲又合，奈爾老農家。"]'),
('388a672b-0fff-4f9b-a2f1-ccba927cfab3','見潭帥劉恭父舍人二首  其一','楊萬里','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','雲霧開衡嶽，波濤息洞庭。',48,'全唐诗/poet.song.139000.json','["雲霧開衡嶽，波濤息洞庭。", "是邦誰岳牧，西掖一文星。", "有眼難人物，斯人尚典刑。", "如何閑處著，不遣肅朝廷。"]'),
('2e662b05-f1d9-4b1f-b0c3-37c7f492139f','見潭帥劉恭父舍人二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','道合寧嫌晚，心期不用多。',48,'全唐诗/poet.song.139000.json','["道合寧嫌晚，心期不用多。", "於公猶未見，此恨獨如何。", "頗辱談間問，端須雪裏過。", "門闌當欠士，許寄病身麽。"]'),
('168ab416-3fd6-413a-bdff-49ec9815360c','蜀士甘彥和寓張魏公門館用予見張欽夫詩韻作二詩見贈和以謝之  其一','楊萬里','宋','宋诗','song-poetry','','[]','說著岷江士，未逢眉已申。',48,'全唐诗/poet.song.139000.json','["說著岷江士，未逢眉已申。", "殷勤來相府，解逅得詩人。", "不是胸中別，何緣句子新。", "談今還悼昔，喜罷反悲辛。"]'),
('8953cc58-4430-4da0-ae41-5f12bf08c786','蜀士甘彥和寓張魏公門館用予見張欽夫詩韻作二詩見贈和以謝之  其二','楊萬里','宋','宋诗','song-poetry','','[]','夜把新詩讀，燈前闔且開。',48,'全唐诗/poet.song.139000.json','["夜把新詩讀，燈前闔且開。", "一行私獨喜，兩脚不虛來。", "天似嫌梅晚，冬初遣雪催。", "與君問花信，能繞百千回。"]'),
('795a95f2-2f2b-45a5-83c5-98b6e01377bf','和侯彥周知縣招飲','楊萬里','宋','宋诗','song-poetry','','[]','乘興山陰更灞橋，人間此事久寥寥。',32,'全唐诗/poet.song.139000.json','["乘興山陰更灞橋，人間此事久寥寥。", "客心也欲將歸去，小爲故人留一宵。"]'),
('2e421a29-346a-467a-b66b-4f2f4a6574b9','和吳伯承提宮孟冬風雨','楊萬里','宋','宋诗','song-poetry','','[]','舊雨新更寒，晝歇夜復隕。',120,'全唐诗/poet.song.139000.json','["舊雨新更寒，晝歇夜復隕。", "我行十日泥，屨跡故未泯。", "吟聲正酸苦，已似琴促軫。", "更遭雪作祟，不由絃不緊。", "與公無詩債，何得便見窘。", "半生領盛名，一面辱傾囷。", "眼底過浮雲，誰見柳下憫。", "覓句許奇險，有底惱肝腎。", "開懷愛我多，落筆爲渠盡。", "獨憐禾頭濕，可歡不可哂。"]'),
('efd1ba1e-1af7-46e2-8195-b840986a1b73','題清江胡民瞻忍堂','楊萬里','宋','宋诗','song-poetry','','[]','俗物茫茫奈我何，兒女昵昵不用呵。',67,'全唐诗/poet.song.139000.json','["俗物茫茫奈我何，兒女昵昵不用呵。", "先生笑問有酒麽，醉來得句自長哦。", "家風孝友春風軟，牀無黄金且青簡。", "君不見多愁多惱張公藝，枉却御前百餘字。"]'),
('53fced3d-02a7-48bb-be5f-28fe838d463c','除夕宿臨川戰平','楊萬里','宋','宋诗','song-poetry','','[]','一臘天頻雪，千山梅未花。',48,'全唐诗/poet.song.139000.json','["一臘天頻雪，千山梅未花。", "終年不爲客，除夕恰辭家。", "雨又垂垂落，風仍故故斜。", "難開愁裏眼，只益鬢邊華。"]'),
('1614660d-97e6-4365-8b3d-c61428b81598','紀聞','楊萬里','宋','宋诗','song-poetry','','[]','人道真虛席，心知必數公。',48,'全唐诗/poet.song.139000.json','["人道真虛席，心知必數公。", "賓王欺釣築，君實誤兒童。", "天在昇平外，春歸小雪中。", "何曾忘諸老，渠自愛松風。"]'),
('ed07248b-d66b-4079-bbbb-e94907ccb57e','又除夕絕句','楊萬里','宋','宋诗','song-poetry','','[]','紫陌相逢誰不客，青燈作伴未爲孤。',32,'全唐诗/poet.song.139000.json','["紫陌相逢誰不客，青燈作伴未爲孤。", "何須家裏作時節，只問旗亭有酒無。"]'),
('610edb48-e3c7-4897-a7d9-9a0b00f7ce07','丁亥正月新晴晚步二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','嫩水春來別樣光，草芽綠甚却成黄。',32,'全唐诗/poet.song.139000.json','["嫩水春來別樣光，草芽綠甚却成黄。", "東風似與行人便，吹盡寒雲放夕陽。"]'),
('7388a5d0-de02-4675-9c64-c8e247ef7623','丁亥正月新晴晚步二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','急下柴車踏晚晴，青鞋步步有沙聲。',32,'全唐诗/poet.song.139000.json','["急下柴車踏晚晴，青鞋步步有沙聲。", "忽逢野沼無人處，兩鴨浮沉最眼明。"]'),
('5d205463-79f4-4d7f-a79e-87df99b5036b','過安仁岸','楊萬里','宋','宋诗','song-poetry','','[]','野水工穿石，疎林不掩巢。',48,'全唐诗/poet.song.139000.json','["野水工穿石，疎林不掩巢。", "雨蒲拳病葉，風篠秃危梢。", "短脛知難續，長腰强自抄。", "茲游良不惡，物色困詼嘲。"]'),
('4a1d183a-d4af-4b90-a6c3-f2ef45675d75','早行鳴山二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','淡淡清霜薄薄冰，曉寒端爲作新晴。',32,'全唐诗/poet.song.139000.json','["淡淡清霜薄薄冰，曉寒端爲作新晴。", "殷勤喚醒梅花睡，枝上春禽一兩聲。"]'),
('fdbe7ff0-f6b4-4c6f-9dfb-1ee9c415902e','早行鳴山二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','靈山未見見龜山，且捲詩書子細看。',32,'全唐诗/poet.song.139000.json','["靈山未見見龜山，且捲詩書子細看。", "春日幸從年後暖，春風須带臘前寒。"]'),
('e45c325e-135e-44ed-bdc6-e2f860ed8ead','明發弋陽縣','楊萬里','宋','宋诗','song-poetry','','[]','燈市通宵沸，朝來解一空。',48,'全唐诗/poet.song.139000.json','["燈市通宵沸，朝來解一空。", "梅邊霜似雪，霧外日如虹。", "句妙元非作，人窮未必工。", "忽驚家已遠，身在大江東。"]'),
('0db88a30-43ee-4664-a407-bfdb0072bb75','霧中見靈山依約不真','楊萬里','宋','宋诗','song-poetry','','[]','東來兩眼不曾寒，四顧千峰掠曉鬟。',32,'全唐诗/poet.song.139000.json','["東來兩眼不曾寒，四顧千峰掠曉鬟。", "天欲惱人消幾許，只教和霧看靈山。"]'),
('5c335479-fdf1-4299-ba2e-0b847da1e20b','題小沙溪鄭氏店江亭','楊萬里','宋','宋诗','song-poetry','','[]','隔水千山又萬山，大江仍合小溪灣。',32,'全唐诗/poet.song.139000.json','["隔水千山又萬山，大江仍合小溪灣。", "岸巾獨立東風裏，眼趁鳬雛下急灘。"]'),
('7ebd505b-071b-4531-8be0-c6891a64c25d','又題鄭店立春後一日','楊萬里','宋','宋诗','song-poetry','','[]','石壁仍叢竹，江亭更小樓。',48,'全唐诗/poet.song.139000.json','["石壁仍叢竹，江亭更小樓。", "灘聲清客夢，燈影動詩愁。", "春日已虛過，元宵看又休。", "誰令不行樂，蹙破兩眉頭。"]'),
('9a7b58e0-d6eb-40e3-9d12-6d61ff9bd733','上元日晚過順溪','楊萬里','宋','宋诗','song-poetry','','[]','恰恰元宵雨脚垂，天風爲我掃除之。',32,'全唐诗/poet.song.139000.json','["恰恰元宵雨脚垂，天風爲我掃除之。", "怪來平地寒如許，雪滿遠峰人未知。"]'),
('357efd81-ce9a-4a94-8072-da0d7d5b4709','白沙買船晚至嚴州','楊萬里','宋','宋诗','song-poetry','','[]','重霧疑朝雨，斜陽竟晚晴。',48,'全唐诗/poet.song.139000.json','["重霧疑朝雨，斜陽竟晚晴。", "萬山江外盡，一塔嶺尖明。", "舟小寧嫌窄，途長已倦行。", "子陵臺下水，未酌意先清。"]'),
('2534bf57-a93b-4a95-96a9-ebd8f5fa64bb','題釣臺二絕句  其一','楊萬里','宋','宋诗','song-poetry','','[]','斷崖初未有人蹤，只合先生著此中。',32,'全唐诗/poet.song.139000.json','["斷崖初未有人蹤，只合先生著此中。", "漢室也無一抔土，釣臺今是幾春風。"]'),
('4409214e-f3ee-417a-bc3c-e010c43a4f6d','題釣臺二絕句  其二','楊萬里','宋','宋诗','song-poetry','','[]','同學書生已冕旒，未將換與一羊裘。',32,'全唐诗/poet.song.139000.json','["同學書生已冕旒，未將換與一羊裘。", "子雲到老不曉事，不信人間有許由。"]'),
('f91e1f66-5b60-4d1f-adfa-f3206a4ec8d5','和周子中韻','楊萬里','宋','宋诗','song-poetry','','[]','清愁政爾喜逢兄，一笑那知客帝城。',64,'全唐诗/poet.song.139000.json','["清愁政爾喜逢兄，一笑那知客帝城。", "海氣不曾晴色好，梨花半落嫩寒生。", "刑書夜誦端何苦，詩句春來想不平。", "我亦有懷無處說，對床只欲爲渠傾。"]'),
('16b2440e-4066-4066-b4ef-3eda542bb45b','都下無憂館小樓春盡旅懷二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','病眼逢書不敢開，春泥謝客亦無來。',32,'全唐诗/poet.song.139000.json','["病眼逢書不敢開，春泥謝客亦無來。", "更無短計銷長日，且遶欄干一百回。"]'),
('cebca2cf-6d8a-491a-90cf-53cd65802ff3','都下無憂館小樓春盡旅懷二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','不關老去願春遲，只恨春歸我未歸。',32,'全唐诗/poet.song.139000.json','["不關老去願春遲，只恨春歸我未歸。", "最是楊花欺客子，向人一一作西飛。"]'),
('8247494f-1047-4e30-a790-efa8d2d4e147','新熱送同邸歸客有感二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','日日思親未拜親，何時乞我自由身。',32,'全唐诗/poet.song.139000.json','["日日思親未拜親，何時乞我自由身。", "同來客子送歸盡，更送後來無數人。"]'),
('10ed5d67-6112-4451-9ac2-f2b29cadd68d','新熱送同邸歸客有感二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','瘦不緣詩不爲春，只教懸罄未教行。',32,'全唐诗/poet.song.139000.json','["瘦不緣詩不爲春，只教懸罄未教行。", "清和天裏不歸去，六月長途作麽生。"]'),
('ac99f128-486a-41f5-b2bb-9f1848c86b4f','跋蜀人魏致堯撫幹萬言書','楊萬里','宋','宋诗','song-poetry','','[]','雨裏短檠頭似雪，客間長鋏食無魚。',32,'全唐诗/poet.song.139000.json','["雨裏短檠頭似雪，客間長鋏食無魚。", "上書慟哭君何苦，政是時人重子虛。"]'),
('6d3b6f4f-43f4-4ba2-be7e-6f56d2980eb0','桐廬道中','楊萬里','宋','宋诗','song-poetry','','[]','肩輿坐睡茶力短，野堠無文山路長。',32,'全唐诗/poet.song.139000.json','["肩輿坐睡茶力短，野堠無文山路長。", "鴉鵲聲歡人不會，枇杷一樹十分黄。"]'),
('092ba813-3ef4-4a36-a2f9-f6ecf1946363','金溪道中','楊萬里','宋','宋诗','song-poetry','','[]','野花垂路止人行，田水偏尋缺處鳴。',32,'全唐诗/poet.song.139000.json','["野花垂路止人行，田水偏尋缺處鳴。", "近浦人家隨曲折，插秧天氣半陰晴。"]'),
('7cde6ed2-9335-4f3b-b5f6-27721feccc4d','將至建昌','楊萬里','宋','宋诗','song-poetry','','[]','梅雨芹泥路不佳，悶來小歇野人家。',32,'全唐诗/poet.song.139000.json','["梅雨芹泥路不佳，悶來小歇野人家。", "綠萍池沼垂楊裏，初見芙蕖第一花。"]'),
('7870c0bf-7b47-4797-b9ed-f4f513bc193d','見王宣子侍郎二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','不作伾文客，投閑可得辭。',48,'全唐诗/poet.song.139000.json','["不作伾文客，投閑可得辭。", "高名真自累，了事竟成癡。", "到底須良匠，非渠更阿誰。", "莫嫌風雪惡，要試歲寒枝。"]'),
('72a05f08-b83f-4c82-8415-23911573b758','見王宣子侍郎二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','老去渾多難，愁來敢怨天。',48,'全唐诗/poet.song.139000.json','["老去渾多難，愁來敢怨天。", "生遭文字誤，更結簿書緣。", "苦憶懸間榻，難回雪後船。", "三年纔一見，百歲幾三年。"]'),
('c1f15c28-15e5-4286-aa67-45d0a3d0b952','都下和同舍客李元老承信贈詩之韻','楊萬里','宋','宋诗','song-poetry','','[]','論交何必星霜久，白頭得似傾蓋友。',288,'全唐诗/poet.song.139000.json','["論交何必星霜久，白頭得似傾蓋友。", "長安市上李將軍，挽弓舊不論石斗。", "只今有子似渠長，清夜讀書雪邊牖。", "雲端烽煙半點無，怪來將軍不好武。", "遺我驪珠三百顆，字字鎸鑱未曾苟。", "得得且看錢塘潮，莫莫言攀渭城柳。", "朝家金印斗樣大，情知不上書生肘。", "儒冠多誤儂飽諳，毛錐焉用君知否。", "便應早請終軍纓，徑須繫取單于首。", "居延蒲類水如天，吹作春風一杯酒。", "歸來冠劍上凌煙，剩作功名落人口。", "如何收斂許光芒，也趁槐花黄裏走。", "獻璞雖真不救脛，絕絃何如只停手。", "人生匹似風中花，榮瘁昇沈豈非偶。", "與君早賦歸去來，名垂萬古知何有。", "不如耳熱歌嗚嗚，醉帽欹傾衣不紐。", "詩流唱和秋蟲鳴，僧房問答獅子吼。", "儘令俗客不妨來，白眼相看勿分剖。"]'),
('2b15a7cf-496d-458b-8e87-f2f71c789487','新淦拋江','楊萬里','宋','宋诗','song-poetry','','[]','煙雨橫江水著天，不曾夏澇似今年。',32,'全唐诗/poet.song.139000.json','["煙雨橫江水著天，不曾夏澇似今年。", "緣堤何用千株柳，只與行人礙過船。"]'),
('19d83980-2119-4bff-a923-48df7b407d34','還家秋夕飲中喜雨','楊萬里','宋','宋诗','song-poetry','','[]','好風有意入金臺，白酒無聲落玉杯。',32,'全唐诗/poet.song.139000.json','["好風有意入金臺，白酒無聲落玉杯。", "秋雨亦嫌秋熱在，打荷飄竹爲人來。"]'),
('7138fbb4-ae00-437b-882d-0470b9a28826','和李天麟秋懷五絕句  其一','楊萬里','宋','宋诗','song-poetry','','[]','漫浪歸來歲又秋，依然風月替人愁。',32,'全唐诗/poet.song.139000.json','["漫浪歸來歲又秋，依然風月替人愁。", "奉酬只麽隨緣句，嬾更雕肝與探鈎。"]'),
('55503374-563b-4071-af94-684bb11e8deb','和李天麟秋懷五絕句  其二','楊萬里','宋','宋诗','song-poetry','','[]','雙井無人後山死，只今誰子定傳燈。',32,'全唐诗/poet.song.139000.json','["雙井無人後山死，只今誰子定傳燈。", "老夫言語渾無味，不但秋來面可憎。"]'),
('f7122658-ad06-4993-acc4-ca221a8a7b89','和李天麟秋懷五絕句  其三','楊萬里','宋','宋诗','song-poetry','','[]','小立南溪暮未還，略容老子照衰顔。',32,'全唐诗/poet.song.139000.json','["小立南溪暮未還，略容老子照衰顔。", "頗驚暝色來天外，未必秋聲在樹間。"]'),
('3df439e1-61af-4e52-9adf-816bec9c35e2','和李天麟秋懷五絕句  其四','楊萬里','宋','宋诗','song-poetry','','[]','綴玉聯珠辱見投，要知詞客解悲秋。',32,'全唐诗/poet.song.139000.json','["綴玉聯珠辱見投，要知詞客解悲秋。", "儂家幸自無煩惱，却被新詩嫁許愁。"]'),
('2af6ca94-4ec8-447d-8f97-d17a863d2573','和李天麟秋懷五絕句  其五','楊萬里','宋','宋诗','song-poetry','','[]','夜把新詩百遍開，句如紅藥與蒼苔。',32,'全唐诗/poet.song.139000.json','["夜把新詩百遍開，句如紅藥與蒼苔。", "如何作許無端甚，押盡車斜始送來。"]'),
('d6b7e7c1-913d-4528-bb61-cc60e4c2d4a5','送相士高元善二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','選官選佛兩悠悠，元不關人浪自愁。',32,'全唐诗/poet.song.139000.json','["選官選佛兩悠悠，元不關人浪自愁。", "洙泗生涯久春草，老夫作麽晚回頭。"]'),
('675631d7-89f3-4050-9dbe-2b20293a507b','送相士高元善二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','穉子煩君一一看，丁寧莫道好求官。',32,'全唐诗/poet.song.139000.json','["穉子煩君一一看，丁寧莫道好求官。", "老來正要團欒坐，伴我秋風把釣竿。"]'),
('c15e9533-1345-49da-8285-df4d1a5bfed8','出城途中小憩','楊萬里','宋','宋诗','song-poetry','','[]','未到江城已日斜，山煙白處是人家。',32,'全唐诗/poet.song.139000.json','["未到江城已日斜，山煙白處是人家。", "秋風畢竟無多巧，只把燕支滴蓼花。"]'),
('56b7b26e-364e-49fa-ab8a-31797be66fbc','題周子中司戶乘成臺三首  其一','楊萬里','宋','宋诗','song-poetry','','[]','不煩營築便成臺，自有青松不用栽。',32,'全唐诗/poet.song.139000.json','["不煩營築便成臺，自有青松不用栽。", "只道先生忙更嬾，也須一日一回來。"]'),
('42e5423d-57f5-473c-988c-1c0957d1d904','題周子中司戶乘成臺三首  其二','楊萬里','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','只須獨立領秋光，何用安排石鼓雙。',32,'全唐诗/poet.song.139000.json','["只須獨立領秋光，何用安排石鼓雙。", "平揖青原未爲差，更於竹外見長江。"]'),
('5521c17b-f715-4f4d-a883-f0d65a54cd24','題周子中司戶乘成臺三首  其三','楊萬里','宋','宋诗','song-poetry','','[]','先生無劓何須補，上到乘成儘放懷。',32,'全唐诗/poet.song.139000.json','["先生無劓何須補，上到乘成儘放懷。", "松樹尚堪驅使在，爲公一一捧詩牌。"]'),
('e77b13aa-a96b-46cb-929f-0771518a76eb','三辰硯屏歌','楊萬里','宋','宋诗','song-poetry','','[]','天小紫，日淡紅，月光正與日相通。',207,'全唐诗/poet.song.139000.json','["天小紫，日淡紅，月光正與日相通。", "一星雪白大於黍，走近月旁無半武。", "吾聞三辰不並明，如何日中見月星。", "霜後梨花定非瑞，春秋獲麟不應貴。", "君不見八月十五夜向晨，東方亭亭升火輪，西有玉李伴金盆。", "是時三辰正如許，君不著眼君莫論。", "吾家大阮嗜文字，看書到曉那能睡。", "三辰并光射窗几，影落硯屏不容洗。", "就中月輪景特奇，桂樹可數葉與枝。", "炯如秋水涵荇藻，天巧此豈人能爲。", "懷璧未爲罪，借書未爲癡。", "公當十襲古錦帊，如何傳翫十手把，不防夜半有力者。"]'),
('b0fc0758-7105-42b3-991b-7f2b54faa488','題文發叔所藏潘子真水墨江湖八境小軸 洞庭波漲','楊萬里','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','湖水吞天去，湖風送浪還。',24,'全唐诗/poet.song.139000.json','["湖水吞天去，湖風送浪還。", "銀山何處是，青底是君山。"]'),
('5f67a681-ec70-4a35-ab71-2e22823e6841','題文發叔所藏潘子真水墨江湖八境小軸 武昌春色','楊萬里','宋','宋诗','song-poetry','','[]','花外庾樓月，鶑邊吳宮柳。',24,'全唐诗/poet.song.139000.json','["花外庾樓月，鶑邊吳宮柳。", "我欲問廢興，春風獨無口。"]'),
('46e0eb44-510b-49f3-b5c9-c9551a5c4530','題文發叔所藏潘子真水墨江湖八境小軸 廬山霽色','楊萬里','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','彭澤收積雨，廬山放嫩晴。',24,'全唐诗/poet.song.139000.json','["彭澤收積雨，廬山放嫩晴。", "多情是瀑布，只作雨中聲。"]'),
('9d9ce1a2-bbe2-4376-acf9-f08f6d5acace','題文發叔所藏潘子真水墨江湖八境小軸 海門殘照','楊萬里','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','萬里長江白，半規斜日黄。',24,'全唐诗/poet.song.139000.json','["萬里長江白，半規斜日黄。", "焦山渾欲到，宛在水中央。"]'),
('6ea761b4-b164-49bb-aed1-319d2aeaf27a','題文發叔所藏潘子真水墨江湖八境小軸 太湖秋晚','楊萬里','宋','宋诗','song-poetry','','["\u592a\u6e56"]','水氣清空外，人家秋色中。',24,'全唐诗/poet.song.139000.json','["水氣清空外，人家秋色中。", "細看千萬落，戶戶水精宮。"]'),
('53d6a407-1a89-44c1-a3b2-b030f60ad0a5','題文發叔所藏潘子真水墨江湖八境小軸 浙江觀潮','楊萬里','宋','宋诗','song-poetry','','["\u94b1\u5858\u6c5f"]','海湧銀爲郭，江橫玉繫腰。',24,'全唐诗/poet.song.139000.json','["海湧銀爲郭，江橫玉繫腰。", "吳儂只言黠，到老也看潮。"]'),
('b4dc5634-7c92-4725-9e85-93e164c2a0ec','題文發叔所藏潘子真水墨江湖八境小軸 西湖夏日','楊萬里','宋','宋诗','song-poetry','','["\u897f\u6e56"]','四月曾湖上，荷錢劣可穿。',24,'全唐诗/poet.song.139000.json','["四月曾湖上，荷錢劣可穿。", "歸來開短紙，十里已紅蓮。"]'),
('a7ae57ab-e846-4208-a366-8f687be28dd0','題文發叔所藏潘子真水墨江湖八境小軸 靈隠冷泉','楊萬里','宋','宋诗','song-poetry','','[]','小潘詩家子，解作無聲詩。',24,'全唐诗/poet.song.139000.json','["小潘詩家子，解作無聲詩。", "八境俱妙絕，冷泉天下奇。"]'),
('b6f5d441-a80e-4cd0-a421-631d02833d74','和文黼主簿叔惠詩之韻','楊萬里','宋','宋诗','song-poetry','','[]','薄宦江湖苦異途，十年骨肉隔音書。',64,'全唐诗/poet.song.139000.json','["薄宦江湖苦異途，十年骨肉隔音書。", "此行政爾見公面，又迫歸歟巾我車。", "安得從容林下去，相從漫浪物之初。", "念公不是漁竿客，合結絲絇立玉除。"]'),
('7823b226-8d84-47dd-913c-84fe684804b0','秋曉出郊二絕句  其一','楊萬里','宋','宋诗','song-poetry','','[]','初日新寒政曉霞，殘山剩水稍人家。',32,'全唐诗/poet.song.139000.json','["初日新寒政曉霞，殘山剩水稍人家。", "霜紅半臉金罌子，雪白一川蕎麥花。"]'),
('39ef3651-542c-4e1b-b91e-d3a6424d7953','秋曉出郊二絕句  其二','楊萬里','宋','宋诗','song-poetry','','[]','野菊相依露下叢，冷香自送水邊風。',32,'全唐诗/poet.song.139000.json','["野菊相依露下叢，冷香自送水邊風。", "豐年氣象無多子，只在雞鳴犬吠中。"]'),
('67762377-a3ce-4157-a585-a4129baa2c24','送楊山人善談相及地理','楊萬里','宋','宋诗','song-poetry','','[]','相人何似相山難，慙媿渠儂眼不寒。',32,'全唐诗/poet.song.139000.json','["相人何似相山難，慙媿渠儂眼不寒。", "木末凉風無半點，如何又欲跨歸鞍。"]'),
('2a686ed7-e899-45d7-82b0-6d77fb2af237','胡英彥得歐陽公二帖蓋訓其子仲純叔弼之語其一公自書之其一東坡書之英彥刻石以遺朋友吾叔父春卿得一本有詩謝英彥和焉萬里用其韻以簡英彥','楊萬里','宋','宋诗','song-poetry','','[]','聖處眇安在，談者一何易。',240,'全唐诗/poet.song.139000.json','["聖處眇安在，談者一何易。", "注瓦矜細巧，岑鼎喪良貴。", "群兒有新舌，六學無故意。", "向來孟韓息，不有歐蘇繼。", "庸知後死者，未渠鄉愿棄。", "同時鴟鴉噪，並起爪觜利。", "兩公察膏肓，與世作薑桂。", "挾山初作難，破竹忽乘勢。", "雙明日配月，再立仁與義。", "我有香一瓣，恨不生並世。", "厥今聖域裏，澹叟真守器。", "怪來蘭玉秀，渠以清白遺。", "當家有學林，滿腹惟典記。", "人間市井言，眼底寇讎視。", "獨於兩公帖，費此半生喜。", "麝煤叩山骨，卧聽丁丁美。", "令我竹林老，亦復拜嘉惠。", "敢云賡絕唱，頗欲與茲事。", "朝來窗几爽，盡室問何瑞。", "寶帖更新詩，小子汝其志。"]'),
('255f8166-6545-4af3-b850-be14bee9953f','寄題張欽夫春風樓','楊萬里','宋','宋诗','song-poetry','','[]','樂齋先生子張子，獨立春風望洙泗。',128,'全唐诗/poet.song.139000.json','["樂齋先生子張子，獨立春風望洙泗。", "四海無人萬古空，詠歌一聲滿天地。", "不應東閣勝東山，浮雲於渠了不關。", "只餘平生醫國手，未忍旁觀縮袖間。", "樓中古書積至斗，樓外春江綠如酒。", "權門得似聖門寒，萬波橫流獨回首。", "向來沂上瑟聲希，由求相顧只心知。", "至今留取一轉語，不知何詠亦何歸。"]'),
('94ed81ae-f383-4d64-9338-55e99bc3b429','四印室長句效劉信夫作呈信夫','楊萬里','宋','宋诗','song-poetry','','[]','廣文眼力自超然，作室題詩字字研。',128,'全唐诗/poet.song.139000.json','["廣文眼力自超然，作室題詩字字研。", "憤世嫉邪聊爾耳，未必崔君真鶴言。", "涪州別駕亦浪語，渠家四印何曾鑄。", "漫向世人言養生，涪州却回宜州去。", "廣文平生不解愁，只將詩句敵清秋。", "白浪如山風打頭，江南江北一虛舟。", "坐上無氈惟有客，青燈枉草强邊策。", "萬言萬當不如默，誤人又指庭前柏。"]'),
('67c29626-6793-4d62-96f3-1cab9ebae0f9','題劉德夫真意亭二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','湖上軒窗岸岸開，誰家不傍讀書臺。',32,'全唐诗/poet.song.139000.json','["湖上軒窗岸岸開，誰家不傍讀書臺。", "新亭自有人知處，只揀風煙好處來。"]'),
('c2ee6e41-528e-49ff-8569-9535403b35c8','題劉德夫真意亭二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','淵明有意自忘言，真處如今底處傳。',32,'全唐诗/poet.song.139000.json','["淵明有意自忘言，真處如今底處傳。", "客子若來問真意，鏡中人影水中天。"]'),
('1600775c-f47c-4b8b-82f1-ecd5a2bf1d94','題蕭岳英常州草蟲軸蓋畫師之女朱氏之筆二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','常州草蟲天下奇，女郎新樣不緣師。',32,'全唐诗/poet.song.139000.json','["常州草蟲天下奇，女郎新樣不緣師。", "未應好手傳輪扁，便恐前身是郭熙。"]'),
('b289f929-3cdf-4d60-949d-a01244fd4084','題蕭岳英常州草蟲軸蓋畫師之女朱氏之筆二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','筆端春草已如生，點綴蟲沙更未停。',32,'全唐诗/poet.song.139000.json','["筆端春草已如生，點綴蟲沙更未停。", "淺著鵝黄作蝴蝶，深將猩血染蜻蜓。"]'),
('2ed155cd-de96-48d0-861b-092a66708d4e','過雙陂','楊萬里','宋','宋诗','song-poetry','','[]','霜後寒溪清更清，冰如溪水水如冰。',32,'全唐诗/poet.song.139000.json','["霜後寒溪清更清，冰如溪水水如冰。", "閑行也有窮忙事，問訊梅花開未曾。"]'),
('83a6ff9f-870c-4869-b881-92cbbe8ea818','夜宿王才臣齋中睡覺聞風雪大作','楊萬里','宋','宋诗','song-poetry','','[]','雨外風非細，風中雪更飛。',48,'全唐诗/poet.song.139000.json','["雨外風非細，風中雪更飛。", "夜聲吹不盡，寒客卧相依。", "一醉醒醒了，平生事事非。", "終年纔小款，明日又言歸。"]'),
('81a4669c-e4b8-4839-8bbc-e9bfb39886ba','和羅巨濟山居十詠  其一','楊萬里','宋','宋诗','song-poetry','','[]','世方爭速化，渠獨請真祠。',48,'全唐诗/poet.song.139000.json','["世方爭速化，渠獨請真祠。", "意在昇沉外，官無冷熱宜。", "山如輞川畫，地似習家池。", "若道閑居嬾，如何有十詩。"]'),
('5b0b731a-3612-4a6b-9ec6-0605d8602d05','和羅巨濟山居十詠  其二','楊萬里','宋','宋诗','song-poetry','','[]','老子朝慵起，春風苦喚行。',48,'全唐诗/poet.song.139000.json','["老子朝慵起，春風苦喚行。", "晴邊猶著雪，寒後未聞鶑。", "偶見千峰翠，偏令兩眼明。", "倦來渾欲睡，無處避溪聲。"]'),
('27799089-74d2-47b2-9761-158ea644bc4e','和羅巨濟山居十詠  其三','楊萬里','宋','宋诗','song-poetry','','[]','只擁書千卷，何須屋萬間。',48,'全唐诗/poet.song.139000.json','["只擁書千卷，何須屋萬間。", "新堂傍溪水，大字署蓬山。", "恰有乘風客，來分半日閑。", "自煎蝦蟹眼，同瀹鷓鴣斑。"]'),
('709d42ed-1cef-4de2-ab8e-177c32808c47','和羅巨濟山居十詠  其四','楊萬里','宋','宋诗','song-poetry','','[]','漫浪真堪老，丁寧勿語人。',48,'全唐诗/poet.song.139000.json','["漫浪真堪老，丁寧勿語人。", "屐痕渾似齒，巾角小於綸。", "從事固不惡，賢人也似醇。", "空瓶未應卧，只恐惱比鄰。"]'),
('047c605c-6f1e-448c-afae-5a2cff65570b','和羅巨濟山居十詠  其五','楊萬里','宋','宋诗','song-poetry','','[]','園花皆手植，梅蕊獨禁寒。',48,'全唐诗/poet.song.139000.json','["園花皆手植，梅蕊獨禁寒。", "色與香無價，飛和雪作團。", "數枝橫翠竹，一夜遶朱欄。", "不惜吟邊苦，收將句裏看。"]'),
('90b069e8-66d7-411a-a8fa-eb58e42559f3','和羅巨濟山居十詠  其六','楊萬里','宋','宋诗','song-poetry','','[]','花柳春全盛，池塘燕學飛。',48,'全唐诗/poet.song.139000.json','["花柳春全盛，池塘燕學飛。", "晚晴還小立，暮色不能歸。", "草遠天無壁，苔深水有衣。", "山居自清絕，不必扣禪扉。"]'),
('58b2425b-8d33-4e11-8d4c-f87da61c7afa','和羅巨濟山居十詠  其七','楊萬里','宋','宋诗','song-poetry','','[]','酒客來中散，詩僧約惠勤。',48,'全唐诗/poet.song.139000.json','["酒客來中散，詩僧約惠勤。", "共聽茅屋雨，添炷博山雲。", "萬事休多問，三杯且一醺。", "君看醉中語，不琢自成文。"]'),
('12e8e117-68d2-4181-a3f4-9d64d1c4ede4','和羅巨濟山居十詠  其八','楊萬里','宋','宋诗','song-poetry','','[]','秀溪何處好，臘尾與春初。',48,'全唐诗/poet.song.139000.json','["秀溪何處好，臘尾與春初。", "山色梅邊浄，人家竹裏居。", "先生來得得，一笑意舒舒。", "歸路無燈火，冰輪掛嶺隅。"]'),
('1a07a58b-0339-4cc0-8244-da3d5b2419dc','和羅巨濟山居十詠  其九','楊萬里','宋','宋诗','song-poetry','','[]','且愛燈檠短，寧論劍鋏長。',48,'全唐诗/poet.song.139000.json','["且愛燈檠短，寧論劍鋏長。", "芝蘭照春紫，編簡著人香。", "賀監聊吳語，昌黎豈楚狂。", "豹文元炳蔚，未信霧能藏。"]'),
('a2c00021-c82b-4a57-8d29-dfb25fd54b79','和羅巨濟山居十詠  其一○','楊萬里','宋','宋诗','song-poetry','','[]','眼底無羣子，毫端有百川。',48,'全唐诗/poet.song.139000.json','["眼底無羣子，毫端有百川。", "脩名如揭月，餘事亦凌煙。", "剩欲携藤去，相從聽雨眠。", "恐渠即霄漢，泉石罷潺湲。"]'),
('2031ba88-1887-4cb2-ad2c-a8987492ca68','趙通判恭人周氏挽辭','楊萬里','宋','宋诗','song-poetry','','[]','早與梁鴻隠，中隨士會歸。',48,'全唐诗/poet.song.139000.json','["早與梁鴻隠，中隨士會歸。", "一門忠義氣，千古日星暉。", "紫告金花詔，青燈錦字機。", "西峰今夜月，墳是昔人非。"]'),
('a362d55e-2c37-4dd4-b718-332d831bec1b','老眼廢書有歎','楊萬里','宋','宋诗','song-poetry','','[]','老矣書無分，居然眼有花。',48,'全唐诗/poet.song.139000.json','["老矣書無分，居然眼有花。", "墨兵非死友，陸諝且生涯。", "雪後霜逾勁，吟邊帽只斜。", "小兒知我嬾，夜誦故喧譁。"]'),
('84e0e94f-02c5-4bb2-95cc-0adac39ce126','過蕉坑','楊萬里','宋','宋诗','song-poetry','','[]','楓葉乾餘尚小紅，苕花飛盡不留茸。',32,'全唐诗/poet.song.139000.json','["楓葉乾餘尚小紅，苕花飛盡不留茸。", "經旬欲雪還無雪，只作清寒惱殺儂。"]'),
('7d7f456c-d930-4921-8ab9-60e7608f44ab','和九叔知縣昨遊長句','楊萬里','宋','宋诗','song-poetry','','[]','詩窮不但兩鬢霜，白髮緣愁千丈長。',96,'全唐诗/poet.song.139000.json','["詩窮不但兩鬢霜，白髮緣愁千丈長。", "一年强半走道路，歸來又見橘柚黄。", "不如南鄰更此里，醉折梅花照溪水。", "扶藜時躡大阮蹤，覓句深參少陵髓。", "昨遊過眼不可留，今朝欲再亦何由。", "新詩已落萬人口，不應更著錦囊收。"]'),
('4f916db3-5719-4687-a093-7d78989716d6','送王無咎善邵康節皇極數二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','安樂窩中書一編，君從何許得真傳。',32,'全唐诗/poet.song.139000.json','["安樂窩中書一編，君從何許得真傳。", "我無杜曲桑麻在，也道此生休問天。"]'),
('daaa6e58-79ba-4bb2-88cd-c50e30be0af6','送王無咎善邵康節皇極數二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','識盡江淮諸貴人，歸來盧水一番新。',32,'全唐诗/poet.song.139000.json','["識盡江淮諸貴人，歸來盧水一番新。", "問渠福將今誰子，容我昇平作倖民。"]'),
('85835024-7e7d-4677-8565-4b2c7d170564','看雪','楊萬里','宋','宋诗','song-poetry','','[]','揉雲剪水作風毬，夜落連明肯便休。',32,'全唐诗/poet.song.139000.json','["揉雲剪水作風毬，夜落連明肯便休。", "舊說六花元未試，偶看一片上駝裘。"]'),
('d9c514fe-9b85-474a-90f7-5a587911644b','送曾秀才歸永豐','楊萬里','宋','宋诗','song-poetry','','[]','白白茅柴强作春，青青燈火夜相親。',64,'全唐诗/poet.song.139000.json','["白白茅柴强作春，青青燈火夜相親。", "超然似子真翹楚，舊矣逢人誦過秦。", "覓舉不應專嗜古，能文安得却嫌貧。", "射科速化誰無術，誤向南溪更問津。"]'),
('1affc96d-6cf6-453b-8d3d-542124b9c44f','寄題鄒公橋','楊萬里','宋','宋诗','song-poetry','','[]','吾儕一事辦不曾，鄒公一橋了此生。',64,'全唐诗/poet.song.139000.json','["吾儕一事辦不曾，鄒公一橋了此生。", "省齋先生三大字，此橋便有千載意。", "今年天亦與護持，桃花春水不多肥。", "濟川題柱吾無夢，夢借新橋作釣磯。"]'),
('dec8e98c-dc53-40d9-9278-6afd45c867f4','贈曾相士二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','富貴真成一聚塵，饑寒選得萬年名。',32,'全唐诗/poet.song.139000.json','["富貴真成一聚塵，饑寒選得萬年名。", "心知那有揚州鶴，更問儂當作麽生。"]'),
('6932ddb7-c9ca-4cea-a5b4-4896819e86c0','贈曾相士二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','拋了儒書讀相書，却將冷眼看諸儒。',32,'全唐诗/poet.song.139000.json','["拋了儒書讀相書，却將冷眼看諸儒。", "曾生肯伴誠齋否，共箇漁舟入五湖。"]'),
('7ebdbe7a-645b-461f-bca5-7f8b88cf6a72','題蕭端虛和樂堂','楊萬里','宋','宋诗','song-poetry','','[]','玉笥風回峽山雨，兩公對床方軟語。',64,'全唐诗/poet.song.139000.json','["玉笥風回峽山雨，兩公對床方軟語。", "少公一生吟樣臞，長公半醉少公扶。", "白頭兄弟不多有，面如橘紅不關酒。", "紫荆花開連理枝，孝友未要時人知。"]'),
('8051bea1-89dd-4cc8-86e0-7d14e5ab2ebb','昌英知縣叔作歲坐上賦瓶裏梅花時坐上九人七首  其一','楊萬里','宋','宋诗','song-poetry','','[]','銷冰作水旋成家，猶似江頭竹外斜。',32,'全唐诗/poet.song.139000.json','["銷冰作水旋成家，猶似江頭竹外斜。", "試問坐中還幾客，九人而已更梅花。"]'),
('7d0ca588-40ea-4d81-9aaa-4d92ee2c78a0','昌英知縣叔作歲坐上賦瓶裏梅花時坐上九人七首  其二','楊萬里','宋','宋诗','song-poetry','','[]','膽樣銀瓶玉樣梅，北枝折得未全開。',32,'全唐诗/poet.song.139000.json','["膽樣銀瓶玉樣梅，北枝折得未全開。", "爲憐落莫空山裏，喚入詩人几案來。"]'),
('caa8c2fc-c62a-4f62-ae96-f559249cd46e','昌英知縣叔作歲坐上賦瓶裏梅花時坐上九人七首  其三','楊萬里','宋','宋诗','song-poetry','','[]','酒兵半已卧長瓶，更看梅兄巧盡情。',32,'全唐诗/poet.song.139000.json','["酒兵半已卧長瓶，更看梅兄巧盡情。", "醉插寒花望松雪，人間曾有箇般清。"]'),
('c72ee15b-3ffb-47bf-bf70-e4162b203c09','昌英知縣叔作歲坐上賦瓶裏梅花時坐上九人七首  其四','楊萬里','宋','宋诗','song-poetry','','[]','寒盡春生夜未央，酒狂狂似醒時狂。',32,'全唐诗/poet.song.139000.json','["寒盡春生夜未央，酒狂狂似醒時狂。", "吾人何用餐煙火，揉碎梅花和蜜霜。"]'),
('c73e1bc1-3a37-4538-8cbd-260523fd851a','昌英知縣叔作歲坐上賦瓶裏梅花時坐上九人七首  其五','楊萬里','宋','宋诗','song-poetry','','[]','衣染龍涎與麝臍，裁雲剪月作冰肌。',32,'全唐诗/poet.song.139000.json','["衣染龍涎與麝臍，裁雲剪月作冰肌。", "小瓶雪水無多子，只篸橫斜一兩枝。"]'),
('7cae26a9-32f4-42b8-b45b-886b5b16e8a4','昌英知縣叔作歲坐上賦瓶裏梅花時坐上九人七首  其六','楊萬里','宋','宋诗','song-poetry','','[]','雪凍霜封稍欲殘，殷勤折向坐中看。',32,'全唐诗/poet.song.139000.json','["雪凍霜封稍欲殘，殷勤折向坐中看。", "綺疎深閉珠簾密，不遣花愁半點寒。"]'),
('1044cb25-bc17-4f6f-914c-4acf3216daff','昌英知縣叔作歲坐上賦瓶裏梅花時坐上九人七首  其七','楊萬里','宋','宋诗','song-poetry','','["\u897f\u6e56"]','梅香不是不寒清，參遍橫枝酒未醒。',32,'全唐诗/poet.song.139000.json','["梅香不是不寒清，參遍橫枝酒未醒。", "夢入西湖疎影裏，覺來失却冷泉亭。"]'),
('81059eb9-ca0e-4e5d-a989-ce42709a7cc9','戊子正月六日雷雨感歎示壽仁子','楊萬里','宋','宋诗','song-poetry','','[]','今晨忽雷雨，天地又發春。',168,'全唐诗/poet.song.139000.json','["今晨忽雷雨，天地又發春。", "草木閟紅綠，生意察已欣。", "蟄蟲且徐動，餘寒未全仁。", "先生起裹頭，三歎一再顰。", "春風吹萬物，不吹先生貧。", "靖怨一束書，只博兩袴塵。", "自倚文字工，竟取造物嗔。", "小兒在傍笑，笑我浪苦辛。", "去年作客子，椒柏羨主人。", "在家不差勝，更用愁此身。", "先生亦一莞，我不如兒真。", "爲我滿眼酤，不問醨與醇。", "杖頭日百錢，無錢借諸隣。", "不然衣可典，及此花柳新。"]'),
('d5566d05-c4a8-4b5d-bbc3-496a7514c674','人日詰朝從昌英叔出謁','楊萬里','宋','宋诗','song-poetry','','[]','四序各自佳，要不如春時。',156,'全唐诗/poet.song.139000.json','["四序各自佳，要不如春時。", "何必花與柳，始愛春物熙。", "今晨駕言出，從公南山西。", "泥軟屨自愜，風嫩面不知。", "寒草動暖芽，晴山餘雨姿。", "水日亦相媚，蹙紋生碎暉。", "鳥聲豈爲我，我聽偶自怡。", "出門初憚煩，載塗乃忘歸。", "但令我意適，豈校出處爲。", "路人見我揖，屬我有所思。", "我不見其面，信口聊應之。", "徐悟恐忤物，欲謝已莫追。", "我率或似傲，彼慍獨得辭。"]'),
('0b3d3310-ce8f-49c2-910c-c4fcaa4f6e02','暮宿半塗','楊萬里','宋','宋诗','song-poetry','','[]','朝日在我東，夕日在我西。',84,'全唐诗/poet.song.139000.json','["朝日在我東，夕日在我西。", "我行日亦行，日歸我未歸。", "勢須就人宿，遠近或難期。", "平生太疎放，似黠亦似癡。", "如何今日行，不以衾枕隨。", "幸逢春小暄，倒睡莫解衣。", "借令今夕寒，我醉亦不知。"]'),
('cc59eb21-0be2-4527-8576-f14d3b1dd37a','次日醉歸','楊萬里','宋','宋诗','song-poetry','','[]','日晚頗欲歸，主人苦見留。',120,'全唐诗/poet.song.139000.json','["日晚頗欲歸，主人苦見留。", "我非不能飲，老病怯觥籌。", "人意不可違，欲去且復休。", "我醉彼自止，醉亦何足愁。", "歸路意昏昏，落日在嶺陬。", "竹裏有人家，欲憩聊一投。", "有叟喜我至，呼我爲君侯。", "告以我非是，俛笑仍掉頭。", "機心久已盡，猶有不下鷗。", "田父亦外我，我老誰與遊。"]'),
('70dd9852-d75b-4872-b45d-999ed7371ff6','上元夜里俗粉米爲繭絲書吉語置其中以占一歲之福禍謂之繭卜因戲作長句','楊萬里','宋','宋诗','song-poetry','','[]','去年上元客三衢，衝雨看燈强作娛。',144,'全唐诗/poet.song.139000.json','["去年上元客三衢，衝雨看燈强作娛。", "今年上元家裏住，村落無燈惟有雨。", "隔溪叢祠稍簫鼓，不知還有遊人否。", "兒女炊玉作繭絲，中藏吉語默有祈。", "小兒祝身取官早，小女只求蠶事好。", "先生平生笑兒癡，逢場亦復作兒嬉。", "不願著脚金華殿，不願增巢上林苑。", "只哦少陵七字詩，但得長年飽喫飯。", "心知繭卜未必然，醉中得卜喜欲癲。"]'),
('2c0a9e43-a864-476c-8d5c-4fe6e2b19672','送蕭仲和往長沙見張欽夫','楊萬里','宋','宋诗','song-poetry','','[]','蕭家伯氏難爲兄，蕭家仲氏難爲弟。',112,'全唐诗/poet.song.139000.json','["蕭家伯氏難爲兄，蕭家仲氏難爲弟。", "御史子孫今有誰，眼中乃見此二士。", "阿兄采蘭壽梅堂，阿弟束書參蜀張。", "聖門九鑰天爲守，玉匙密付蜀張手。", "子到長沙渠問儂，爲言真成一老翁。", "功名妄念雪銷了，只愛吟詩惱魚鳥。", "子歸好在中秋前，看子新年勝故年。"]'),
('98ec39cb-33d7-46fa-bcc8-879c4e896738','送鄒元升歸安福','楊萬里','宋','宋诗','song-poetry','','[]','我昔見子盧溪南，炯如玉雪照晴嵐。',96,'全唐诗/poet.song.139000.json','["我昔見子盧溪南，炯如玉雪照晴嵐。", "子今訪我南溪北，凜如騄驥成骨骼。", "袖中文字細作行，讀來病眼生寒光。", "尖新句子入時樣，故應破陣翰墨場。", "春風春雨春山路，喜子能來愁子去。", "故人一別二十年，且對青燈夜深語。"]'),
('58e7bbfc-043b-4a91-aa13-6fb9427ed71c','和昌英叔雪中春酌','楊萬里','宋','宋诗','song-poetry','','[]','南溪春寒强似冬，南溪春水走玉虹。',132,'全唐诗/poet.song.139000.json','["南溪春寒强似冬，南溪春水走玉虹。", "雷公戲手行春雪，詩人嘲詞便飛屑。", "只嫌春雪趁春雷，春容正要渠栽培。", "凍作玉花銷作雨，多般點綴春庭戶。", "酒杯如海醉即休，醉中看雪忘却愁。", "如何呼酒不痛飲，可令詩肩受淒凜。", "少時狂殺老更狂，長恐此意墮渺茫。", "醉鄉有地分一席，且與先生十分梨花注大白。"]'),
('a9d8083d-67ff-4d02-b0df-72c1bff175fb','送劉生談命','楊萬里','宋','宋诗','song-poetry','','[]','學兵先學策，談命先談格。',60,'全唐诗/poet.song.139000.json','["學兵先學策，談命先談格。", "君看前輩富貴人，豈與寒士校日辰。", "星家者流有劉子，進人退人若翻水。", "談何容易驗他年，却是直言差可喜。"]'),
('8b51df15-4a49-4c1c-baa4-56f53b432c0f','和曾克俊惠詩','楊萬里','宋','宋诗','song-poetry','','[]','眼底春光正入年，社前燕子已言旋。',64,'全唐诗/poet.song.139000.json','["眼底春光正入年，社前燕子已言旋。", "雨多厭聽鳩夫婦，病起全疎酒聖賢。", "舊喜作詩今已懶，君能得句我先傳。", "略無好語償嘉惠，只麽從權只麽權。"]'),
('cc7f3930-50e0-4de6-a655-c00663cb4018','和胡侍郎見簡','楊萬里','宋','宋诗','song-poetry','','[]','花邊雪裏撚霜髭，怪底詩來妙一時。',64,'全唐诗/poet.song.139000.json','["花邊雪裏撚霜髭，怪底詩來妙一時。", "聊復小吟開後悟，便應大用到前疑。", "先生此曲難先和，著句如棋且著持。", "每望南雲尺有咫，其人甚遠只嗟咨。"]'),
('10de8e0d-c706-44f9-92b6-8f5cc73c2650','贈彭雲翔長句','楊萬里','宋','宋诗','song-poetry','','[]','讀書臺邊士如雲，盧溪門下士如麟。',104,'全唐诗/poet.song.139000.json','["讀書臺邊士如雲，盧溪門下士如麟。", "定知此地難爲士，後來之秀說彭子。", "雪裏能來訪我爲，當階下馬雪滿衣。", "贈我文章無不有，出入歐蘇與韓柳。", "如今場屋號作家，相州紅纈洛中花，豈如彭子有律令。", "會當一書取張景，今年誰子司文柄。"]'),
('54c20b0a-c64b-4f59-b6a2-2603be6974fa','和賀升卿雲庵升卿嘗上書北闕既歸去歲寄此詩今乃和以報之','楊萬里','宋','宋诗','song-poetry','','[]','賀子胸中自有山，結庵山底更雲間。',64,'全唐诗/poet.song.139000.json','["賀子胸中自有山，結庵山底更雲間。", "遺才只道今無許，此士如何尚著閑。", "未應萬言直杯水，向來九虎守天關。", "莫嫌久不還詩債，詩債從來隔歲還。"]'),
('598b5743-6cc7-4d45-aea1-dbd8631b1f47','送昌英叔知縣之官麻陽','楊萬里','宋','宋诗','song-poetry','','[]','政坐詩無半點塵，天令著句錦江春。',64,'全唐诗/poet.song.139000.json','["政坐詩無半點塵，天令著句錦江春。", "遠民蒙惠即真學，漫仕緣親非爲身。", "許日相從今恨少，先生此別我誰鄰。", "不應更作徒勞嘆，廊廟方尋密縣人。"]'),
('4229c1d1-ca39-4c89-bfa9-3117524c9b3d','和周子中病中代書之韻兼督胡季文季永游山之約','楊萬里','宋','宋诗','song-poetry','','[]','吟外今何病，愁邊我索居。',48,'全唐诗/poet.song.139000.json','["吟外今何病，愁邊我索居。", "昔無今樣嬾，新欠故人書。", "只說遊山去，誰令作計疎。", "衡廬負我輩，我輩負衡廬。"]'),
('3d084b13-1afb-43b5-b811-d6244bc43ec4','除夕前一日絕句','楊萬里','宋','宋诗','song-poetry','','[]','雪留遠嶺半尖白，雲漏斜陽一線黄。',32,'全唐诗/poet.song.139000.json','["雪留遠嶺半尖白，雲漏斜陽一線黄。", "天肯放晴差易耳，殷勤剩覓幾朝霜。"]'),
('fd6feefb-0bdc-4d8c-a033-cdc94c46a293','己丑上元後晚望','楊萬里','宋','宋诗','song-poetry','','[]','雪裏晴偏好，寒餘暖尚輕。',48,'全唐诗/poet.song.139000.json','["雪裏晴偏好，寒餘暖尚輕。", "山煙春自起，野燒暮方明。", "又是元宵過，端令病骨驚。", "遣愁聊覓句，得句却愁生。"]'),
('5dbd4040-49a8-490e-943b-5bec1b07f905','送文黼叔主簿之官松溪','楊萬里','宋','宋诗','song-poetry','','[]','乃翁只解日爭暉，不解塵中脫叔兮。',64,'全唐诗/poet.song.139000.json','["乃翁只解日爭暉，不解塵中脫叔兮。", "楊簿故應過習簿，建溪好處說松溪。", "此行詩句何須覓，滿路春光總是題。", "飛上金鑾穩安脚，竹林分付一鶑啼。"]'),
('31226f03-d039-4764-a4e8-876493fc45b3','送周仲覺訪來又別','楊萬里','宋','宋诗','song-poetry','','[]','酒邊詩裏久塵埃，見子令人病眼開。',64,'全唐诗/poet.song.139000.json','["酒邊詩裏久塵埃，見子令人病眼開。", "無夕不談談不睡，看薪成火火成灰。", "小留差勝匆匆別，欲去何如莫莫來。", "渠政功名我巖壑，老身誰子共歸哉。"]'),
('123bacf8-89d3-4e9a-a3c7-d67b00883724','休日晚步二絕句  其一','楊萬里','宋','宋诗','song-poetry','','[]','未須急訪社中狂，且到西園探海棠。',32,'全唐诗/poet.song.139000.json','["未須急訪社中狂，且到西園探海棠。", "今歲行春雖較晚，也勝雨裏度春光。"]'),
('b300f086-b527-4f30-9314-c2fb80a543a4','休日晚步二絕句  其二','楊萬里','宋','宋诗','song-poetry','','[]','晚雲欲雨又欲晴，天借吾人作此行。',32,'全唐诗/poet.song.139000.json','["晚雲欲雨又欲晴，天借吾人作此行。", "莫道行春無去處，山礬香裏聽溪聲。"]'),
('41014091-1b00-4d2b-91f7-69a1cded5d99','寒食前三日行脚遇雨','楊萬里','宋','宋诗','song-poetry','','[]','信脚那知遠，雖勞亦快哉。',48,'全唐诗/poet.song.139000.json','["信脚那知遠，雖勞亦快哉。", "如何寒食近，無數野花開。", "碧草望中去，黑雲頭上來。", "吾行吾自返，雨子不須催。"]'),
('335a0b02-07be-4add-ad8c-2d8d081f2bf1','和張器先十絕  其一','楊萬里','宋','宋诗','song-poetry','','[]','舊聞我里子張子，七字端能出六奇。',32,'全唐诗/poet.song.139000.json','["舊聞我里子張子，七字端能出六奇。", "窮巷有門無剝啄，怪來佳客肯差池。"]'),
('6f5e1613-01d4-4bf8-a277-9f47afebe37f','和張器先十絕  其二','楊萬里','宋','宋诗','song-poetry','','[]','向來一別十番秋，消息中間風馬牛。',32,'全唐诗/poet.song.139000.json','["向來一別十番秋，消息中間風馬牛。", "只道故人霄漢去，不應林壑小淹留。"]'),
('8542e390-8f59-4beb-a220-6d75decc1402','和張器先十絕  其三','楊萬里','宋','宋诗','song-poetry','','[]','誰云涸轍困波臣，合脫青鞋立縉紳。',32,'全唐诗/poet.song.139000.json','["誰云涸轍困波臣，合脫青鞋立縉紳。", "寄與有司高著眼，後來文格待渠新。"]'),
('d4334d15-666f-4b42-a3b3-ba111c18c484','和張器先十絕  其四','楊萬里','宋','宋诗','song-poetry','','[]','我自窮愁坐綴文，何堪見子可憐生。',32,'全唐诗/poet.song.139000.json','["我自窮愁坐綴文，何堪見子可憐生。", "兩窮政好同詩社，一戰猶須倩酒兵。"]'),
('49245e77-1a0f-4fa9-a96f-833d940ee23b','和張器先十絕  其五','楊萬里','宋','宋诗','song-poetry','','[]','散盡千金買盡書，短檠雨夜趁三餘。',32,'全唐诗/poet.song.139000.json','["散盡千金買盡書，短檠雨夜趁三餘。", "相如自倚多文富，不問家無擔石儲。"]'),
('4a84780e-5b61-4455-a14b-0323ed35dd2d','和張器先十絕  其六','楊萬里','宋','宋诗','song-poetry','','[]','不隨俗子作蠅營，深入書林寄此生。',32,'全唐诗/poet.song.139000.json','["不隨俗子作蠅營，深入書林寄此生。", "已與杜郎爭筆陣，更傳侯喜有詩聲。"]'),
('3b06e29a-8e88-4b7c-b72c-f354e1678b0e','和張器先十絕  其七','楊萬里','宋','宋诗','song-poetry','','[]','漏黄官柳已垂牆，針水公畦未種秧。',32,'全唐诗/poet.song.139000.json','["漏黄官柳已垂牆，針水公畦未種秧。", "多謝詩人來得得，踏開三徑雨中荒。"]'),
('76cb7a1d-5e0e-44ec-a822-329c7f5ba0a4','和張器先十絕  其八','楊萬里','宋','宋诗','song-poetry','','[]','老夫端欲買江天，抹月批風嚥聖賢。',32,'全唐诗/poet.song.139000.json','["老夫端欲買江天，抹月批風嚥聖賢。", "他日君來相問當，南溪溪北北山前。"]'),
('ca53a1c8-8487-4c89-a8d6-3e315a9c5548','和張器先十絕  其九','楊萬里','宋','宋诗','song-poetry','','[]','學成不必要心齋，眼到前脩脚自偕。',32,'全唐诗/poet.song.139000.json','["學成不必要心齋，眼到前脩脚自偕。", "挽住春風還獨笑，更無一物可裝懷。"]'),
('39e5d7cf-842d-4cf3-adaf-b385c6678332','和張器先十絕  其一○','楊萬里','宋','宋诗','song-poetry','','[]','臺家搜遍北山萊，傾國如君不用媒。',32,'全唐诗/poet.song.139000.json','["臺家搜遍北山萊，傾國如君不用媒。", "次第幽人出空谷，鶴書即傍日邊來。"]'),
('2e97d994-21c8-4e87-9c52-2e3e1e529563','挽鄭恭老少卿','楊萬里','宋','宋诗','song-poetry','','[]','天不遺耆老，人誰尚典刑。',48,'全唐诗/poet.song.139000.json','["天不遺耆老，人誰尚典刑。", "向來卿月白，無復史天青。", "詩派回風雪，心源貝葉經。", "故應書带草，和露泣康成。"]'),
('427219b8-569d-4336-b580-13386faa590c','和濟翁惠詩','楊萬里','宋','宋诗','song-poetry','','[]','語妙渾忘夜，杯行未厭頻。',48,'全唐诗/poet.song.139000.json','["語妙渾忘夜，杯行未厭頻。", "平生憎俗子，勝處要吾人。", "已結詩中社，仍居族裏親。", "酒邊不著句，何許見天真。"]'),
('d737ef8f-2fa8-4104-ad2a-9c3df3d52c52','文遠叔挽詞','楊萬里','宋','宋诗','song-poetry','','[]','氣爽塵埃外，川行翰墨間。',48,'全唐诗/poet.song.139000.json','["氣爽塵埃外，川行翰墨間。", "匆匆未白首，去去忽青山。", "琴在絃安用，人亡鶴不還。", "竹林有前約，欲語淚先潸。"]'),
('1e490437-1ed8-49d4-b200-c688f20cfbac','雨中送客有感','楊萬里','宋','宋诗','song-poetry','','[]','不知春向雨中回，只道春光未苦來。',32,'全唐诗/poet.song.139000.json','["不知春向雨中回，只道春光未苦來。", "老子今晨偶然出，李花全落鄭花開。"]'),
('6c6d235d-0221-41da-8378-79196a1f4134','題謝昌國金牛煙雨圖','楊萬里','宋','宋诗','song-poetry','','[]','金牛煙雨最相關，老子方將老是間。',32,'全唐诗/poet.song.139000.json','["金牛煙雨最相關，老子方將老是間。", "不分艮齋來貌取，更於句裏占江山。"]'),
('07675354-a85f-416b-800f-bf8ed8781abb','春日六絕句  其一','楊萬里','宋','宋诗','song-poetry','','[]','遠目隨天去，斜陽著樹明。',24,'全唐诗/poet.song.139000.json','["遠目隨天去，斜陽著樹明。", "犬知何處吠，人在半山行。"]'),
('f175e03e-6319-4ec4-9007-1b7e91d3b7c1','春日六絕句  其二','楊萬里','宋','宋诗','song-poetry','','[]','春醉非關酒，郊行不問塗。',24,'全唐诗/poet.song.139000.json','["春醉非關酒，郊行不問塗。", "青天何處了，白鳥入空無。"]'),
('4178f04b-1bbb-43cc-be64-448cf09e13e0','春日六絕句  其三','楊萬里','宋','宋诗','song-poetry','','[]','霧氣因山見，波痕到岸消。',24,'全唐诗/poet.song.139000.json','["霧氣因山見，波痕到岸消。", "詩人元自懶，物色故相撩。"]'),
('4fbf1c90-b499-4745-88ef-2f0611e1e92e','春日六絕句  其四','楊萬里','宋','宋诗','song-poetry','','[]','江水夜韶樂，海棠春貴妃。',24,'全唐诗/poet.song.139000.json','["江水夜韶樂，海棠春貴妃。", "殷勤向春道，莫遣一花飛。"]'),
('01d849ce-7c33-4baa-8abc-ad9cd48cf0ef','春日六絕句  其五','楊萬里','宋','宋诗','song-poetry','','[]','日落碧簪外，人行紅雨中。',24,'全唐诗/poet.song.139000.json','["日落碧簪外，人行紅雨中。", "幽人詩酒裏，又是一春風。"]'),
('38584686-abab-4d0f-9905-f905c059db17','春日六絕句  其六','楊萬里','宋','宋诗','song-poetry','','[]','春色有情意，桃花生暮寒。',24,'全唐诗/poet.song.139000.json','["春色有情意，桃花生暮寒。", "只應催客子，不遣立江干。"]'),
('af5ff9ba-76d0-415b-826e-7695737da24c','和濟翁弟惠詩二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','竟歲不得面，移書焉用頻。',48,'全唐诗/poet.song.139000.json','["竟歲不得面，移書焉用頻。", "我方得吾弟，今豈有斯人。", "海內友非少，談間子獨親。", "醉餘無浪語，尤見醉中真。"]'),
('1c817c75-9a9a-4d29-940c-b03dd20bfe32','和濟翁弟惠詩二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','相思何所似，饑者食仁頻。',48,'全唐诗/poet.song.139000.json','["相思何所似，饑者食仁頻。", "此客非常客，詩人太逼人。", "黄初那足過，子建巧能親。", "臺閣俱知己，誰能薦子真。"]'),
('f4771df9-4672-442a-8001-bf9bb130a592','夏夜追凉','楊萬里','宋','宋诗','song-poetry','','["\u590f\u5929"]','夜熱依然午熱同，開門小立月明中。',32,'全唐诗/poet.song.139000.json','["夜熱依然午熱同，開門小立月明中。", "竹深樹密蟲鳴處，時有微涼不是風。"]'),
('ce6d97bb-96f9-4965-a68f-a5dfd8ee712e','暑雨後散策','楊萬里','宋','宋诗','song-poetry','','[]','溪南稻紫似溪北，雨後山青非雨前。',32,'全唐诗/poet.song.139000.json','["溪南稻紫似溪北，雨後山青非雨前。", "芒屨泥深涼不淺，今年六月箇般天。"]'),
('d73a8d81-db8f-498c-93c0-e48981171028','夏月頻雨','楊萬里','宋','宋诗','song-poetry','','[]','一番暑雨一番涼，真箇令人愛日長。',32,'全唐诗/poet.song.139000.json','["一番暑雨一番涼，真箇令人愛日長。", "隔水風來知有意，爲吹十里稻花香。"]'),
('7dab29a4-7597-4c5d-9d5c-8f2996dd7a56','新秋盛熱','楊萬里','宋','宋诗','song-poetry','','[]','度夏今年未覺難，那知秋熱政無端。',32,'全唐诗/poet.song.139000.json','["度夏今年未覺難，那知秋熱政無端。", "晚林不動蟬聲苦，蟬亦無風可得餐。"]'),
('81148dde-908a-4f18-a100-cec4d0f4d7b4','送慶基叔往上猶二絕  其一','楊萬里','宋','宋诗','song-poetry','','[]','南溪不住住猶溪，別駕賢孫法掾兒。',32,'全唐诗/poet.song.139000.json','["南溪不住住猶溪，別駕賢孫法掾兒。", "莫以甘棠南國蔭，便忘萱草北堂詩。"]'),
('246c05b7-73de-49c8-9b8f-6272cf33dec6','送慶基叔往上猶二絕  其二','楊萬里','宋','宋诗','song-poetry','','[]','六十慈親路一千，郎君歸省又何年。',32,'全唐诗/poet.song.139000.json','["六十慈親路一千，郎君歸省又何年。", "贈行句子真聊爾，且折垂楊當贈鞭。"]'),
('62e93ec4-83dd-4fcc-9bbd-efcd1094240a','初秋暮雨','楊萬里','宋','宋诗','song-poetry','','[]','禾穟輕黄尚淺青，村舂已報隔林聲。',32,'全唐诗/poet.song.139000.json','["禾穟輕黄尚淺青，村舂已報隔林聲。", "忽驚暮色翻成曉，仰見雙虹雨外明。"]'),
('1fd8c696-c00f-4d97-a385-09cf9af98f0f','濟翁弟贈白團扇子一面作百竹圖有詩和以謝之','楊萬里','宋','宋诗','song-poetry','','[]','月波初上湧寒金，桂樹風來細有音。',32,'全唐诗/poet.song.139000.json','["月波初上湧寒金，桂樹風來細有音。", "特地此君偏作惱，爲儂隔却半輪陰。"]'),
('b2ca99aa-4859-4e35-a226-5a5dbf9987a1','秋日晚望','楊萬里','宋','宋诗','song-poetry','','[]','村落豐登裏，人家笑語聲。',48,'全唐诗/poet.song.139000.json','["村落豐登裏，人家笑語聲。", "溪霞晚紅濕，松日暮黄輕。", "只麽秋殊淺，如何氣許清。", "不應久閑散，便去羨功名。"]'),
('f424c1a9-d92b-41ee-9f07-24dc77d52cba','秋夜讀書','楊萬里','宋','宋诗','song-poetry','','[]','穉子慵都睡，先生喚不應。',48,'全唐诗/poet.song.139000.json','["穉子慵都睡，先生喚不應。", "蟲聲窗外月，書冊夜深燈。", "半醉聊今古，千年幾廢興。", "有懷人未會，不樂我何曾。"]'),
('3a8a2599-7525-4720-bed4-c50e24ca795e','睡起理髮','楊萬里','宋','宋诗','song-poetry','','[]','老態隨年覺，新涼與睡謀。',48,'全唐诗/poet.song.139000.json','["老態隨年覺，新涼與睡謀。", "鵲驚茅屋曉，臂冷葛衣秋。", "遠嶺元無約，開門便見投。", "閑中多事在，一日一梳頭。"]'),
('bcfda27d-924e-41a2-a8cc-c08ddb17a156','暮歸','楊萬里','宋','宋诗','song-poetry','','[]','山色偏宜暮，桐聲小作秋。',48,'全唐诗/poet.song.139000.json','["山色偏宜暮，桐聲小作秋。", "人行溪側畔，天在樹梢頭。", "學嬾真成嬾，知休却得休。", "遣愁愁不去，愁盡自無愁。"]'),
('e918c41a-0936-4c42-8c9c-6d8c43edc122','曉望','楊萬里','宋','宋诗','song-poetry','','[]','暑退誰當憶，秋生喜此逢。',48,'全唐诗/poet.song.139000.json','["暑退誰當憶，秋生喜此逢。", "荒林失輕霧，寒日上危峰。", "忽有吟邊興，忘看鏡裏容。", "不須無鮑謝，始得擅詩宗。"]'),
('59f6c2d6-b958-47f7-b9e6-40003594a780','午睡起','楊萬里','宋','宋诗','song-poetry','','[]','過雨餘秋暑，移床揀午涼。',48,'全唐诗/poet.song.139000.json','["過雨餘秋暑，移床揀午涼。", "小風吹醉面，凜氣忽如霜。", "日脚何曾動，桐陰有底忙。", "倦來聊作睡，睡起更蒼茫。"]'),
('c234c381-98cb-427f-8394-a892f8673970','和胡季永赴季文遊園良集之韻聊以致私怨於獨往云','楊萬里','宋','宋诗','song-poetry','','[]','有酒招元亮，無漿饋子居。',48,'全唐诗/poet.song.139000.json','["有酒招元亮，無漿饋子居。", "何曾三不速，焉用一行書。", "乞飲殊無分，干時不已疎。", "猶應慰大嚼，玉軸到吾廬。"]'),
('278105f9-cfb4-4413-9002-8c1c186c71cf','四美堂','楊萬里','宋','宋诗','song-poetry','','[]','義山禾水在處在，明月清風無地無。',67,'全唐诗/poet.song.139000.json','["義山禾水在處在，明月清風無地無。", "光祿子孫寧底巧，不應造物獨私渠。", "君不見謝家名子取四字，段家作堂兼四美。", "主人自有筆如椽，何用殷勤問楊子。"]'),
('eb599b68-93eb-4432-9f6a-eba2322144c8','秋晚過泉口','楊萬里','宋','宋诗','song-poetry','','[]','日色全無熱，秋涼不似初。',48,'全唐诗/poet.song.139000.json','["日色全無熱，秋涼不似初。", "行人驚翡翠，掠水度芙蕖。", "平野一回顧，遠山千有餘。", "誰令貪眺望，却道廢看書。"]'),
('6b10127e-cd9f-4ad8-b05e-6d41bbffd410','豐山小憩','楊萬里','宋','宋诗','song-poetry','','[]','歸路元無遠，行人倦自遲。',48,'全唐诗/poet.song.139000.json','["歸路元無遠，行人倦自遲。", "野香寒蝶聚，秋色老楓知。", "得得逢清蔭，休休憩片時。", "江山豈無意，邀我覓新詩。"]'),
('2d1187f8-0ba6-4c49-8234-e4a3320e4223','過劉村江','楊萬里','宋','宋诗','song-poetry','','[]','波走痕痕日，江呈岸岸秋。',48,'全唐诗/poet.song.139000.json','["波走痕痕日，江呈岸岸秋。", "清流堪數石，淺涉不須舟。", "野菊知何喜，迎風舞未休。", "歸塗愁欲暮，未暮我何愁。"]'),
('5179d2f6-66d6-47e6-a262-34b11bd79207','寄蕭仲和','楊萬里','宋','宋诗','song-poetry','','[]','貧裏端何好，欣然肯不居。',48,'全唐诗/poet.song.139000.json','["貧裏端何好，欣然肯不居。", "詩臞將到骨，室陋得關渠。", "我嬾今仍老，誰能强著書。", "談間可無子，獨判一秋虛。"]'),
('2b238da1-59b0-4199-a2e4-e15b2d15f22b','題劉朝英進齋','楊萬里','宋','宋诗','song-poetry','','[]','燈火三更雨，詩書一古琴。',48,'全唐诗/poet.song.139000.json','["燈火三更雨，詩書一古琴。", "惟愁脚力軟，未必聖門深。", "莫笑雲端樹，初如澗底針。", "不應將一第，用破半生心。"]'),
('832d4880-d43d-4328-98bd-6408c5e97c29','題王季安主簿佚老堂二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','造物那能惱我曹，軟紅塵裏漫徒勞。',32,'全唐诗/poet.song.139000.json','["造物那能惱我曹，軟紅塵裏漫徒勞。", "是中却有商量處，且道青原幾許高。"]'),
('de8c7716-f976-4bfe-8953-2bee057409a8','題王季安主簿佚老堂二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','布襪青鞋已嬾行，不如宴坐聽啼鶑。',32,'全唐诗/poet.song.139000.json','["布襪青鞋已嬾行，不如宴坐聽啼鶑。", "只言此老渾無事，種竹移花作麽生。"]'),
('5fcab575-f146-442c-b0b9-6029787fb775','和王元駒','楊萬里','宋','宋诗','song-poetry','','[]','向來淮海說三秦，脚踏蘇門最絕塵。',64,'全唐诗/poet.song.139000.json','["向來淮海說三秦，脚踏蘇門最絕塵。", "莫道江山歇英氣，如今文物有斯人。", "黄埃九陌誰知子，青竹千年獨問津。", "未得相看已相識，只慚空嘆蜀莊珍。"]'),
('1e02facb-e134-4b89-834d-028f594f7fed','題丘成之司理明遠閣','楊萬里','宋','宋诗','song-poetry','','[]','决曹據按塵似海，高閣退食心如冰。',64,'全唐诗/poet.song.139000.json','["决曹據按塵似海，高閣退食心如冰。", "夜將官本校家本，萬山圍裏短檠燈。", "能文未得傲能吏，好官不應博丁字。", "何時著脚最高層，目送歸鴻揮綠綺。"]'),
('f826ea94-67e6-45fe-952c-37465cf7fa4d','和謝昌國送韋俊臣相訪','楊萬里','宋','宋诗','song-poetry','','[]','芒屩爲車不必巾，天窮未害子能文。',32,'全唐诗/poet.song.139000.json','["芒屩爲車不必巾，天窮未害子能文。", "謝家有句元無繼，枉却催詩頭上雲。"]'),
('caef82f0-30ee-4096-9eb6-0f4d90ef68af','歲晚出城','楊萬里','宋','宋诗','song-poetry','','[]','溫飽能消底，奔忙自作癡。',48,'全唐诗/poet.song.139000.json','["溫飽能消底，奔忙自作癡。", "平生脚已繭，今日鬢將絲。", "山刻霜餘骨，梅臨水底枝。", "只嫌長落莫，不道許幽奇。"]'),
('ac2515a6-aada-4fb9-9c24-aa5b27a170be','至鷓鴣洞','楊萬里','宋','宋诗','song-poetry','','[]','岸凍樹逾瘦，日高林始明。',60,'全唐诗/poet.song.139000.json','["岸凍樹逾瘦，日高林始明。", "瑶草密如積，玉泉中暗鳴。", "初至心爲動，欲歸脚還停。", "江湖千萬峰，穿儂兩鞋青。", "如何鷓鴣嶺，咫尺來未曾。"]'),
('391c1a61-e5c1-4c46-acc2-238a7a1e78c9','讀張忠獻公謚冊感歎','楊萬里','宋','宋诗','song-poetry','','[]','恩視韓兼趙，名均獻與忠。',48,'全唐诗/poet.song.139000.json','["恩視韓兼趙，名均獻與忠。", "禮中非不極，勳外若爲同。", "三聖無多學，千年僅一翁。", "猶憐公議在，拚淚乞秋風。"]'),
('ebf22929-35a2-468f-8436-72412c6485da','寄張欽夫二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','作郡纔佳政，留中即好音。',48,'全唐诗/poet.song.139000.json','["作郡纔佳政，留中即好音。", "還將著書手，拈出正君心。", "嶽麓風霜飽，脩門雨露深。", "登庸何恨晚，廊廟要山林。"]'),
('5116d5ee-8db1-4a88-abca-f51c945782e1','寄張欽夫二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','工瑟曾緣利，鳴琴豈負予。',48,'全唐诗/poet.song.139000.json','["工瑟曾緣利，鳴琴豈負予。", "髮於貧裏白，詩亦病來疎。", "知己俱霄漢，孤蹤且簿書。", "三年知免矣，一飽會歸歟。"]'),
('945287e4-c691-49ad-8e51-903c6590ce94','和慶長懷麻陽叔二詩  其一','楊萬里','宋','宋诗','song-poetry','','[]','舊雪纔追送，新梅又作繁。',48,'全唐诗/poet.song.139000.json','["舊雪纔追送，新梅又作繁。", "欣逢上林雁，聊免管城冠。", "酒債多多在，詩盟久久寒。", "忽思十年事，有枕不能安。"]'),
('b7fd4164-701f-4489-b3ef-0af724e4f0c3','和慶長懷麻陽叔二詩  其二','楊萬里','宋','宋诗','song-poetry','','[]','自幼仍投老，相懽不解愁。',48,'全唐诗/poet.song.139000.json','["自幼仍投老，相懽不解愁。", "政緣湖外別，負却竹林秋。", "佳政真餘事，聞人說甚休。", "不應野水渡，橫此濟川舟。"]'),
('08d88d0c-2eb1-40e6-bf9a-3fa22c56f0fa','送羅永年歸永豐','楊萬里','宋','宋诗','song-poetry','','[]','誰道三年聚，能勝一別多。',48,'全唐诗/poet.song.139000.json','["誰道三年聚，能勝一別多。", "歲寒知子可，心折奈吾何。", "所喜如椽筆，能揮却日戈。", "老夫留病眼，看子中文科。"]'),
('4b4cb26f-5a06-43bc-a41e-0c979c290c9e','夜坐小集','楊萬里','宋','宋诗','song-poetry','','[]','霜餘雪後夜無風，人在燈前梅影中。',32,'全唐诗/poet.song.139000.json','["霜餘雪後夜無風，人在燈前梅影中。", "玉作寒蔬冰作酒，詩人猶自怨天窮。"]'),
('1d418a7b-d9c8-4324-b414-658e66f69a97','和謝昌國送管相士韻','楊萬里','宋','宋诗','song-poetry','','[]','半世緣癡自作勞，萬人爭處我方逃。',32,'全唐诗/poet.song.139000.json','["半世緣癡自作勞，萬人爭處我方逃。", "憐渠識盡公卿得，一馬歸來骨轉高。"]'),
('5d72e2f4-e8a6-4451-b0cc-63000b56485f','郭漢卿母挽詩','楊萬里','宋','宋诗','song-poetry','','[]','婦節今安仰，斯人古有光。',48,'全唐诗/poet.song.139000.json','["婦節今安仰，斯人古有光。", "雞鳴不知雨，薺茂獨凌霜。", "未拜金花誥，空悲玉樹郎。", "藤輿簾蹙繡，無復出萱堂。"]'),
('a59b17d7-9c26-4aae-96fe-ab2f36fbea3b','庚寅正月送羅季周遊學禾川','楊萬里','宋','宋诗','song-poetry','','[]','眼邊相識蠶樣密，如子歲寒萬纔一。',64,'全唐诗/poet.song.139000.json','["眼邊相識蠶樣密，如子歲寒萬纔一。", "我往西山子義山，老裏一別堪三年。", "外舅陰功不知數，諸孫太半廊廟具。", "學文先要學忍饑，明年看子刺天飛。"]'),
('f56f4e60-a635-4011-8c9e-19798c907488','過秀溪長句','楊萬里','宋','宋诗','song-poetry','','[]','去年來此上巳日，今年重來未寒食。',64,'全唐诗/poet.song.139000.json','["去年來此上巳日，今年重來未寒食。", "臨溪照影老自羞，慚愧春光尚相識。", "秀溪何許好春容，最是溪深樹密中。", "海棠開盡却成白，桃花欲落翻深紅。"]'),
('90b28b28-377b-4ad2-9467-0a0700b2be1b','題薦福寺','楊萬里','宋','宋诗','song-poetry','','[]','千山底裏著樓臺，半夜松風萬壑哀。',32,'全唐诗/poet.song.139000.json','["千山底裏著樓臺，半夜松風萬壑哀。", "曉起巡簷看題壁，雨聲一片隔林來。"]'),
('32a79b76-c49a-4f09-8100-8299214c8883','晚過黄洲鋪二絕  其一','楊萬里','宋','宋诗','song-poetry','','[]','數峰殘日紫將銷，一片新秧綠未交。',32,'全唐诗/poet.song.139000.json','["數峰殘日紫將銷，一片新秧綠未交。", "道是今年春水小，漲痕也到岸花梢。"]'),
('e99d2907-991b-44a6-9752-7117fec00d5b','晚過黄洲鋪二絕  其二','楊萬里','宋','宋诗','song-poetry','','[]','僕夫已倦路猶賒，脚底殊勞眼底佳。',32,'全唐诗/poet.song.139000.json','["僕夫已倦路猶賒，脚底殊勞眼底佳。", "綠錦堆中半團雪，千楓擁出一桐花。"]'),
('66c4a5f5-031f-4795-8ba1-e6d4a5d03de1','過白沙渡得長句呈澹庵先生','楊萬里','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','收紅拾紫消幾許，也費一春强半雨。',96,'全唐诗/poet.song.139000.json','["收紅拾紫消幾許，也費一春强半雨。", "不辭長江萬波阻，來聽先生夜深語。", "尚憶向來侍樽俎，微雪斜飛小梅吐。", "先生半酣染霜兔，金章玉句空萬古。", "今年寒食還相聚，明年寒食知何處。", "只道先生押班去，不道門生折腰苦。"]'),
('f811c6e8-fe25-4e09-bfbc-83581617d011','長句寄周舍人子充','楊萬里','宋','宋诗','song-poetry','','[]','省齋先生太高寒，肯將好官博好山。',96,'全唐诗/poet.song.139000.json','["省齋先生太高寒，肯將好官博好山。", "又告君王覓閑散，要讀短檠三萬卷。", "州家新畫瑞霧圖，渠莫錯認何關渠。", "青原兩公復雙起，山川出雲不在此。", "自憐無地寄病身，四海知己非無人。", "老窮只是詩自悞，春色撩人又成句。"]'),
('bd3a246a-6c16-40a1-9a59-be0fb8e34a70','題峽江譚溫父詠齋','楊萬里','宋','宋诗','song-poetry','','[]','漁郎載我下峽水，夜尋故人有譚子。',64,'全唐诗/poet.song.139000.json','["漁郎載我下峽水，夜尋故人有譚子。", "柴門竹屋斷崖底，艮齋手題詠齋字。", "巴丘花草一番新，玉笥峰頭月半輪。", "如今政是暮春者，三歎春風舞雩下。"]'),
('f8f72033-4023-40f5-a667-1b951eedce38','淺夏獨行奉新縣圃','楊萬里','宋','宋诗','song-poetry','','[]','我來官下未多時，梅已黄深李綠肥。',32,'全唐诗/poet.song.139000.json','["我來官下未多時，梅已黄深李綠肥。", "只怪南風吹紫雪，不知屋角楝花飛。"]'),
('80848c14-54ea-4431-8044-136a07300174','晚登清心閣望雨','楊萬里','宋','宋诗','song-poetry','','[]','憫雨喜見雲，喜雲愁不雨。',48,'全唐诗/poet.song.139000.json','["憫雨喜見雲，喜雲愁不雨。", "長風將怒點，慰此樓中暮。", "喜雨不但人，松竹亦鼓舞。", "未知今年熟，得似去年否。"]'),
('b753a632-4c37-48b1-a5b2-de27b34acc11','登清心閣','楊萬里','宋','宋诗','song-poetry','','[]','苦遭好月喚登樓，脚力雖慵不自由。',32,'全唐诗/poet.song.139000.json','["苦遭好月喚登樓，脚力雖慵不自由。", "上得金梯一回首，冰輪已過樹梢頭。"]'),
('55921922-df63-4ae2-812d-7854d6f73b1d','立秋後一日雨天欲暮小立問月亭','楊萬里','宋','宋诗','song-poetry','','[]','雨後林中別樣涼，意行幽徑不知長。',32,'全唐诗/poet.song.139000.json','["雨後林中別樣涼，意行幽徑不知長。", "風蟬幸自無星事，强爲閑人報夕陽。"]'),
('c5351b09-6895-4f16-ae08-883676dc4f29','七月十二日夜登清心閣醉吟','楊萬里','宋','宋诗','song-poetry','','[]','小樓秋夜月明底，仰不見天惟見水。',64,'全唐诗/poet.song.139000.json','["小樓秋夜月明底，仰不見天惟見水。", "岸巾獨立四無人，白月青天伴楊子。", "誰知橫玉作秋聲，一聲吹盡九陌塵。", "月輪半仄吾未睡，樓角風生涼殺人。"]'),
('1fb44bcf-eac5-4945-9438-dde61bcace9d','月夜散策縣圃有飛蝶仍聞笛聲','楊萬里','宋','宋诗','song-poetry','','[]','月明未許人早睡，笛聲解與秋爭清。',32,'全唐诗/poet.song.139000.json','["月明未許人早睡，笛聲解與秋爭清。", "夜深不應有飛蝶，渠儂似欲伴人行。"]'),
('8b79ceb1-84eb-412d-8c54-0535d12436c8','中秋後一夕登清心閣二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','昨夜雲爲祟，今宵月始妍。',48,'全唐诗/poet.song.139000.json','["昨夜雲爲祟，今宵月始妍。", "如何一日隔，便減半分圓。", "影裏偏宜竹，光中不剩天。", "客來休遣去，我醉正無眠。"]'),
('4f314717-f688-45e2-9a05-adb832b1ea69','中秋後一夕登清心閣二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','秋夜真成晝，西山却在東。',48,'全唐诗/poet.song.139000.json','["秋夜真成晝，西山却在東。", "吹高半輪月，正頼一襟風。", "清景今年過，何人此興同。", "青天忽成紙，似欲借詩翁。"]'),
('51686aba-2999-4134-971e-a2c24c49b506','木犀','楊萬里','宋','宋诗','song-poetry','','[]','天將秋氣蒸寒馥，月借金波滴小黄。',32,'全唐诗/poet.song.139000.json','["天將秋氣蒸寒馥，月借金波滴小黄。", "不會溪堂老居士，更談桂子是天香。"]'),
('e8692097-d7a5-4d7a-9944-7a0e0ef6739a','送客既歸晚登清心閣','楊萬里','宋','宋诗','song-poetry','','[]','誰不知儂嬾，其如送客何。',48,'全唐诗/poet.song.139000.json','["誰不知儂嬾，其如送客何。", "葉聲和雨細，山色上樓多。", "出處俱爲累，昇沉儘聽他。", "疎鐘暮相答，也解說愁麽。"]'),
('82647611-5496-4375-8c0e-6ac5a9e5486a','戲嘲金燈花上皂蝶','楊萬里','宋','宋诗','song-poetry','','[]','花鬚爲飯露爲漿，黑霧玄霜剪薄裳。',32,'全唐诗/poet.song.139000.json','["花鬚爲飯露爲漿，黑霧玄霜剪薄裳。", "飛繞金燈來又去，不知能有幾多香。"]'),
('fa6f27cb-ce75-4e1b-907e-9db9a96afe01','劉世臣先生挽詩','楊萬里','宋','宋诗','song-poetry','','[]','策第仍爲邑，於公未足論。',48,'全唐诗/poet.song.139000.json','["策第仍爲邑，於公未足論。", "眼中無佛國，戶外即韓門。", "道大功非細，人亡德則存。", "西風寄雙淚，吹到秀峰原。"]'),
('1ecca5cc-d44e-4029-873a-85b4aae4aad3','羅元通挽詩','楊萬里','宋','宋诗','song-poetry','','[]','奏賦曾三北，興能竟二南。',48,'全唐诗/poet.song.139000.json','["奏賦曾三北，興能竟二南。", "如何雙桂子，枉著拜親衫。", "舊事餘詩酒，何人續笑談。", "生前孝友在，伐石爲公鑱。"]'),
('046a3210-5681-4c34-a4be-9a10bd26f7f7','羅价卿母李氏挽詩','楊萬里','宋','宋诗','song-poetry','','[]','孝豈天無報，慈如古所稱。',48,'全唐诗/poet.song.139000.json','["孝豈天無報，慈如古所稱。", "百年得偕老，二子看同升。", "未拜鸞迴紙，先虛繡蹙藤。", "他時潁考叔，清淚落君羹。"]'),
('fafbb819-f474-4936-beed-46d8014c95f2','過西山','楊萬里','宋','宋诗','song-poetry','','[]','一年兩踏西山路，西山笑人應解語。',64,'全唐诗/poet.song.139000.json','["一年兩踏西山路，西山笑人應解語。", "胸中百斛朱墨塵，雨捲珠簾無半句。", "殷勤買酒謝西山，慚愧山光開我顔。", "鬢絲渾爲催科白，塵埃滿胸獨遑惜。"]'),
('c59683ae-cef6-4264-b764-5969815db983','豫章江皋二絕句  其一','楊萬里','宋','宋诗','song-poetry','','[]','幸自輕陰好片秋，如何餘熱未全休。',32,'全唐诗/poet.song.139000.json','["幸自輕陰好片秋，如何餘熱未全休。", "大江欲近風先冷，平野無邊草亦愁。"]'),
('963ea002-e35b-4686-9e84-fd93d6de0ac9','豫章江皋二絕句  其二','楊萬里','宋','宋诗','song-poetry','','[]','只今秋稼滿江郊，猶記春船掠屋茅。',32,'全唐诗/poet.song.139000.json','["只今秋稼滿江郊，猶記春船掠屋茅。", "可是北風寒入骨，荻花爭作向南梢。"]'),
('e5001ffd-9f0e-452d-aba2-4e8d54292446','同李簿養直登秋屏','楊萬里','宋','宋诗','song-poetry','','[]','大範今無寺，秋屏故有基。',48,'全唐诗/poet.song.139000.json','["大範今無寺，秋屏故有基。", "看山非不好，吊古却成悲。", "行役真何苦，同來也未遲。", "題詩只惡語，差勝不題詩。"]'),
('24bde10a-ad88-450b-99db-9d08d9f1128b','送別吳帥','楊萬里','宋','宋诗','song-poetry','','[]','我公四海不數人，小煩江西作好春。',96,'全唐诗/poet.song.139000.json','["我公四海不數人，小煩江西作好春。", "落霞秋水只似舊，如何入筆事事新。", "即今諸公方衮衮，一老不應閑裏頓。", "政緣山水太殷勤，日夜叫閽乞此身。", "二天去人忽覺遠，兩地起公端不免。", "蒼生未要怨東山，未必東山當此怨。"]'),
('8c6704f3-956b-457a-8fc4-77824fbd5202','歸自豫章復過西山','楊萬里','宋','宋诗','song-poetry','','[]','一眼苕花十里明，忽疑九月雪中行。',32,'全唐诗/poet.song.139000.json','["一眼苕花十里明，忽疑九月雪中行。", "我行莫笑無騶從，自有西山管送迎。"]'),
('f2daf598-3127-4ef4-b8a9-b28f9ec7aca4','送何主簿歸豐城','楊萬里','宋','宋诗','song-poetry','','[]','衆裏非無士，難中却幾人。',48,'全唐诗/poet.song.139000.json','["衆裏非無士，難中却幾人。", "如何新帥澤，偏作此邦春。", "未要栖鸞恨，方看報主身。", "青燈一樽酒，聊復話酸辛。"]'),
('d7a4f0b4-72a2-4e84-9a13-61d24b6af7c7','詔追供職學省曉發鳴山驛','楊萬里','宋','宋诗','song-poetry','','[]','數店疎仍密，千峰整復斜。',48,'全唐诗/poet.song.139000.json','["數店疎仍密，千峰整復斜。", "冰痕猶带浪，霜草自成花。", "錄錄堪朝列，星星已鬢華。", "帝城萬事好，得似早還家。"]'),
('4779781c-655d-4167-aee3-eb612134c0bb','望見靈山','楊萬里','宋','宋诗','song-poetry','','[]','旱後催科惱殺儂，且隨尺一解而東。',32,'全唐诗/poet.song.139000.json','["旱後催科惱殺儂，且隨尺一解而東。", "靈山忽近西山遠，回首新吳一夢中。"]'),
('495c04a4-b214-4e11-8d65-8fd57b3554de','登烏石寺','楊萬里','宋','宋诗','song-poetry','','[]','回頭身忽在樹杪，一覽千山萬山小。',96,'全唐诗/poet.song.139000.json','["回頭身忽在樹杪，一覽千山萬山小。", "怪崖不落欹欲摧，令人仰看怯眼開。", "小亭解事知儂倦，翼然飛出青山半。", "上頭最上却鏡平，百畝金碧千衲僧。", "高峰高寺更高閣，進步竿頭若爲脚。", "茲遊勝絕庸非天，山下虛行二十年。"]'),
('e02ff303-90b2-4fda-8aee-c64bfc7c3c32','夜宿楊溪曉起見雪','楊萬里','宋','宋诗','song-poetry','','[]','茅簷無聲風不起，誤喜夜來雨應止。',96,'全唐诗/poet.song.139000.json','["茅簷無聲風不起，誤喜夜來雨應止。", "開門送眼忽心驚，失却前山萬堆翠。", "江南只說浙西山，更令著雪與人看。", "諸峰盡處一峰出，凜然玉立最高寒。", "溪聲細伴吟聲苦，客心冷趁波心去。", "掉頭得句恐天嗔，且喚征夫問前路。"]'),
('04a513e6-9e8c-45ec-8bbe-1c8f26fde88e','辛卯五月送丘宗卿太博出守秀州二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','馮翊端誰可，丘遲肯去麽。',48,'全唐诗/poet.song.139000.json','["馮翊端誰可，丘遲肯去麽。", "繭絲臣敢後，饑饉帝云何。", "身達當難免，能稱未要多。", "但無田里嘆，不必袴襦歌。"]'),
('1cea9b1c-9ce8-49eb-b04d-acb6ac7bdaec','辛卯五月送丘宗卿太博出守秀州二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','老矣渠憐我，超然我愛渠。',48,'全唐诗/poet.song.139000.json','["老矣渠憐我，超然我愛渠。", "論詩春雨夜，解手藕花初。", "夢只江湖去，情知伎倆疎。", "未應五馬貴，不寄一行書。"]'),
('5565e4f3-1e10-43a0-ae84-62cd1aa60b1d','代錢塘宰莫子章賀皇太子生辰','楊萬里','宋','宋诗','song-poetry','','[]','寒外乾坤浄，霜前殿閣新。',120,'全唐诗/poet.song.139000.json','["寒外乾坤浄，霜前殿閣新。", "如何震一索，頓有月重輪。", "甲觀堂初畫，青宮牓更銀。", "三天同日曉，一氣八荒春。", "東序繙周學，南陽摘漢親。", "承祧英類祖，問寢孝通神。", "帝子臨京邑，藩寮著野人。", "天將重九節，瑞應誕彌辰。", "萸菊雙爲壽，山河總效珍。", "前星環紫極，長照漆園椿。"]'),
('641a11ca-4214-48c4-9a59-2ca5a39876ec','題呂子明國諭退庵','楊萬里','宋','宋诗','song-poetry','','[]','筆硯工爲祟，湖山苦約盟。',48,'全唐诗/poet.song.139000.json','["筆硯工爲祟，湖山苦約盟。", "坐忘非聖處，行樂且吾生。", "一笑誰當會，孤斟句恰成。", "何時却乘興，雪外叩柴荆。"]'),
('93dbfaf9-1253-4b8f-b1a5-8278b5dd068d','送蜀士張之源二子維燾中童子科西歸','楊萬里','宋','宋诗','song-poetry','','[]','岷山玉樣清，岷水眼樣明。',92,'全唐诗/poet.song.139000.json','["岷山玉樣清，岷水眼樣明。", "風流文彩故應爾，又見張家雙驥子。", "小兒八歲骨未成，誦書新作鸞鶴聲。", "大兒十二氣已老，覓句談經人絕倒。", "豫章七年人得知，駃騠三日世便奇。", "天生異材能幾許，更飽風霜也未遲。"]'),
('3e484084-c649-4205-930f-68f54402c049','壬辰別頭胡元伯丞公折雙梅見贈作一絕以謝之','楊萬里','宋','宋诗','song-poetry','','[]','一花怪結雙青子，獨蔕還藏兩玉花。',32,'全唐诗/poet.song.139000.json','["一花怪結雙青子，獨蔕還藏兩玉花。", "薄相春工寧底巧，眼明初見雪枝斜。"]'),
('b97372ab-18a6-43f6-bbb2-e7023937fb16','四月二日進士唱名萬里以省試官待罪殿廬遇林謙之說詩夜歸又得林柬因紀其事','楊萬里','宋','宋诗','song-poetry','','[]','清曉朝帝所，就列復少須。',96,'全唐诗/poet.song.139000.json','["清曉朝帝所，就列復少須。", "不逢林夫子，於何得故吾。", "宮雲霽猶未，宸風爽亦初。", "說詩憐新體，信美古則無。", "將無古人拙，未必今製疎。", "夜歸辱良訊，送似談笑餘。", "病懷翻不樂，此意從誰舒。", "短歌紀幽事，老矣復焉如。"]'),
('8aabe817-df4a-4a0c-a3fe-658e0dfcf61e','送黄仲秉少卿知瀘州二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','灩澦方如象，餘皇底似飛。',48,'全唐诗/poet.song.139000.json','["灩澦方如象，餘皇底似飛。", "相將刺天去，收拾大名歸。", "西掖桐陰靜，瀘南荔子肥。", "未應經世具，便欲閉山扉。"]'),
('6c87c256-3fdc-4b16-9f1c-486136de5635','送黄仲秉少卿知瀘州二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','補外公何幸，求歸我尚留。',48,'全唐诗/poet.song.139000.json','["補外公何幸，求歸我尚留。", "還爲萬里別，又費半生愁。", "安得欹黄帽，相從却白頭。", "醉中有話在，欲說忘來休。"]'),
('f34a8fc8-6a43-453c-be7b-75143055c8f7','晚立西湖惠照寺石橋上','楊萬里','宋','宋诗','song-poetry','','["\u897f\u6e56"]','船於鏡面入煙叢，寺在湖心更柳中。',32,'全唐诗/poet.song.139000.json','["船於鏡面入煙叢，寺在湖心更柳中。", "暮色欲來吾欲去，其如南北兩高峰。"]'),
('f88fa1d1-26fc-44e2-aa71-7d8ca9aaf0dd','謁永祐陵歸途遊龍瑞宮觀禹穴','楊萬里','宋','宋诗','song-poetry','','[]','我昔騎鳳超九疑，今復御風登會稽。',64,'全唐诗/poet.song.139000.json','["我昔騎鳳超九疑，今復御風登會稽。", "禹穴下窺正深黑，地老天荒知是非。", "好峰高處偏薄霧，秋熱苦時恰輕雨。", "回頭却望昭陵松，雲氣成龍或成虎。"]'),
('2edb2238-1425-4d29-9c41-b0eba610b996','寄馬會叔','楊萬里','宋','宋诗','song-poetry','','[]','影轉郎官宿，春隨刺史天。',48,'全唐诗/poet.song.139000.json','["影轉郎官宿，春隨刺史天。", "相從忽相別，同舍況同年。", "我愛吳兒說，兄如邵父然。", "賜金真浪費，喚取從甘泉。"]'),
('b75d7b74-1e5d-4d7a-82b2-b847f739e6e6','送傅安道郎中將漕七閩二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','一代風騷將，百年忠義家。',48,'全唐诗/poet.song.139000.json','["一代風騷將，百年忠義家。", "出關稱使者，踏雪度梅花。", "夢破南宮被，春生北斗槎。", "懸知入奏日，不待貢新茶。"]'),
('92acfef9-9007-4747-8621-6db421cb09f2','送傅安道郎中將漕七閩二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','把酒春如許，論詩夜未央。',48,'全唐诗/poet.song.139000.json','["把酒春如許，論詩夜未央。", "相逢便金石，何必試冰霜。", "離合知難免，愁思自不忘。", "它年一茅屋，公肯訪荒涼。"]'),
('0b0f3b78-63fc-40fd-b17c-01fd8bcf185b','故恭人劉氏挽詞','楊萬里','宋','宋诗','song-poetry','','[]','雨露低蘋沼，芝蘭上桂林。',48,'全唐诗/poet.song.139000.json','["雨露低蘋沼，芝蘭上桂林。", "魚軒簾蹙繡，鸞紙誥塗金。", "死者夫何恨，歸歟乃宿心。", "不偕君子老，愁絕白頭吟。"]'),
('3f42e9a4-1e29-489a-bd43-d6c923f9e18a','王龜齡挽詞','楊萬里','宋','宋诗','song-poetry','','[]','佛以偏師勝，天能一手回。',48,'全唐诗/poet.song.139000.json','["佛以偏師勝，天能一手回。", "橫空立萬仞，不爲作三魁。", "道大身無著，人亡世却哀。", "溪梅那解事，寂寞爲誰開。"]'),
('a130d32a-8db6-4b62-8be3-db0ea93cfd5d','吳母葉氏太孺人挽詞','楊萬里','宋','宋诗','song-poetry','','[]','髮以留賓短，家從教子貧。',48,'全唐诗/poet.song.139000.json','["髮以留賓短，家從教子貧。", "斑衣奉常署，象服鏡湖春。", "許穆詩還廢，班姑史尚新。", "不堪萱草露，也解泣慈親。"]'),
('63472fb3-66aa-420f-9f96-f69dd89b2f0e','答章漢直','楊萬里','宋','宋诗','song-poetry','','[]','詩人今代謝宣城，舉手新年章子平。',64,'全唐诗/poet.song.139000.json','["詩人今代謝宣城，舉手新年章子平。", "雨剩風殘忽春暮，花催草喚又詩成。", "五湖煙水三冬卧，萬里雲霄一日程。", "老裏睡多吟裏少，舊來句熟近來生。"]'),
('074e7871-ff01-4571-91a6-b466b35a40ea','西湖晚歸','楊萬里','宋','宋诗','song-poetry','','["\u897f\u6e56"]','際晚游人也合歸，畫船猶自弄斜暉。',32,'全唐诗/poet.song.139000.json','["際晚游人也合歸，畫船猶自弄斜暉。", "西湖兩岸千株柳，絮不因風暖自飛。"]'),
('ee28b6f6-f3db-4775-a45c-ef5c4fed710f','癸巳省宿詠南宮小桃','楊萬里','宋','宋诗','song-poetry','','[]','孤坐南宮悄，桃花故故紅。',48,'全唐诗/poet.song.139000.json','["孤坐南宮悄，桃花故故紅。", "晴曛半臉日，寒慘數鬚風。", "昔歲山村裏，春光痛飲中。", "不煩渠伴宿，今我已衰翁。"]'),
('a457cfe9-32c6-4d1b-aa38-cf08054d87a4','送李童子西歸','楊萬里','宋','宋诗','song-poetry','','[]','江西李家童子郎，腹載五車干玉皇。',128,'全唐诗/poet.song.139000.json','["江西李家童子郎，腹載五車干玉皇。", "選德殿後春晝長，天子呼來傍御床。", "口角誦書如布穀，眼光骨法俱冰玉。", "紫綃輕衫髮錦束，萬人回頭看不足。", "莫言幼慧長不奇，楊文公與晏臨淄。", "老翁笞兒也太癡，欲鞭轅下追霜蹄。", "六歲取官曲肱似，春風晝繡歸吾里。", "生子當如李童子，至如吾兒豚犬耳。"]'),
('69a8f8f5-b68a-4dbd-a148-f001a5ff1e7f','送林謙之司業出爲桂路提刑','楊萬里','宋','宋诗','song-poetry','','[]','雨眠起宵坐，搔首偶不欣。',192,'全唐诗/poet.song.139000.json','["雨眠起宵坐，搔首偶不欣。", "孤念元無感，懷我同社人。", "昨日林先生，抱經出成均。", "初聞爲渠喜，忽悟誰我親。", "緬然記宿昔，夜款水際門。", "微月耿秋寂，幽蛩慨涼新。", "論詩煮豆粥，粥熟天已晨。", "先生補天手，萬象焉能春。", "若非千載仰，却要今世珍。", "聖門舊傳業，不在先生身。", "雪前何有松，燬中諒非珉。", "論思尺有咫，決去曾逡巡。", "誰言我無耳，老矣未有聞。", "先生又舍我，離別尚足云。", "桂山玉筍立，桂水羅带紋。", "得句能寄似，不須持嶺雲。"]'),
('17044038-6e7b-40d6-9036-3024fda29bac','寄題天台臨海縣白鶴廟西泉','楊萬里','宋','宋诗','song-poetry','','[]','東泉千年流不休，西泉千年秘不流。',104,'全唐诗/poet.song.139000.json','["東泉千年流不休，西泉千年秘不流。", "臨海令君一念作，猿鳥未知泉已覺。", "殿脚西頭蒼石根，向來元無泉眼痕。", "一朝擘崖迸膏乳，却與東泉作賓主。", "令君已昇金掌中，白鶴古祠煙雨濛。", "父老思君難再得，登亭飲泉三歎息，祝君公臺壽千百。"]'),
('c087c305-2e48-4a3c-b617-a6ef26fd3ed4','和韓子雲惠詩','楊萬里','宋','宋诗','song-poetry','','[]','幸自同裘好，誰令異巷居。',48,'全唐诗/poet.song.139000.json','["幸自同裘好，誰令異巷居。", "恭承五箇字，不但百車渠。", "句法端何樣，先生肯乞餘。", "只容彈劍鋏，敢道出無車。"]'),
('3fda8e58-d7a3-4af8-8609-1161d79b5219','送丁子章將漕湖南三首  其一','楊萬里','宋','宋诗','song-poetry','','[]','嶽麓猿聲裏，湘流雁影邊。',48,'全唐诗/poet.song.139000.json','["嶽麓猿聲裏，湘流雁影邊。", "自天持一節，到日是新年。", "身退名逾重，今稀古則然。", "黄花非不好，只是插離筵。"]'),
('37aaf079-46b4-40d9-a9f3-a9c3415c2564','送丁子章將漕湖南三首  其二','楊萬里','宋','宋诗','song-poetry','','[]','湖外遊曾漫，荒餘好在麽。',48,'全唐诗/poet.song.139000.json','["湖外遊曾漫，荒餘好在麽。", "山應依樣瘦，民豈似田多。", "不是無風物，其如費拊摩。", "人言補外樂，且道定如何。"]'),
('00d48b5f-68df-4b24-9c7e-c5a262436c88','送丁子章將漕湖南三首  其三','楊萬里','宋','宋诗','song-poetry','','[]','半世行天下，同心寡友生。',48,'全唐诗/poet.song.139000.json','["半世行天下，同心寡友生。", "故人今又去，此意向誰傾。", "白髮三更語，青燈一點明。", "看渠還玉署，老我正歸耕。"]'),
('242c2121-f287-4ffc-92ed-d5ad8390394d','送葉叔羽寺丞持節淮東二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','呼酒東西玉，探梅南北枝。',48,'全唐诗/poet.song.139000.json','["呼酒東西玉，探梅南北枝。", "相逢長不款，此別有餘思。", "古道寒如水，吾儕鬢已絲。", "一生商略此，更待贈臨岐。"]'),
('2be74082-7f09-461b-8386-07cf4c6cea4e','送葉叔羽寺丞持節淮東二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','煮海誰爲祟，沿淮困不勝。',48,'全唐诗/poet.song.139000.json','["煮海誰爲祟，沿淮困不勝。", "民思賢使者，帝遣大農丞。", "玉節寒侵斗，牙檣凍作冰。", "來歸聞早著，紫禁要渠登。"]'),
('94cca421-985c-4bf7-955c-60251ad9605d','題張興伯主簿經訓堂','楊萬里','宋','宋诗','song-poetry','','[]','范家尚有釜生魚，張家無魚釜也無。',96,'全唐诗/poet.song.139000.json','["范家尚有釜生魚，張家無魚釜也無。", "屠沽兒亦莫笑渠，渠有至富汝不如。", "一翁凍吟擁竹爐，諸郎映雪夜讀書。", "山鬼來聽鶴驚起，萬壑無人霽月孤。", "不論取官大門閭，始是經訓爲菑畬。", "父子每腹百斛珠，出門掩鼻馬牛裾。"]'),
('36f05328-7bdb-4aef-bcca-6ee2a4c9ad42','馬郎中母蔣夫人挽章','楊萬里','宋','宋诗','song-poetry','','[]','文物餘三逕，芝蘭秀五常。',48,'全唐诗/poet.song.139000.json','["文物餘三逕，芝蘭秀五常。", "魚軒來粉省，象服去黄堂。", "此母今誰似，清名死不亡。", "一生令吏部，廢却蓼莪章。"]'),
('73157c82-2e07-4aa2-92b1-274ae5a7fbcf','送韓子雲檢正將漕江東二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','宰士仍名士，詩人更德人。',48,'全唐诗/poet.song.139000.json','["宰士仍名士，詩人更德人。", "還家桐樹古，攬轡繡衣新。", "不以髯邊雪，而忘句裏春。", "登庸衣鉢在，得戀大江濱。"]'),
('0b21c09c-0c89-466f-8af9-edf9f17e83f3','送韓子雲檢正將漕江東二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','名下得佳句，夢中哦半生。',48,'全唐诗/poet.song.139000.json','["名下得佳句，夢中哦半生。", "未逢心已契，相見眼偏明。", "復此匆匆別，蒼然惘惘情。", "非關風外樹，儂自作離聲。"]'),
('fcc4901c-bb7c-45e0-b8b5-9d6a541ff9f9','送陳行之寺丞出守南劍二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','甫爾丞農扈，翩然牧劍津。',48,'全唐诗/poet.song.139000.json','["甫爾丞農扈，翩然牧劍津。", "諸公誰不相，有子幾何人。", "氣節霜餘凜，辭章玉樣新。", "飛騰可輕料，渠亦正青春。"]'),
('26d05395-0b1b-4fc0-91dd-263f62bca261','送陳行之寺丞出守南劍二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','我召公先到，公歸我亦行。',48,'全唐诗/poet.song.139000.json','["我召公先到，公歸我亦行。", "三年如夢爾，一笑可憐生。", "野店緣山去，春風並轡輕。", "先愁饒水上，話別若爲情。"]'),
('052835e4-5f9a-42a1-a71a-63c3d3945f13','送鄉僧德璘二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','衲子向來元士子，詩僧遮莫更禪僧。',32,'全唐诗/poet.song.139000.json','["衲子向來元士子，詩僧遮莫更禪僧。", "不妨參透諸方得，別有宮牆第一層。"]'),
('b5720f1b-d085-4f5a-aec1-a5d972371fcc','送鄉僧德璘二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','湖上諸峰紫翠間，三年欲到幾曾閑。',32,'全唐诗/poet.song.139000.json','["湖上諸峰紫翠間，三年欲到幾曾閑。", "儂今去處渠知麽，不是南山即北山。"]'),
('f83c678f-a750-45ac-a783-8c6d38093e68','別蕭挺之泉州二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','郎署春同宿，州麾晚卜鄰。',48,'全唐诗/poet.song.139000.json','["郎署春同宿，州麾晚卜鄰。", "出山成底事，藉手得斯人。", "名實今無對，雲霄早致身。", "再逢應互笑，誰髮不如銀。"]'),
('c78de75a-eea4-4dfe-a79f-22615f3d04e7','別蕭挺之泉州二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','八葉今成九，一枝誰敢雙。',48,'全唐诗/poet.song.139000.json','["八葉今成九，一枝誰敢雙。", "野人應補外，賢者亦爲邦。", "夾岸梅臨水，孤帆雪湧江。", "別愁纔半掬，不遣我心降。"]'),
('c9b82a6f-4336-435e-a0bf-8c1230293b33','甲午出知漳州晚發船龍山暮宿桐廬二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','一席清風萬壑雲，送將華髮得歸身。',32,'全唐诗/poet.song.139000.json','["一席清風萬壑雲，送將華髮得歸身。", "海潮也怯桐江浄，不遣濤頭過富春。"]'),
('3b229494-5f30-4a5f-b69f-4ca6994e306e','甲午出知漳州晚發船龍山暮宿桐廬二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','道塗奔走不曾安，却羨山家住得閑。',32,'全唐诗/poet.song.139000.json','["道塗奔走不曾安，却羨山家住得閑。", "記取還山安住日，更忘奔走道塗間。"]'),
('f0e5bba4-4db5-420d-962d-425e2140b2b6','上嚴州烏石灘','楊萬里','宋','宋诗','song-poetry','','[]','人語相聞數尺間，其如灘惡費人牽。',32,'全唐诗/poet.song.139000.json','["人語相聞數尺間，其如灘惡費人牽。", "已從灘下過灘上，却立前船待後船。"]'),
('27918f90-b879-4cdc-82f7-e4d4046b30d6','雨裏問訊張定叟通判西園杏花二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','白白紅紅一樹春，晴光炫眼看難真。',32,'全唐诗/poet.song.139000.json','["白白紅紅一樹春，晴光炫眼看難真。", "無端昨夜蕭蕭雨，細錦全機卸作茵。"]'),
('c153da52-ebad-4b9b-9590-8f63c43fabb8','雨裏問訊張定叟通判西園杏花二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','梅不嫌疎杏要繁，主人何忍折令殘。',32,'全唐诗/poet.song.139000.json','["梅不嫌疎杏要繁，主人何忍折令殘。", "也知雨意將無惡，爲勒芳菲故故寒。"]'),
('9eef9225-3ae1-4bf9-8ecf-9d633a38884e','携家小歇嚴州建德縣簿廳曉起','楊萬里','宋','宋诗','song-poetry','','[]','不堪久客只思歸，曉起巡簷强撚髭。',32,'全唐诗/poet.song.139000.json','["不堪久客只思歸，曉起巡簷强撚髭。", "偶聽梅梢啼一鳥，舉頭立看獨多時。"]'),
('246f089b-0bd1-4f32-bd72-1d34fb9393bd','題嚴州新堂','楊萬里','宋','宋诗','song-poetry','','[]','新堂略有次第否，忙裏從公一來覷。',112,'全唐诗/poet.song.139000.json','["新堂略有次第否，忙裏從公一來覷。", "是時新晴收舊雨，小風吹花掠巾屨。", "江山只道不解語，云何惠然堂上聚。", "北山故挽南山住，東溪不遣西溪去。", "向來天藏在何處，遭公拈出天不拒。", "舊亭不爲山作主，背山起樓何以故。", "更煩好手鏟東阜，放出釣臺寸來許。"]'),
('013080a4-213a-4bc5-a58d-c3428bc3e1ad','和馮倅投贈韻二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','先生彈鋏凍吟時，此豈求他一世知。',32,'全唐诗/poet.song.139000.json','["先生彈鋏凍吟時，此豈求他一世知。", "只怨送窮窮不去，元來却不怨工詩。"]'),
('519d6241-23e5-4e4e-bfce-6aea86166a32','和馮倅投贈韻二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','繭紙松煤細作行，兩詩字字可珍藏。',32,'全唐诗/poet.song.139000.json','["繭紙松煤細作行，兩詩字字可珍藏。", "書生伎倆成何事，只博虛名萬古香。"]'),
('f5421444-175c-40c8-9006-7aba45881a3a','積雨小霽暮立捲書亭前二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','報晴底用暮寒爲，薄薄春衫橫見欺。',32,'全唐诗/poet.song.139000.json','["報晴底用暮寒爲，薄薄春衫橫見欺。", "似有如無風細甚，柳絲無頼恰先知。"]'),
('e6f00dd7-48e8-471d-abe1-5c924cb9b93e','積雨小霽暮立捲書亭前二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','淡紫斜陽嫩碧天，一春今夕始開顔。',32,'全唐诗/poet.song.139000.json','["淡紫斜陽嫩碧天，一春今夕始開顔。", "看山偶忘歸來却，月到西廊第二間。"]'),
('3b7ad88a-5f9c-4146-ae68-8751deba41ec','虞丞相挽詞三首  其一','楊萬里','宋','宋诗','song-poetry','','[]','負荷偏宜重，經綸別有源。',48,'全唐诗/poet.song.139000.json','["負荷偏宜重，經綸別有源。", "雪山真將相，赤壁再乾坤。", "奄忽人千古，凄涼月一痕。", "世無生仲達，好手未須論。"]'),
('9542a1de-a0a5-4c21-b993-13c62250edf5','虞丞相挽詞三首  其二','楊萬里','宋','宋诗','song-poetry','','[]','保奭方爲左，希文自請西。',48,'全唐诗/poet.song.139000.json','["保奭方爲左，希文自請西。", "不勞三尺劍，已辦一丸泥。", "已矣歸黄壤，傷哉夢白雞。", "清風誰作誦，何石不天齊。"]'),
('a36355f6-3a40-4564-912a-a4f20fe33dd3','虞丞相挽詞三首  其三','楊萬里','宋','宋诗','song-poetry','','[]','一老堂堂日，諸賢得得來。',48,'全唐诗/poet.song.139000.json','["一老堂堂日，諸賢得得來。", "但令元氣壯，患不塞塵開。", "名大天難著，人亡首忍回。", "東風好西去，吹淚到泉臺。"]'),
('e7d1a3e6-9b35-4c9f-ac73-69a47c1a40f8','南溪山居秋日睡起','楊萬里','宋','宋诗','song-poetry','','[]','客至從嗔不著冠，起來信手攬書看。',32,'全唐诗/poet.song.139000.json','["客至從嗔不著冠，起來信手攬書看。", "小蜂得計欺儂睡，偷飲晴窗硯滴乾。"]'),
('f581d841-97b9-46b5-b70c-1425aacee8a2','秋夕書懷','楊萬里','宋','宋诗','song-poetry','','[]','老去還多感，歸來政倦遊。',48,'全唐诗/poet.song.139000.json','["老去還多感，歸來政倦遊。", "數峰愁外月，一葉靜邊秋。", "偶憶平生事，真供獨笑休。", "燈花吾會得，村酒恰當篘。"]'),
('a72e7d79-a114-485d-a0ba-1ba751bc7926','秋暑二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','一年强半走塵埃，觸熱還山亦快哉。',32,'全唐诗/poet.song.139000.json','["一年强半走塵埃，觸熱還山亦快哉。", "幸自西風歸較早，却教秋暑伴將來。"]'),
('e0e69c6a-09c3-434c-b865-38719ed6b2b2','秋暑二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','追涼能到竹溪無，隔水斜陽未肯晡。',32,'全唐诗/poet.song.139000.json','["追涼能到竹溪無，隔水斜陽未肯晡。", "剩暑不蒙蕉扇扇，細雲聊倩月梳梳。"]'),
('5faa5f09-25b9-4102-8b2d-e0a8334eb22c','觀稼','楊萬里','宋','宋诗','song-poetry','','[]','三年再旱獨堪聞，一熟諸村稍作欣。',32,'全唐诗/poet.song.139000.json','["三年再旱獨堪聞，一熟諸村稍作欣。", "老子朝朝弄田水，眼看翠浪作黄雲。"]'),
('2b02723e-f730-43d1-8633-bac59ddc6c14','感秋','楊萬里','宋','宋诗','song-poetry','','[]','舊不悲秋只愛秋，風中吹笛月中樓。',32,'全唐诗/poet.song.139000.json','["舊不悲秋只愛秋，風中吹笛月中樓。", "如今秋色渾如舊，欲不悲秋不自由。"]'),
('9370713e-80b7-4d9d-b7f6-6836fc97e572','送翁志道','楊萬里','宋','宋诗','song-poetry','','[]','平生翁子妙談天，誰愛青山不愛官。',32,'全唐诗/poet.song.139000.json','["平生翁子妙談天，誰愛青山不愛官。", "一笑同看巖下井，秋來能更起微瀾。"]'),
('e2668684-0651-4842-a53c-0fe58571a9e3','表弟周明道工於傳神而山水亦佳久別來訪贈以絕句二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','筆端人物更江山，外弟周郎兩不難。',32,'全唐诗/poet.song.139000.json','["筆端人物更江山，外弟周郎兩不難。", "可把吳松半江水，博他頭上進賢冠。"]'),
('318689d0-187d-4dfe-97cc-b6b5c148679b','表弟周明道工於傳神而山水亦佳久別來訪贈以絕句二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','儂家有軸郭熙山，墮在冰溪雪嶺間。',32,'全唐诗/poet.song.139000.json','["儂家有軸郭熙山，墮在冰溪雪嶺間。", "有弟新來眼如月，爲儂洗手拾將還。"]'),
('378667ae-baa2-4c8f-af8d-f9b9f99f8609','送彭元忠司戶二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','觸熱能相訪，言歸有底忙。',48,'全唐诗/poet.song.139000.json','["觸熱能相訪，言歸有底忙。", "百聞纔半面，一別又三湘。", "詩入江西社，心傳肘後方。", "木天須此士，丹筆校官黄。"]'),
('5fd30bff-1d82-4245-b26e-f0743dc3b892','送彭元忠司戶二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','浯石高仍瘦，愚溪紺且寒。',48,'全唐诗/poet.song.139000.json','["浯石高仍瘦，愚溪紺且寒。", "憑君聊杖屨，道我問平安。", "句好今逾進，書來剩寄看。", "只言官舍小，簷下過湘灘。"]'),
('2b720f7d-d2f9-40a2-8557-0acc6f1530ee','乙未和楊謹仲教授春興','楊萬里','宋','宋诗','song-poetry','','[]','歸歟還復換年芳，不分官梅惱石腸。',64,'全唐诗/poet.song.139000.json','["歸歟還復換年芳，不分官梅惱石腸。", "黄帽政堪供短棹，白頭可更獻長楊。", "忽逢社裏催搜句，安得花邊對舉觴。", "天上含香有知己，彈冠端復爲王陽。"]'),
('ea362c15-7561-48d5-bbf0-d655333dd556','寄廣東提刑林謙之司業','楊萬里','宋','宋诗','song-poetry','','[]','玉節星槎下九天，祝融海若讓雲煙。',64,'全唐诗/poet.song.139000.json','["玉節星槎下九天，祝融海若讓雲煙。", "故人一別還三歲，新句如今更幾篇。", "憶昨待班南內否，論詩看雪未央前。", "夢中若箇韶州路，庾嶺梅花正可憐。"]'),
('6b15a99d-9c87-45e1-a893-7fd960ef69c2','送子上弟之石井','楊萬里','宋','宋诗','song-poetry','','[]','我生苦終鮮，四海皆弟兄。',120,'全唐诗/poet.song.139000.json','["我生苦終鮮，四海皆弟兄。", "四海尚如許，而況吾宗盟。", "君年甫弱冠，已有儁異聲。", "作賦擬三都，著論追過秦。", "平生一瓣香，何曾舉似人。", "子上與濟翁，真若吾同生。", "我窮無人共，二子慰眼明。", "濟翁往荆州，君作石井行。", "一老便落莫，有話從誰評。", "懷哉勿重陳，呼酒且細傾。"]'),
('a50f1e10-b99e-40b1-8d78-61b37704ec26','雨中送客','楊萬里','宋','宋诗','song-poetry','','[]','閑人也解有忙時，送客誰令作許癡。',32,'全唐诗/poet.song.139000.json','["閑人也解有忙時，送客誰令作許癡。", "一夜黑風吹白雪，昨朝紫陌總黄泥。"]'),
('9063e5ab-f96d-4482-8c09-b9ce2c583fbe','送客夜歸呈蕭岳英縣丞','楊萬里','宋','宋诗','song-poetry','','[]','並舍頻過亦幾曾，却因送客得同行。',64,'全唐诗/poet.song.139000.json','["並舍頻過亦幾曾，却因送客得同行。", "風船逆水四十里，雪屋吹燈三二更。", "老去病身禁底苦，向來危宦若爲情。", "天台香火儂當覓，且伴先生學養生。"]'),
('d9f184e1-8844-4c12-b43b-42b455af76f7','二月望日','楊萬里','宋','宋诗','song-poetry','','[]','海棠著意喚詩愁，桃李纔開又落休。',32,'全唐诗/poet.song.139000.json','["海棠著意喚詩愁，桃李纔開又落休。", "小雨輕風春一半，去年今日在嚴州。"]'),
('844dfb34-4a06-4110-a7b0-ede2317b839d','醉筆呈尚長道','楊萬里','宋','宋诗','song-poetry','','[]','晚風一雨生新漲，只送仙槎到天上。',128,'全唐诗/poet.song.139000.json','["晚風一雨生新漲，只送仙槎到天上。", "十年相別一相逢，和氣春風談笑中。", "如今耆舊晨星似，猶及先生說遺事。", "舌端往往疏九河，只有剩浪無欠波。", "漢渠周柱幾青竹，却在先生一泓腹。", "諸公道是今乏才，如何此士尚塵埃。", "此行青規更黄閣，拭目孤鴻徑寥廓。", "能念南溪病客無，風來肯寄半行書。"]'),
('c0e8591e-7eb6-4331-94de-6b25992f2ca3','初夏三絕句  其一','楊萬里','宋','宋诗','song-poetry','','[]','麥黄秧碧百家衣，已熱猶寒四月時。',32,'全唐诗/poet.song.139000.json','["麥黄秧碧百家衣，已熱猶寒四月時。", "雨後覓春無一寸，野薔薇發釅燕脂。"]'),
('c300993d-7a7e-4acd-9fbe-4bae7107e9de','初夏三絕句  其二','楊萬里','宋','宋诗','song-poetry','','[]','手種琅玕劣十年，今年新筍不勝繁。',32,'全唐诗/poet.song.139000.json','["手種琅玕劣十年，今年新筍不勝繁。", "不知明早添多少，日暮閑來數一番。"]'),
('82bd56cb-c4e8-4665-91f7-56ca369049bf','初夏三絕句  其三','楊萬里','宋','宋诗','song-poetry','','[]','竹間露重午方乾，松裏雲深夏亦寒。',32,'全唐诗/poet.song.139000.json','["竹間露重午方乾，松裏雲深夏亦寒。", "只道一溪無十里，爲誰百屈更千盤。"]'),
('a252a80d-72e7-4dcf-b32a-b74ec4e707ef','行圃','楊萬里','宋','宋诗','song-poetry','','[]','薤本新痕割復齊，豆苗初葉合仍離。',32,'全唐诗/poet.song.139000.json','["薤本新痕割復齊，豆苗初葉合仍離。", "鶑聲政好還飛去，不爲詩人更許時。"]'),
('ce24bf1f-2fb9-449d-a1db-409dab9ffb8e','看筍六言','楊萬里','宋','宋诗','song-poetry','','[]','筍如滕薛爭長，竹似夷齊獨清。',28,'全唐诗/poet.song.139000.json','["筍如滕薛爭長，竹似夷齊獨清。", "只愛錦綳滿地，暗林忽兩三莖。"]'),
('c583a894-b505-4638-8922-fbe797b020c5','農家六言','楊萬里','宋','宋诗','song-poetry','','[]','插秧已蓋田面，疎苗猶逗水光。',28,'全唐诗/poet.song.139000.json','["插秧已蓋田面，疎苗猶逗水光。", "白鷗飛處極浦，黄犢歸時夕陽。"]'),
('cec6896b-31ea-48e7-90d4-ab07cf5f67e8','山居','楊萬里','宋','宋诗','song-poetry','','[]','鬢秃猶云少，書多却道窮。',48,'全唐诗/poet.song.139000.json','["鬢秃猶云少，書多却道窮。", "柴門疎竹處，茅屋萬山中。", "幽夢時能憶，閑題底要工。", "不知蟬報夏，爲復自吟風。"]'),
('75f5a580-6b1a-4ea0-86ee-36db6974ad6f','有歎','楊萬里','宋','宋诗','song-poetry','','[]','老來無面見毛錐，猶把閑愁付小詩。',32,'全唐诗/poet.song.139000.json','["老來無面見毛錐，猶把閑愁付小詩。", "若道愁多頭易白，鷺鷥從小鬢成絲。"]'),
('4b471c48-f43f-4c8c-839b-9bcf5bba3a5f','梅熟小雨','楊萬里','宋','宋诗','song-poetry','','[]','風從獨樹忽然來，雨去前山遠却迴。',32,'全唐诗/poet.song.139000.json','["風從獨樹忽然來，雨去前山遠却迴。", "留許枝間慰愁眼，兒童抵死打黄梅。"]'),
('8f4e6001-bea1-4180-b70e-e7963d0e5f5f','書王右丞詩後','楊萬里','宋','宋诗','song-poetry','','[]','晚因子厚識淵明，早學蘇州得右丞。',32,'全唐诗/poet.song.139000.json','["晚因子厚識淵明，早學蘇州得右丞。", "忽夢少陵談句法，勸參庾信謁陰鏗。"]'),
('e1939edf-40fb-45e1-802c-29dbea002b0f','飯罷登山','楊萬里','宋','宋诗','song-poetry','','[]','樹遠通鶑響，花晴带雨痕。',48,'全唐诗/poet.song.139000.json','["樹遠通鶑響，花晴带雨痕。", "登山偶回首，隔水見前村。", "澹往孤無伴，清歸笑不言。", "還家更遲著，松菊未應存。"]'),
('7b1efa7f-ca43-48c7-bf7b-c36422708e8b','待次臨漳諸公薦之易地毗陵自媿無濟劇才上章丐祠','楊萬里','宋','宋诗','song-poetry','','[]','亦豈真辭祿，誰令自不才。',48,'全唐诗/poet.song.139000.json','["亦豈真辭祿，誰令自不才。", "更須三釜戀，未放兩眉開。", "道我今貧却，何朝不飯來。", "商量若爲可，杜宇一聲催。"]'),
('f8a71f6b-ac3c-44f7-85a1-42efbf45fcb9','梔子花','楊萬里','宋','宋诗','song-poetry','','[]','樹恰人來短，花將雪樣看。',48,'全唐诗/poet.song.139000.json','["樹恰人來短，花將雪樣看。", "孤姿妍外浄，幽馥暑中寒。", "有朶篸瓶子，無風忽鼻端。", "如何山谷老，只爲賦山礬。"]'),
('48b2ef8f-f44a-430c-8ab6-7d43167a9b6b','謝傅宣州安道郎中送宣城筆','楊萬里','宋','宋诗','song-poetry','','[]','忽驚騎吏叩柴荆，厚祿移書訪死生。',64,'全唐诗/poet.song.139000.json','["忽驚騎吏叩柴荆，厚祿移書訪死生。", "今日猶遲傅巖雨，前身端是謝宣城。", "解包兔穎霜盈把，試墨山泉月一泓。", "老裏苦吟翻作拙，撚鬚枉斷兩三莖。"]'),
('c60871c6-458f-4b9a-8597-51910dc5f78c','病瘧無聊','楊萬里','宋','宋诗','song-poetry','','[]','病身兀兀意昏昏，急掛東窗避夕曛。',32,'全唐诗/poet.song.139000.json','["病身兀兀意昏昏，急掛東窗避夕曛。", "坐看雲生還有雨，忽然雨止併無雲。"]'),
('6ca8eb4a-f6e1-4c1c-a5a5-d915ac5d47c5','秋典','楊萬里','宋','宋诗','song-poetry','','[]','宿有青霞願，惟應白鷺知。',48,'全唐诗/poet.song.139000.json','["宿有青霞願，惟應白鷺知。", "風煙聊晚望，山水入秋宜。", "老裏還多病，貧中却剩詩。", "浪愁餘熱在，會自有涼時。"]'),
('34a8cc1e-629f-4aa5-83c3-7f85b80a951b','中秋與諸子果飲','楊萬里','宋','宋诗','song-poetry','','[]','幾年今夕一番逢，千古何人此興同。',64,'全唐诗/poet.song.139000.json','["幾年今夕一番逢，千古何人此興同。", "酒入銀河波底月，笛吹玉桂樹梢風。", "莫言秋色無多巧，浄洗清光也費工。", "老子病來渾不飲，如何頻報綠尊空。"]'),
('43585bae-cf1a-462e-88d6-6ea0342492e4','挽鄒彥明','楊萬里','宋','宋诗','song-poetry','','[]','野渡無冰涉，荒民不木饑。',48,'全唐诗/poet.song.139000.json','["野渡無冰涉，荒民不木饑。", "橋橫侍郎記，墓立舍人碑。", "自古誰無死，何人沒後思。", "淙淙富川水，便是挽歌詞。"]'),
('6b0bb28d-2fc2-4cb9-88c5-1d6f520632c2','探梅偶李判官餽熊掌','楊萬里','宋','宋诗','song-poetry','','[]','小摘梅花篸玉壺，旋糟熊掌削瓊膚。',32,'全唐诗/poet.song.139000.json','["小摘梅花篸玉壺，旋糟熊掌削瓊膚。", "燈前雪裏新醅熟，放却先生不醉無。"]'),
('25541f30-9042-4d6f-ae9c-403313c86b23','醉後撚梅花近壁以燈照之宛然如墨梅','楊萬里','宋','宋诗','song-poetry','','[]','老子年來畫入神，鑿空幻出墨梅春。',32,'全唐诗/poet.song.139000.json','["老子年來畫入神，鑿空幻出墨梅春。", "壁爲玉板燈爲筆，整整斜斜樣樣新。"]'),
('6e5686f9-515b-4a28-b3f4-baeaa91a5995','釣雪舟倦睡','楊萬里','宋','宋诗','song-poetry','','[]','小閣明窗半掩門，看書作睡政昏昏。',32,'全唐诗/poet.song.139000.json','["小閣明窗半掩門，看書作睡政昏昏。", "無端却被梅花惱，特地吹香破夢魂。"]'),
('2ee0b4b3-9769-4fa9-8c1e-bfe835499d39','晚步南溪弄水','楊萬里','宋','宋诗','song-poetry','','[]','吾廬在南溪，溪北北山半。',180,'全唐诗/poet.song.139000.json','["吾廬在南溪，溪北北山半。", "山空誰肯鄰，影靜鶴爲伴。", "萬松當籬落，千巖上几案。", "花草豈厭多，不多亦堪翫。", "一丘萬事足，半點無外羨。", "如何濯雙纓，獨欠泉一眼。", "晚晴漫野步，偶到溪側畔。", "頗怪清淺流，雪後劣如線。", "相將二三子，一笑出奇觀。", "瓊砂雜瑶礫，掇拾作微堰。", "鏘然便淙琤，清若奏琴阮。", "當流立孤石，灧澦忽童丱。", "不塞勢何怒，惟激聲故遠。", "從今日日來，愁肺要湔浣。", "兒童俾勿壞，鷗鷺好看管。"]'),
('d352c69c-8ef5-4ac0-aeaf-9e5ebb284a33','醉眠夜聞霜風甚緊起坐達旦二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','玉酒醺人底易醒，月低梅影恰三更。',32,'全唐诗/poet.song.139000.json','["玉酒醺人底易醒，月低梅影恰三更。", "只嫌老眼清無睡，不道松聲聽到明。"]'),
('cef67376-0592-4a98-bad4-4bf262828917','醉眠夜聞霜風甚緊起坐達旦二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','雪花旋落旋成融，橫作清霜陣陣風。',32,'全唐诗/poet.song.139000.json','["雪花旋落旋成融，橫作清霜陣陣風。", "一夜急吹君會否，妬它殘葉戀丹楓。"]'),
('b9392a15-7571-473f-9fbe-70ac99f6e389','霜夜望月','楊萬里','宋','宋诗','song-poetry','','[]','人靜蛩喧天欲霜，不眠獨自步風廊。',32,'全唐诗/poet.song.139000.json','["人靜蛩喧天欲霜，不眠獨自步風廊。", "閑看月走仍雲走，知是雲忙復月忙。"]'),
('5869e554-c02a-41ab-919d-d196494ad277','瓶中梅花長句','楊萬里','宋','宋诗','song-poetry','','["\u897f\u6e56"]','幽人蚤作月滿階，月隨幽人登舫齋。',240,'全唐诗/poet.song.139000.json','["幽人蚤作月滿階，月隨幽人登舫齋。", "推門欲開猶未開，猛香排門撲我懷。", "徑從鼻孔上灌頂，拂拂吹盡髮底埃。", "恍然墮我衆香國，欲問何祥無處覓。", "冥搜一室一物無，瓶裏一枝梅的皪。", "平生爲梅判斷腸，何曾知渠有許香。", "夜來偶忘挂南窗，貯此幽馥萬斛强。", "却憶去年西湖上，錦屏下瞰千青嶂。", "谷深梅盛一萬株，十頃雪花浮欲漲。", "是時雨後初晴前，日光烘花香作煙。", "政如新火炷博山，烝出沉水和龍涎。", "醉登絕頂撼疎影，掇蕊餐花照冰井。", "蜀人老張同舍郎，喚作謫仙儂笑領。", "如今茅屋卧山村，更無載酒來叩門。", "一尊孤斟懶論文，猶有梅花是故人。"]'),
('a159612c-0c94-4001-bfcb-e3f41ead4931','夜飲以白糖嚼梅花','楊萬里','宋','宋诗','song-poetry','','[]','剪雪作梅只堪嗅，點蜜如霜新可口。',64,'全唐诗/poet.song.139000.json','["剪雪作梅只堪嗅，點蜜如霜新可口。", "一花自可嚥一杯，嚼盡寒花幾杯酒。", "先生清貧似饑蚊，饞涎流到瘦脛根。", "贛江壓糖白於玉，好伴梅花聊當肉。"]'),
('caebea83-9a5d-49ac-9b84-62aa777c1ad2','釣雪舟中霜夜望月','楊萬里','宋','宋诗','song-poetry','','[]','溪邊小立苦待月，月知人意偏遲出。',112,'全唐诗/poet.song.139000.json','["溪邊小立苦待月，月知人意偏遲出。", "歸來閉戶悶不看，忽然飛上千峰端。", "却登釣雪聊一望，冰輪正挂松梢上。", "詩人愛月愛中秋，有人問儂儂掉頭。", "一年月色只臘裏，雪汁揩磨霜水洗。", "八荒萬里一青天，碧潭浮出白玉盤。", "更約梅花作渠伴，中秋不是欠此段。"]'),
('717bb178-7877-4bb5-8502-3fa550d144cd','梅花下小飲','楊萬里','宋','宋诗','song-poetry','','[]','今年春在臘前回，怪底空山早見梅。',64,'全唐诗/poet.song.139000.json','["今年春在臘前回，怪底空山早見梅。", "數點有情吹面過，一花無頼背人開。", "爲携竹葉澆瓊樹，旋折冰葩浸玉盃。", "近節雨晴誰料得，明朝無興也重來。"]'),
('141d9211-4ba8-46a1-b077-47a00b1df530','幽居三詠 釣雪舟','楊萬里','宋','宋诗','song-poetry','','[]','青鞋黄帽綠蓑衣，釣雪舟中雪政飛。',32,'全唐诗/poet.song.139000.json','["青鞋黄帽綠蓑衣，釣雪舟中雪政飛。", "歸自嚴州無一物，扁舟載得釣臺歸。"]'),
('33d3239e-36b0-4bf0-86be-498849ac92ef','幽居三詠 雲卧菴','楊萬里','宋','宋诗','song-poetry','','[]','十年兩袖軟紅塵，歸濯滄浪且幅巾。',32,'全唐诗/poet.song.139000.json','["十年兩袖軟紅塵，歸濯滄浪且幅巾。", "不是白雲留我住，我留雲住卧閑身。"]'),
('b10ba1a5-f86a-4ad6-a133-36c82c9b8c26','幽居三詠 誠齋','楊萬里','宋','宋诗','song-poetry','','[]','浯溪見了紫巖回，獨笑春風儘放懷。',32,'全唐诗/poet.song.139000.json','["浯溪見了紫巖回，獨笑春風儘放懷。", "謾向世人談昨夢，便來喚我作誠齋。"]'),
('330d5433-c869-4b4c-bd59-7f7f57b0229a','寄題更好軒二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','經丘尋壑恰忙時，更有工夫到得詩。',32,'全唐诗/poet.song.139000.json','["經丘尋壑恰忙時，更有工夫到得詩。", "政用此時索詩債，素兄青士若爲癡。"]'),
('27851682-88c4-4106-aa2a-053c8ededff6','寄題更好軒二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','無梅有竹竹無朋，有竹無梅梅獨醒。',32,'全唐诗/poet.song.139000.json','["無梅有竹竹無朋，有竹無梅梅獨醒。", "雪裏霜中兩清絕，梅花白白竹青青。"]'),
('09c9db7a-c7ec-4a48-8e7e-afe2ced7552a','郡中送春盤','楊萬里','宋','宋诗','song-poetry','','[]','餠如繭紙不可風，菜如縹茸劣可縫。',96,'全唐诗/poet.song.139000.json','["餠如繭紙不可風，菜如縹茸劣可縫。", "韭芽捲黄苣舒紫，蘆菔削冰寒脫齒。", "卧沙壓玉割紅香，部署五珍訪詩腸。", "野人未見新曆日，忽得春盤還太息。", "新年五十奈老何，霜鬚看鏡幾許多。", "麴生嗔人不解事，且爲春盤作春醉。"]'),
('c7deedf5-626e-4ee8-bf44-f503d4d2eb1c','臘裏立春蜂蝶輩出','楊萬里','宋','宋诗','song-poetry','','[]','嫩日催青出凍荄，小風吹白落疎梅。',32,'全唐诗/poet.song.139000.json','["嫩日催青出凍荄，小風吹白落疎梅。", "殘冬未放春交割，早有黄蜂紫蝶來。"]'),
('69ead440-3df7-472c-ae7e-fb9064abf54f','梅花落盡有感','楊萬里','宋','宋诗','song-poetry','','[]','五樹梅花一樹遲，花遲花早總離披。',32,'全唐诗/poet.song.139000.json','["五樹梅花一樹遲，花遲花早總離披。", "春風只解吹梅落，不爲愁人染鬢絲。"]'),
('a73b3e55-de62-49d0-a4b6-804e27c3d268','丙申歲朝','楊萬里','宋','宋诗','song-poetry','','[]','椒盤又頌一年初，多拜猶欣未要扶。',64,'全唐诗/poet.song.139000.json','["椒盤又頌一年初，多拜猶欣未要扶。", "山色長供青篛笠，春光不爲白髭鬚。", "仙家風土閑中是，歲後鶑花較早無。", "人事馳驅不須歎，倦來添得睡工夫。"]'),
('fc1bab39-e82a-4846-873a-f664212611be','與劉景明晚步','楊萬里','宋','宋诗','song-poetry','','[]','行盡南溪溪北涯，李花看了看桃花。',32,'全唐诗/poet.song.139000.json','["行盡南溪溪北涯，李花看了看桃花。", "歸來倦卧呼童子，旋煮山泉瀹建茶。"]'),
('fd7c5a2b-9c70-4dd8-a818-0f89a8a078d4','贈劉景明來訪','楊萬里','宋','宋诗','song-poetry','','[]','研席相從昔少年，白頭誰信兩蒼然。',64,'全唐诗/poet.song.139000.json','["研席相從昔少年，白頭誰信兩蒼然。", "來從八桂三湘外，憶折雙松十載前。", "告我明朝還又別，對床終夕不成眠。", "交游存沒休休說，且爲梅花釂玉船。"]'),
('55168e67-d340-45b1-91fb-b6d6f1e6251c','曉看牡丹呈彭仲莊','楊萬里','宋','宋诗','song-poetry','','[]','牡丹新植舊來無，早起看花花更蘇。',64,'全唐诗/poet.song.139000.json','["牡丹新植舊來無，早起看花花更蘇。", "晴翠滿空天政曉，暖紅蒸霧汗成珠。", "絕憐嫩日偏催老，猶喜輕寒爲給扶。", "來歲一株應百朶，只今紫笋繞根鬚。"]'),
('a0f58ffe-8375-4b3e-b3e4-5317281a574e','和彭仲莊對牡丹止酒二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','病身無伴卧空山，石友相從慰眼寒。',32,'全唐诗/poet.song.139000.json','["病身無伴卧空山，石友相從慰眼寒。", "呼酒撚花談舊事，牡丹匹似夢中看。"]'),
('4ba7cac3-5e52-4357-8df3-cac7bbcdc85a','和彭仲莊對牡丹止酒二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','老裏心情客裏懷，逢花不飲若爲開。',32,'全唐诗/poet.song.139000.json','["老裏心情客裏懷，逢花不飲若爲開。", "虛名身後真何用，更判生前酒一杯。"]'),
('d76a11ac-c64b-4b2c-bba7-0fe75b058884','暮春小雨','楊萬里','宋','宋诗','song-poetry','','[]','宿酒微醒尚小醺，似癡如病不多欣。',32,'全唐诗/poet.song.139000.json','["宿酒微醒尚小醺，似癡如病不多欣。", "深深池沼輕輕雨，獨倚欄干看水紋。"]'),
('73082ea2-0040-4892-944e-fa2180864670','夏日絕句','楊萬里','宋','宋诗','song-poetry','','[]','不但春妍夏亦佳，隨緣花草是生涯。',32,'全唐诗/poet.song.139000.json','["不但春妍夏亦佳，隨緣花草是生涯。", "鹿葱解插纖長柄，金鳳仍開最小花。"]'),
('ba526c0f-354b-44c2-99b0-fc6f1821c728','小池','楊萬里','宋','宋诗','song-poetry','','["\u63cf\u5199\u6c34", "\u590f\u5929", "\u4e00\u5e74\u7ea7\u4e0b\u518c", "\u53e4\u8bd7\u4e09\u767e\u9996", "\u5b8b\u8bd7", "\u6c34"]','泉眼無聲惜細流，樹陰照水愛晴柔。',32,'全唐诗/poet.song.139000.json','["泉眼無聲惜細流，樹陰照水愛晴柔。", "小荷纔露尖尖角，早有蜻蜓立上頭。"]'),
('1826645e-aed7-4524-84d3-a6715136e98d','題左正卿壽慈堂','楊萬里','宋','宋诗','song-poetry','','[]','萬事絲窠黏露珠，奉親最樂天下無。',96,'全唐诗/poet.song.139000.json','["萬事絲窠黏露珠，奉親最樂天下無。", "丘明遠孫千里駒，有母七十髮漆如。", "雪底笋生冰底魚，人間無覓天賜渠。", "三更月落堂西隅，母自挑燈兒讀書。", "去年生日不用扶，今年生日健過初。", "冰桃碧藕脆如酥，一觴千歲母子俱。"]'),
('87fdf471-33b6-4a19-bb1f-3eba34a3effe','挽謝母安人胡氏','楊萬里','宋','宋诗','song-poetry','','[]','玉樹仍雙桂，金花不一書。',48,'全唐诗/poet.song.139000.json','["玉樹仍雙桂，金花不一書。", "雪封青竹笋，霧失白藤輿。", "天下誰無母，江西未有渠。", "西峰半輪月，松檟政疎疎。"]'),
('69c9a4b5-a7cc-43c7-8709-6df597a114d2','雨霽幽興寄張欽夫','楊萬里','宋','宋诗','song-poetry','','[]','大官有重荷，豐廩無薄憂。',132,'全唐诗/poet.song.139000.json','["大官有重荷，豐廩無薄憂。", "草茹我豈腴，飽亦與彼侔。", "積雨久自霽，曙光清以幽。", "欣然出荆扉，不出旬已周。", "初意欲看竹，信步偶臨流。", "北驚失故岸，東見生新洲。", "懷哉古與今，與此豈不猶。", "歸來翻不樂，隠几到昔遊。", "平生忘年友，草草相應酬。", "暫夢不多款，喚人苦鳴鳩。", "山林本無事，亦復擾擾休。"]'),
('35d78356-e51a-4e21-8782-e8094707bbed','題劉伯山蕃殖圖二首畫禾黍稌菽麥  其一','楊萬里','宋','宋诗','song-poetry','','[]','老子平生只荷鋤，誤携破硯到清都。',32,'全唐诗/poet.song.139000.json','["老子平生只荷鋤，誤携破硯到清都。", "歸來荒盡西疇却，媿見劉家蕃殖圖。"]'),
('16eca604-8d3b-443d-88a4-16e9ecd73bf8','題劉伯山蕃殖圖二首畫禾黍稌菽麥  其二','楊萬里','宋','宋诗','song-poetry','','[]','黄雲翠莢雜玄珠，上熟今年不負渠。',32,'全唐诗/poet.song.139000.json','["黄雲翠莢雜玄珠，上熟今年不負渠。", "說似田家早收拾，一番風雨一番疎。"]'),
('2686ac3c-353c-4b20-b1b0-26561844c35f','極暑題釣雪','楊萬里','宋','宋诗','song-poetry','','[]','暑中北閣望南窗，將謂南窗分外涼。',32,'全唐诗/poet.song.139000.json','["暑中北閣望南窗，將謂南窗分外涼。", "到得南窗還更熱，芙蕖和蕊落幽香。"]'),
('c46ec5c2-bed5-401c-a0c0-07abb75fcde9','讀書','楊萬里','宋','宋诗','song-poetry','','[]','讀書不厭勤，勤甚倦且昏。',84,'全唐诗/poet.song.139000.json','["讀書不厭勤，勤甚倦且昏。", "不如卷書坐，人書兩忘言。", "興來忽開卷，徑到百聖源。", "說悟本無悟，談玄初未玄。", "當其會心處，只有一欣然。", "此樂誰爲者，非我亦非天。", "自笑終未是，撥書枕頭眠。"]'),
('c2937f52-1f42-4ad8-89d8-8167c3efdd1a','六月二十三日立秋','楊萬里','宋','宋诗','song-poetry','','[]','暑中剩喜立秋初，特地西風半點無。',32,'全唐诗/poet.song.139000.json','["暑中剩喜立秋初，特地西風半點無。", "旋汲井花澆睡眼，灑將荷葉看跳珠。"]'),
('36410a92-a93e-4adf-9b79-4afe4adff348','聽雨','楊萬里','宋','宋诗','song-poetry','','[]','歸舟昔歲宿嚴陵，雨打疎篷聽到明。',32,'全唐诗/poet.song.139000.json','["歸舟昔歲宿嚴陵，雨打疎篷聽到明。", "昨夜茅簷疎雨作，夢中喚作打篷聲。"]'),
('792ef368-1298-425c-84fa-7bf55f16342f','中秋前二夕釣雪舟中靜坐二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','月到南窗小半扉，無燈始覺室生輝。',32,'全唐诗/poet.song.139000.json','["月到南窗小半扉，無燈始覺室生輝。", "人間何處冰壺是，身在冰壺却道非。"]'),
('4d2abeec-3c52-4ca7-aa15-99f154f35cbf','中秋前二夕釣雪舟中靜坐二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','去歲中秋政病餘，愛它月色强支吾。',32,'全唐诗/poet.song.139000.json','["去歲中秋政病餘，愛它月色强支吾。", "今年老矣差無病，後夜中秋有月無。"]'),
('e83a0699-cbd3-4fda-887c-93e54112eb04','中秋無月既望月甚佳二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','中秋無月莫尤天，月入秋來夜夜妍。',32,'全唐诗/poet.song.139000.json','["中秋無月莫尤天，月入秋來夜夜妍。", "且道今宵明月色，何曾減却半分圜。"]'),
('1ab3b02b-8bbf-4c0e-8fbc-55ffb07ae032','中秋無月既望月甚佳二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','月到中秋故故無，今宵月好莫渠孤。',32,'全唐诗/poet.song.139000.json','["月到中秋故故無，今宵月好莫渠孤。", "舊傳月徑圜千里，影落金杯只粒珠。"]'),
('26644747-6b32-4145-ba49-c78d2212996d','晚興','楊萬里','宋','宋诗','song-poetry','','[]','雙井茶芽醒骨甜，蓬萊香燼倦人添。',32,'全唐诗/poet.song.139000.json','["雙井茶芽醒骨甜，蓬萊香燼倦人添。", "蜘蛛政苦空庭闊，風爲將絲度別簷。"]'),
('b1f70e75-801f-4419-986a-2459023cbba1','約劉彥純會建安寺','楊萬里','宋','宋诗','song-poetry','','[]','邂逅何時可，平章後月涼。',48,'全唐诗/poet.song.139000.json','["邂逅何時可，平章後月涼。", "前期來一夕，古寺作重陽。", "白酒多多載，黄花急急香。", "遣詩愁已遣，何況更連床。"]'),
('a86c6b1b-119e-419a-b8d7-f21bec3bdbc4','送客山行','楊萬里','宋','宋诗','song-poetry','','[]','嶺雲爲作小涼天，山店重來憶去年。',32,'全唐诗/poet.song.139000.json','["嶺雲爲作小涼天，山店重來憶去年。", "獨樹丹楓誰不見，何須更立萬松前。"]'),
('1b425433-7fbd-4371-a906-d480702aa93a','秋月','楊萬里','宋','宋诗','song-poetry','','[]','夜氣涼於水，高齋可當樓。',48,'全唐诗/poet.song.139000.json','["夜氣涼於水，高齋可當樓。", "古來除却月，此外更無秋。", "寒入蘭心勁，光隨菊脚流。", "惟愁清不極，清極却成愁。"]'),
('0b2588e3-74b3-4e93-adac-31cc5251dc45','雨夜','楊萬里','宋','宋诗','song-poetry','','[]','歲晚能無感，詩成只獨哦。',48,'全唐诗/poet.song.139000.json','["歲晚能無感，詩成只獨哦。", "螢光寒欲淡，秋雨暮偏多。", "伴老貧無恙，留愁酒肯麽。", "吟蟲將落葉，爲我拍還歌。"]'),
('10545315-c489-4326-bc52-e512f2023d5f','秋雨歎十解  其一','楊萬里','宋','宋诗','song-poetry','','[]','雨入秋宵滴到明，不知有意復無情。',32,'全唐诗/poet.song.139000.json','["雨入秋宵滴到明，不知有意復無情。", "若言不攪愁人夢，爲許千千萬萬聲。"]'),
('ce7eaa41-dbae-4f36-95c8-30748f26faf6','秋雨歎十解  其二','楊萬里','宋','宋诗','song-poetry','','[]','霖霖滴滴未休休，不解教儂不白頭。',32,'全唐诗/poet.song.139000.json','["霖霖滴滴未休休，不解教儂不白頭。", "却把窮愁比秋雨，猶應秋雨少於愁。"]'),
('a92fe31d-2a66-49aa-b46e-2e4a1e3940c9','秋雨歎十解  其三','楊萬里','宋','宋诗','song-poetry','','[]','濕侵團扇不能輕，冷逼孤燈分外明。',32,'全唐诗/poet.song.139000.json','["濕侵團扇不能輕，冷逼孤燈分外明。", "蕉葉半黄荷葉碧，兩家秋雨一家聲。"]'),
('e0cd30f8-2d45-4759-9481-7c8718aead9a','秋雨歎十解  其四','楊萬里','宋','宋诗','song-poetry','','[]','厭聽點滴井邊桐，起看空濛一望中。',32,'全唐诗/poet.song.139000.json','["厭聽點滴井邊桐，起看空濛一望中。", "橫著東山三十里，真珠簾外翠屏風。"]'),
('c982b1aa-8df2-4e3e-bd24-98db2e58e01c','秋雨歎十解  其五','楊萬里','宋','宋诗','song-poetry','','[]','籬下黄花最恨它，金鈿香少淚痕多。',32,'全唐诗/poet.song.139000.json','["籬下黄花最恨它，金鈿香少淚痕多。", "仙人解補銀河漏，天上無泥奈許何。"]'),
('94e484ce-4186-4ae0-a23e-c212bebb317c','秋雨歎十解  其六','楊萬里','宋','宋诗','song-poetry','','[]','老子愁來只苦吟，一吟一嘆爲秋霖。',32,'全唐诗/poet.song.139000.json','["老子愁來只苦吟，一吟一嘆爲秋霖。", "居人只道秋霖苦，不道行人泥更深。"]'),
('08c3ff7a-af5c-47aa-a9bb-e819fabe4c47','秋雨歎十解  其七','楊萬里','宋','宋诗','song-poetry','','[]','晝落無聲夜有聲，只堪醉聽不堪醒。',32,'全唐诗/poet.song.139000.json','["晝落無聲夜有聲，只堪醉聽不堪醒。", "簷牙半點能多少，滴入苔階一寸青。"]'),
('33686269-bf45-4505-a963-ba205d0bdf9f','秋雨歎十解  其八','楊萬里','宋','宋诗','song-poetry','','[]','曉起窮忙作麽生，雨中安否問秋英。',32,'全唐诗/poet.song.139000.json','["曉起窮忙作麽生，雨中安否問秋英。", "枯荷倒盡饒渠著，滴損蘭花太薄情。"]'),
('7f3d2d58-711d-49cd-8041-57c4cb8afa03','秋雨歎十解  其九','楊萬里','宋','宋诗','song-poetry','','[]','似霧如塵有却無，須臾密密復疎疎。',32,'全唐诗/poet.song.139000.json','["似霧如塵有却無，須臾密密復疎疎。", "忽忘九月清霜曉，喚作濛濛二月初。"]'),
('d357232c-8248-4118-87a2-492f161f2c3a','秋雨歎十解  其一○','楊萬里','宋','宋诗','song-poetry','','[]','不是簷聲不放眠，只將愁思壓衰年。',32,'全唐诗/poet.song.139000.json','["不是簷聲不放眠，只將愁思壓衰年。", "道他滴瀝渾無頼，不到侯門舞袖邊。"]'),
('180e0b21-e525-4757-b622-252c54260b2b','寄題劉直卿冰壺二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','外看積翠玉千峰，中有清池月半弓。',32,'全唐诗/poet.song.139000.json','["外看積翠玉千峰，中有清池月半弓。", "更拓長堤三十里，剩栽楊柳與芙蓉。"]'),
('d42cad32-8d75-4819-8bdc-8cb8edd66476','寄題劉直卿冰壺二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','壺裏清冰冰裏人，箇邊無地可留塵。',32,'全唐诗/poet.song.139000.json','["壺裏清冰冰裏人，箇邊無地可留塵。", "何時去弄池中月，照我星星白髮新。"]'),
('a95ff1ec-3d1a-4188-b78c-b22eb4a89b3f','寄題王國華環秀樓二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','近山遠岫不知重，暖翠晴嵐只滿空。',32,'全唐诗/poet.song.139000.json','["近山遠岫不知重，暖翠晴嵐只滿空。", "珍重主人將好手，盡驅秀色入樓中。"]'),
('6d0193f4-ca82-4abf-81f1-24d4b52abcc1','寄題王國華環秀樓二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','平地看山山絕低，上樓山色逐層奇。',32,'全唐诗/poet.song.139000.json','["平地看山山絕低，上樓山色逐層奇。", "不知山與樓爭長，爲復樓隨山却移。"]'),
('7656191b-5aff-448b-9785-39a3bf1f3fb9','贈尚長道簽判','楊萬里','宋','宋诗','song-poetry','','[]','今代高人尚子平，風流文采舊家聲。',64,'全唐诗/poet.song.139000.json','["今代高人尚子平，風流文采舊家聲。", "合於玉笋班中立，却向紅蓮幕裏行。", "天色惱人渾欲雪，燭花照別若爲情。", "日邊已辦除書著，莫戀南樓秋月明。"]'),
('7ce0e707-06fc-4dc2-b377-6238acdf58b0','贈尚獻之','楊萬里','宋','宋诗','song-poetry','','[]','老鳳蒼然姿，雛鳳鏘然鳴。',120,'全唐诗/poet.song.139000.json','["老鳳蒼然姿，雛鳳鏘然鳴。", "一見渠父子，令人英氣生。", "大尚傲一世，不肯揖公卿。", "小尚刷羽毛，勢欲追風鵬。", "吾州八千士，下筆電雹聲。", "小尚灑墨汁，一笑萬人驚。", "姓名登天府，紙價高帝城。", "勗哉更摩厲，制勝在此行。", "相遭又相別，勿作兒女情。", "舟行得秀句，寄我增雙明。"]'),
('c30acf34-e853-4acb-b66f-2148f42e08ef','題陳叔虎繡梅花扇','楊萬里','宋','宋诗','song-poetry','','[]','指下生寒影，針端即化工。',24,'全唐诗/poet.song.139000.json','["指下生寒影，針端即化工。", "冰痕將雪點，不受燭光融。"]'),
('cb032311-0a99-4f61-b50d-01c9de9f1a84','和彭仲莊七言','楊萬里','宋','宋诗','song-poetry','','[]','向來年少今老翁，隨身不去只有窮。',160,'全唐诗/poet.song.139000.json','["向來年少今老翁，隨身不去只有窮。", "請君與我共看鏡，豈復平生冰雪容。", "秋霖暗天瘦日色，滿掇黄花當朝食。", "何人裹飯問子桑，窮裏逢君自爲客。", "空山凍吟只自奇，故人之外誰相知。", "今年相從豈不好，安得到老長追隨。", "喜君詩思未渠薄，秋後花鷹兔邊落。", "慚我短才澀欲無，霜餘冰澗流還涸。", "君游宣溪何日來，愁城封閉待君開。", "定知此行脫寒谷，領取陽春一併回。"]'),
('1db3cc17-e9d3-457d-a680-6482c639c7c1','胡季永挽詞二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','澹庵潜聖學，未許外人傳。',48,'全唐诗/poet.song.139000.json','["澹庵潜聖學，未許外人傳。", "門裏存衣鉢，吟邊可管弦。", "浣花宗武轡，儋耳小坡船。", "綠鬢成黄壤，從今更問天。"]'),
('f0ed9a3c-e9ea-4c66-9079-d0529c54bcf2','胡季永挽詞二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','一昨官都下，同時寄客間。',48,'全唐诗/poet.song.139000.json','["一昨官都下，同時寄客間。", "相從湖上寺，覽遍浙西山。", "駿足應千里，彪文未一斑。", "霜風吹病眼，老淚爲渠潸。"]'),
('4c6067da-0145-4c0f-87e7-4202cae50fda','送徐吉水解組造朝','楊萬里','宋','宋诗','song-poetry','','[]','我住南溪溪北涯，閉門草長不曾開。',64,'全唐诗/poet.song.139000.json','["我住南溪溪北涯，閉門草長不曾開。", "風窗只怪燈花喜，雪徑傳呼縣尹來。", "道是朝廷舉廉吏，如何江海尚遺才。", "西樞東觀俱知己，拜了除書却探梅。"]'),
('dc60bb6a-6350-495d-adb7-e93c0dfae288','寄題蕭民望扶疎堂二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','不栽繁杏試晴紅，不種垂楊拂暖茸。',32,'全唐诗/poet.song.139000.json','["不栽繁杏試晴紅，不種垂楊拂暖茸。", "堂下生涯無一物，月中脩竹雪中松。"]'),
('ed4fba2d-a32e-4b13-8320-3ae0a239f461','寄題蕭民望扶疎堂二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','株松箇竹已奇奇，那更扶疎蔭碧漪。',32,'全唐诗/poet.song.139000.json','["株松箇竹已奇奇，那更扶疎蔭碧漪。", "喚醒淵明千載夢，政緣瀘水一篇詩。"]'),
('b1c9952e-bcf3-4fbd-ae14-971b2e8f94ef','送奔醫時亨往攸縣省覲','楊萬里','宋','宋诗','song-poetry','','[]','雪恰來時子恰行，白雲飛邊雙眼明。',64,'全唐诗/poet.song.139000.json','["雪恰來時子恰行，白雲飛邊雙眼明。", "阿母幾年不相見，阿兄喚渠來作伴。", "探囊半粒黄金丹，湘南小兒開病顔。", "江西兩奔留不住，併被湘南奪將去。"]'),
('c91697f7-a7c4-4a4d-bb22-5f1e40797e92','晚步','楊萬里','宋','宋诗','song-poetry','','[]','半疋輕煙束翠山，一梳寒月印青天。',32,'全唐诗/poet.song.139000.json','["半疋輕煙束翠山，一梳寒月印青天。", "生憎野燒無端甚，直上高林杳靄邊。"]'),
('f8d559df-ce40-47d9-8242-80eb19174622','燈下讀山谷詩','楊萬里','宋','宋诗','song-poetry','','[]','天下無雙雙井黄，遺編猶作舊時香。',64,'全唐诗/poet.song.139000.json','["天下無雙雙井黄，遺編猶作舊時香。", "百年人物今安在，千載功名紙半張。", "使我詩篇如許好，關人身事亦何嘗。", "地爐火暖燈花喜，且只移家住醉鄉。"]'),
('39bc7699-a148-4ee9-8660-db3ffc69e8e8','題劉直卿崇蘭軒','楊萬里','宋','宋诗','song-poetry','','[]','風亦何須過，林仍不厭深。',48,'全唐诗/poet.song.139000.json','["風亦何須過，林仍不厭深。", "莫將春色眼，來看歲寒心。", "政坐香通國，端令佩滿襟。", "楚人更饒舌，得免世間尋。"]'),
('27720126-e450-4f6d-a31f-ee0e728572ae','寄題朱景元直節軒二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','見說幽居似渭川，一川脩竹雪霜寒。',32,'全唐诗/poet.song.139000.json','["見說幽居似渭川，一川脩竹雪霜寒。", "如何翦得蒼蒼玉，乞與誠齋作釣竿。"]'),
('bfc137c1-fe26-426a-ac20-efde49cb7d27','寄題朱景元直節軒二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','月到梢頭十倍明，風來葉底百分清。',32,'全唐诗/poet.song.139000.json','["月到梢頭十倍明，風來葉底百分清。", "儘言直節無人會，歲晚君看太瘦生。"]'),
('8ef818c5-62bb-4298-b660-cf13b92db7bd','和同年梁韶州寺丞次張寄詩','楊萬里','宋','宋诗','song-poetry','','["\u897f\u6e56"]','故人一別恰三年，誰與論詩更說禪。',64,'全唐诗/poet.song.139000.json','["故人一別恰三年，誰與論詩更說禪。", "忽報一麾官嶺外，寄來七字雪梅前。", "人惟南內班行舊，語带西湖山水鮮。", "安得對床吟至曉，旋烹山茗試溪泉。"]'),
('bf9df83d-c953-474c-a084-b75cbc33bab6','送永新杜宰解印還朝','楊萬里','宋','宋诗','song-poetry','','[]','去年摘山初弄兵，永新縣前戈劍腥。',96,'全唐诗/poet.song.139000.json','["去年摘山初弄兵，永新縣前戈劍腥。", "杜侯不持一寸鐵，閉閣堅卧民不驚。", "軍前米作山谷聚，木牛流馬安用許。", "但令綠林無點塵，何須爛額畫麒麟。", "紫皇急才宵不寐，斯人合著班行裏。", "速騎匹馬謁明光，夜來溪風吹玉霜。"]'),
('5f152d93-eb6f-48aa-bfa1-eab970633c31','探梅','楊萬里','宋','宋诗','song-poetry','','[]','山間幽步不勝奇，政是深寒淺暮時。',32,'全唐诗/poet.song.139000.json','["山間幽步不勝奇，政是深寒淺暮時。", "一樹梅花開一朶，惱人偏在最高枝。"]'),
('db3cc898-0176-40cd-9113-ef9db2cad6b0','霜夜','楊萬里','宋','宋诗','song-poetry','','[]','月影全無只有星，如何夜色照人清。',32,'全唐诗/poet.song.139000.json','["月影全無只有星，如何夜色照人清。", "素娥未必饒青女，不道霜明勝月明。"]'),
('956c78af-51b3-406b-8bec-d6c838390ff6','月下梅花','楊萬里','宋','宋诗','song-poetry','','[]','天恐梅花不耐寒，遣將孤月問平安。',32,'全唐诗/poet.song.139000.json','["天恐梅花不耐寒，遣將孤月問平安。", "未須一夜都開盡，留取前前後後看。"]'),
('0ca72dc4-ca74-4525-a661-ff45a46855e7','訪周仲覺夜宿南嶺月色粲然曉起路濕聞有夜雨','楊萬里','宋','宋诗','song-poetry','','[]','夜晴那得曉來泥，纔見金鉦浴紺池。',32,'全唐诗/poet.song.139000.json','["夜晴那得曉來泥，纔見金鉦浴紺池。", "一陣五更松上雨，元來睡著不曾知。"]'),
('c03ec2e6-1b0a-42e9-9d1b-dfa7125d6f38','過西坑','楊萬里','宋','宋诗','song-poetry','','[]','乾風無那濕雲何，吹不能開只助他。',32,'全唐诗/poet.song.139000.json','["乾風無那濕雲何，吹不能開只助他。", "野水落溪生蟹眼，一番過了一番多。"]'),
('7b4f77dc-e585-4e06-97dc-6e0b62a2850f','觀陂水','楊萬里','宋','宋诗','song-poetry','','[]','波緩漚遲似讓行，忽然赴壑怒還生。',32,'全唐诗/poet.song.139000.json','["波緩漚遲似讓行，忽然赴壑怒還生。", "東歸到底誰先後，何用爭流作許聲。"]'),
('be96d6f6-02f0-41ec-97d8-dc99caf73715','劉村渡二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','隔岸輕舟不可呼，小橋獨木有如無。',32,'全唐诗/poet.song.139000.json','["隔岸輕舟不可呼，小橋獨木有如無。", "落松滿地金釵瘦，遠樹黏天菌子孤。"]'),
('daab6c5b-c16a-4cc5-bcab-ae9c4e26d767','劉村渡二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','曠野風從脚底生，遠峰頂與額般平。',32,'全唐诗/poet.song.139000.json','["曠野風從脚底生，遠峰頂與額般平。", "何人知道誠齋叟，獨著駝裘破雨行。"]'),
('4e61fb86-9e94-449d-8ac8-374274bbd4f7','晚歸遇雨','楊萬里','宋','宋诗','song-poetry','','[]','略略煙痕草許低，初初雨影傘先知。',32,'全唐诗/poet.song.139000.json','["略略煙痕草許低，初初雨影傘先知。", "溪回谷轉愁無路，忽有梅花一兩枝。"]'),
('18b1a99e-38b3-4fe0-8b93-1435ab560632','和閩漕傅安道郎中送毛平仲詩韻寄謝惠書及詩','楊萬里','宋','宋诗','song-poetry','','[]','宣城訊後忽年餘，閩水風來又歲除。',64,'全唐诗/poet.song.139000.json','["宣城訊後忽年餘，閩水風來又歲除。", "人品只今推正始，詩聲何止過黄初。", "豈無天上同朝友，不寄山中半紙書。", "珍重故人多問我，鬢毛半脫齒全疎。"]'),
('624b096b-5e86-44d5-aefa-f2637f5e06eb','丁酉初春和張欽夫榕溪閣五言','楊萬里','宋','宋诗','song-poetry','','[]','榕影下照水，翠蛟舒復樛。',156,'全唐诗/poet.song.139000.json','["榕影下照水，翠蛟舒復樛。", "溪光逆昇簷，朱夏凍以幽。", "高閣昔雨荒，奇觀久風休。", "南軒天遣來，山谷神與謀。", "宇新址惟舊，景逝人爲留。", "不意猿飲潭，復見駟駕輈。", "先生何孤往，野客欠從游。", "願携龍文璧，去瀹兔褐甌。", "垂手掬寒泚，移床聽涼颼。", "閣迥詩更超，古往今亦猶。", "攬渠五字妙，覺我百疾瘳。", "出山未遽誤，在山未遽優。", "如何近來夢，夜夜在釣舟。"]'),
('39f837b4-c8b1-41b0-a8a2-00b3726ae371','曾達臣挽詞二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','珠凍蘭溪水，冰封玉笥山。',48,'全唐诗/poet.song.139000.json','["珠凍蘭溪水，冰封玉笥山。", "是翁元不死，蛻骨此中間。", "書畫今存否，儀刑杳莫攀。", "端令郡博士，陟岵淚斑斑。"]'),
('98e98f87-ac05-491e-b73e-ecb5f634c5dd','曾達臣挽詞二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','議論千千古，胸懷一一奇。',48,'全唐诗/poet.song.139000.json','["議論千千古，胸懷一一奇。", "非關時棄我，不肯我干時。", "老鶴雲間意，長松雪外姿。", "平生獨知命，冷眼看人癡。"]'),
('885f95f7-ba80-4f08-b62c-a3e6596aa68e','題劉景明百牛圖扇面','楊萬里','宋','宋诗','song-poetry','','[]','吉語聞田父，新年勝故年。',24,'全唐诗/poet.song.139000.json','["吉語聞田父，新年勝故年。", "借儂百觳觫，雨裏破荒田。"]'),
('08a2a83c-2ce6-40a5-9fb5-7e34bdc895e9','題劉景明百馬圖扇面','楊萬里','宋','宋诗','song-poetry','','[]','霧鬣如無筆，霜蹄不带埃。',24,'全唐诗/poet.song.139000.json','["霧鬣如無筆，霜蹄不带埃。", "直言明眼著，若箇是龍媒。"]'),
('18a60adc-346f-4323-9cf7-767886efdfd7','題鄧國材水墨寒林','楊萬里','宋','宋诗','song-poetry','','[]','人間那得箇山川，船上漁郎便是仙。',32,'全唐诗/poet.song.139000.json','["人間那得箇山川，船上漁郎便是仙。", "遠嶺外頭江盡處，問渠何許洞中天。"]'),
('c3babaa6-66a1-4af7-9736-a2c70d9d1484','春寒絕句','楊萬里','宋','宋诗','song-poetry','','[]','幾絲微雨噀前山，半點輕寒健牡丹。',32,'全唐诗/poet.song.139000.json','["幾絲微雨噀前山，半點輕寒健牡丹。", "只道一春晴較少，到它晴了是春殘。"]'),
('5ad0d9d3-767b-4961-af73-99a413676cf6','雨中酴醾','楊萬里','宋','宋诗','song-poetry','','[]','翡翠堆頭亂不梳，梅花腦子糝肌膚。',32,'全唐诗/poet.song.139000.json','["翡翠堆頭亂不梳，梅花腦子糝肌膚。", "夜來急雨元無事，曉起看花一片無。"]'),
('5fab09c8-7864-4863-9bea-b5695f2e8fb3','晚春即事二絕  其一','楊萬里','宋','宋诗','song-poetry','','[]','尺許新條長杏栽，丈餘斑笋出牆隈。',32,'全唐诗/poet.song.139000.json','["尺許新條長杏栽，丈餘斑笋出牆隈。", "浪愁草草酴醾過，不道婷婷芍藥來。"]'),
('ca0a57cd-1b57-4922-817e-fbd39685078d','晚春即事二絕  其二','楊萬里','宋','宋诗','song-poetry','','[]','樹頭吹得葉冥冥，三日顛風不小停。',32,'全唐诗/poet.song.139000.json','["樹頭吹得葉冥冥，三日顛風不小停。", "只是向來枯樹子，知他那得許多青。"]'),
('6983cb66-01b7-41f8-ba3f-be0b5fca5c84','寄題鄒虞卿覿仙閣','楊萬里','宋','宋诗','song-poetry','','[]','仙山去天纔一握，與山相高鄒氏閣。',64,'全唐诗/poet.song.139000.json','["仙山去天纔一握，與山相高鄒氏閣。", "月波吹面寒欲冰，斗柄掛簷危不落。", "葉縣雙鳬那復飛，緱山一鶴何時歸。", "王仙肯來閣上否，共絲麟脯傾天酒。"]'),
('cccbec7a-6fbd-475f-a8a0-30730be92eec','入城','楊萬里','宋','宋诗','song-poetry','','[]','杜鵑有底怨春啼，燕子無端貼水飛。',32,'全唐诗/poet.song.139000.json','["杜鵑有底怨春啼，燕子無端貼水飛。", "不種自紅仍自白，野酴醾壓野薔薇。"]'),
('095606a1-940f-4808-9fb6-8c632ef9016e','永和放船二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','永和不到又經秋，淡日微風好放舟。',32,'全唐诗/poet.song.139000.json','["永和不到又經秋，淡日微風好放舟。", "最是可憐江上路，人來人去幾時休。"]'),
('fe52eb0e-97f4-4646-99f4-5854410b35af','永和放船二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','瀕江樓閣祇遥看，却恐登臨不足觀。',32,'全唐诗/poet.song.139000.json','["瀕江樓閣祇遥看，却恐登臨不足觀。", "已是老來無眼力，更供兩岸萬峰寒。"]'),
('b058aac9-824e-460b-8296-9e1a930bb0e9','丁酉四月十日之官毗陵舟行阻風宿椆陂江口二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','蟲聲兩岸不堪聞，把燭銷愁且一尊。',32,'全唐诗/poet.song.139000.json','["蟲聲兩岸不堪聞，把燭銷愁且一尊。", "誰宿此船愁似我，船篷猶带燭煙痕。"]'),
('db6af640-58ae-4c3e-9edd-82004c2546b2','丁酉四月十日之官毗陵舟行阻風宿椆陂江口二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','十里江行一日程，出山似被北風嗔。',32,'全唐诗/poet.song.139000.json','["十里江行一日程，出山似被北風嗔。", "東窗水影西窗月，併照船中不睡人。"]'),
('678363da-82ba-40f8-b02d-878999e8918e','舟次西徑','楊萬里','宋','宋诗','song-poetry','','[]','夜來徐汊伴鷗眠，西徑晨炊小泊船。',32,'全唐诗/poet.song.139000.json','["夜來徐汊伴鷗眠，西徑晨炊小泊船。", "蘆荻漸多人漸少，鄱陽湖尾水如天。"]'),
('eae34ba5-1d16-4ab8-b43b-a0c810733fcc','餘干泝流至安仁','楊萬里','宋','宋诗','song-poetry','','[]','半篙新漲滿帆風，兩岸千山一抹中。',32,'全唐诗/poet.song.139000.json','["半篙新漲滿帆風，兩岸千山一抹中。", "慚媿櫂郎能袖手，若非袖手更無功。"]'),
('2518194a-e2d3-416e-a415-15ba70e8af88','宿小沙溪  其一','楊萬里','宋','宋诗','song-poetry','','[]','樹捧山煙補缺雲，風揉花雨作香塵。',32,'全唐诗/poet.song.139000.json','["樹捧山煙補缺雲，風揉花雨作香塵。", "綠楊儘道無情著，何苦垂條拂路人。"]'),
('d1874b58-1f52-4c89-a219-5b470c4d1c2b','宿小沙溪  其二','楊萬里','宋','宋诗','song-poetry','','[]','諸峰知我厭泥行，捲盡癡雲放嫩晴。',32,'全唐诗/poet.song.139000.json','["諸峰知我厭泥行，捲盡癡雲放嫩晴。", "不分竹梢含宿雨，時將殘點滴寒聲。"]'),
('b84fa514-6b7e-4b3d-942b-735c2b8fe6dc','玉山道中','楊萬里','宋','宋诗','song-poetry','','[]','村北村南水響齊，巷頭巷尾樹陰低。',32,'全唐诗/poet.song.139000.json','["村北村南水響齊，巷頭巷尾樹陰低。", "青山自負無塵色，盡日殷勤照碧溪。"]'),
('db15a125-15fd-4c85-b7d1-365560b4e6a8','入常山界二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','老隨千騎赴毗陵，騎吏朝來有喜聲。',32,'全唐诗/poet.song.139000.json','["老隨千騎赴毗陵，騎吏朝來有喜聲。", "未到常山三十里，此身已在浙中行。"]'),
('cce85374-37bf-40d8-805b-5e80d7610246','入常山界二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','昨日愁霖今喜晴，好山夾路玉亭亭。',32,'全唐诗/poet.song.139000.json','["昨日愁霖今喜晴，好山夾路玉亭亭。", "一峰忽被雲偷去，留得崢嶸半截青。"]'),
('1ead7f37-7d73-4c7f-bf8e-054eab6a1bf1','小憩栟楮','楊萬里','宋','宋诗','song-poetry','','[]','笋輿放下倦騰騰，睡倚胡床撼不應。',32,'全唐诗/poet.song.139000.json','["笋輿放下倦騰騰，睡倚胡床撼不應。", "櫸柳細花吹面落，誤揮團扇撲飛蠅。"]'),
('5a3d43c2-1f8a-4885-84b4-971111d1db8e','過招賢渡四首  其一','楊萬里','宋','宋诗','song-poetry','','[]','歸舟曾被此灘留，說著招賢夢亦愁。',32,'全唐诗/poet.song.139000.json','["歸舟曾被此灘留，說著招賢夢亦愁。", "五月雪飛人不信，一來灘下看濤頭。"]'),
('21ff3f43-fbdf-4b52-8569-5e1feda2155d','過招賢渡四首  其二','楊萬里','宋','宋诗','song-poetry','','[]','一江故作兩江分，立殺呼船隔岸人。',32,'全唐诗/poet.song.139000.json','["一江故作兩江分，立殺呼船隔岸人。", "柳上青蟲寧許劣，垂絲到地却回身。"]'),
('601d6633-b5e7-4934-a926-57638b1fa501','過招賢渡四首  其三','楊萬里','宋','宋诗','song-poetry','','[]','倦游客子自無聊，不是江山景不饒。',32,'全唐诗/poet.song.139000.json','["倦游客子自無聊，不是江山景不饒。", "危岸崩沙新改路，斷渠橫石自成橋。"]'),
('8fbd1ddb-8423-4395-898e-d2786b40d65e','過招賢渡四首  其四','楊萬里','宋','宋诗','song-poetry','','[]','岸上行人莫嘆勞，長年三老政呼號。',32,'全唐诗/poet.song.139000.json','["岸上行人莫嘆勞，長年三老政呼號。", "也知灘惡船難上，仰踏桅竿卧著篙。"]'),
('b29e9bf0-235c-42aa-9762-2a3fafe7393f','苕溪登舟','楊萬里','宋','宋诗','song-poetry','','[]','深於池沼淺於河，動地風來也不波。',32,'全唐诗/poet.song.139000.json','["深於池沼淺於河，動地風來也不波。", "只道東來行役苦，胡床面面是菱荷。"]'),
('31886b34-08d1-4db6-a5c5-5cec9afb770a','舟過德清','楊萬里','宋','宋诗','song-poetry','','[]','人家兩岸柳陰邊，出得門來便入船。',32,'全唐诗/poet.song.139000.json','["人家兩岸柳陰邊，出得門來便入船。", "不是全無最佳處，何窗何戶不清妍。"]'),
('d0bb2297-42a8-4ac7-9c31-997e35c9adee','舟泊吳江三首  其一','楊萬里','宋','宋诗','song-poetry','','[]','獨立吳江第四橋，橋南橋北渺銀濤。',32,'全唐诗/poet.song.139000.json','["獨立吳江第四橋，橋南橋北渺銀濤。", "此身真在吳江裏，不用并州快剪刀。"]'),
('74bbf54d-2792-4344-9fff-3f7b3c6f132a','舟泊吳江三首  其二','楊萬里','宋','宋诗','song-poetry','','[]','江湖便是老生涯，佳處何妨且泊家。',32,'全唐诗/poet.song.139000.json','["江湖便是老生涯，佳處何妨且泊家。", "自汲松江橋下水，垂虹亭上試新茶。"]'),
('f3c09968-d7d9-4ad1-9fe6-3c621a92aa71','舟泊吳江三首  其三','楊萬里','宋','宋诗','song-poetry','','["\u592a\u6e56"]','東是吳江西太湖，長橋橫截萬尋餘。',32,'全唐诗/poet.song.139000.json','["東是吳江西太湖，長橋橫截萬尋餘。", "江妃舞倦凌波襪，玉带圍腰攬鏡初。"]'),
('2970d7eb-1d49-43fe-a057-75770ef87051','七月十四日雨後毗陵郡圃荷橋上納凉','楊萬里','宋','宋诗','song-poetry','','[]','荷葉迎風聽，荷花過雨看。',24,'全唐诗/poet.song.139000.json','["荷葉迎風聽，荷花過雨看。", "移床橋上坐，墮我鏡中寒。"]'),
('fcdd2305-179d-4729-aea2-4309ffb944a9','暮立荷橋','楊萬里','宋','宋诗','song-poetry','','[]','欲問紅蕖幾莟開，忽驚浴罷夕陽催。',32,'全唐诗/poet.song.139000.json','["欲問紅蕖幾莟開，忽驚浴罷夕陽催。", "也知今夕來差晚，猶勝窮忙不到來。"]'),
('b0a107d9-c090-4310-bd94-b08147d5a191','秋熱追凉池上','楊萬里','宋','宋诗','song-poetry','','[]','圃迥人全寂，池清慮自消。',48,'全唐诗/poet.song.139000.json','["圃迥人全寂，池清慮自消。", "萍根微著水，荷葉欲穿橋。", "今歲知何故，秋陽爾許驕。", "追涼猶有處，此老未無聊。"]'),
('3f540054-5f1a-431e-a879-767b3f8ab95f','秋凉晚步','楊萬里','宋','宋诗','song-poetry','','["\u79cb\u5929", "\u6292\u6000", "\u5199\u666f"]','秋氣堪悲未必然，輕寒政是可人天。',32,'全唐诗/poet.song.139000.json','["秋氣堪悲未必然，輕寒政是可人天。", "綠池落盡紅蕖却，荷葉猶開最小錢。"]'),
('c3aec4d4-b195-4d67-8942-bb483e38cba8','毗陵郡齋冬至晴寒','楊萬里','宋','宋诗','song-poetry','','[]','竹屋消殘半瓦霜，冰河凍裂一漁航。',32,'全唐诗/poet.song.139000.json','["竹屋消殘半瓦霜，冰河凍裂一漁航。", "不須宮線量曦影，化日今年特地長。"]'),
('17a003dd-4c7d-44a8-b1b2-036501c5d6fe','蠟梅','楊萬里','宋','宋诗','song-poetry','','[]','天向梅梢別出奇，國香未許世人知。',32,'全唐诗/poet.song.139000.json','["天向梅梢別出奇，國香未許世人知。", "殷勤滴蠟緘封却，偷被霜風拆一枝。"]'),
('4e47dcda-fc3e-45ae-903a-d4fcb9bd878f','登浄遠亭','楊萬里','宋','宋诗','song-poetry','','[]','池冰受日未全開，旋旋波痕百皺來。',32,'全唐诗/poet.song.139000.json','["池冰受日未全開，旋旋波痕百皺來。", "野鴨被人驚得慣，作羣飛去却飛回。"]'),
('86d1ffb3-c398-4f8d-8911-82fe6878dea1','戊戌正月二日雪作二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','雪與新春作伴回，擣霜爲片雹爲埃。',32,'全唐诗/poet.song.139000.json','["雪與新春作伴回，擣霜爲片雹爲埃。", "只愁雪虐梅無奈，不道梅花領雪來。"]'),
('3cedcf76-8bb8-44b1-835a-f8ddd06bcfbc','戊戌正月二日雪作二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','夢回紙帳怪生寒，童子傳呼雪作團。',32,'全唐诗/poet.song.139000.json','["夢回紙帳怪生寒，童子傳呼雪作團。", "已被曉風融作水，頭巾不裹起來看。"]'),
('89a2369f-8d64-4ca3-a080-e4638025d514','戲題郡齋水墨坐屏二面二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','兩客呼船一急行，樹林半落半猶青。',32,'全唐诗/poet.song.139000.json','["兩客呼船一急行，樹林半落半猶青。", "諸峰最是中峰好，我欲峰頭築小亭。"]'),
('35acfa61-29ad-4555-a9d9-ad90f0729900','戲題郡齋水墨坐屏二面二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','荆溪四面四無山，不是荒林即野田。',32,'全唐诗/poet.song.139000.json','["荆溪四面四無山，不是荒林即野田。", "忽有石崖天半出，飛泉落處稍人煙。"]'),
('cbd06755-cb6b-437b-96f4-1b02b423c909','郡圃小梅一枝先開','楊萬里','宋','宋诗','song-poetry','','[]','小窠梅樹太尖新，先爲東風覓得春。',32,'全唐诗/poet.song.139000.json','["小窠梅樹太尖新，先爲東風覓得春。", "後日千株空玉雪，如今一朶許精神。"]'),
('44fb8b3e-a8e4-4aa5-ae39-9b36daabe437','戲贈子仁姪','楊萬里','宋','宋诗','song-poetry','','[]','小阮新來覓句忙，自携破硯汲寒江。',32,'全唐诗/poet.song.139000.json','["小阮新來覓句忙，自携破硯汲寒江。", "天公念子抄詩苦，借與朝陽小半窗。"]'),
('db31d5af-52ca-4cf0-8765-7e7bf01fae49','浄遠亭晚望','楊萬里','宋','宋诗','song-poetry','','[]','鸂鶒嬌紅野鴨青，爲人浮沒爲人鳴。',32,'全唐诗/poet.song.139000.json','["鸂鶒嬌紅野鴨青，爲人浮沒爲人鳴。", "忽聞風起仍波起，乃是飛聲與落聲。"]'),
('c18c1c95-5025-494d-86bc-b4714e33c2ac','郡齋梅花','楊萬里','宋','宋诗','song-poetry','','[]','月朶千痕雪半梢，便無雪月更飄蕭。',32,'全唐诗/poet.song.139000.json','["月朶千痕雪半梢，便無雪月更飄蕭。", "不應臘尾春頭裏，兩歲風光一併饒。"]'),
('d8d35f4d-4cca-4513-8ec0-7fee463e01e7','雪後尋梅','楊萬里','宋','宋诗','song-poetry','','[]','去年看梅南溪北，月作主人梅作客。',128,'全唐诗/poet.song.139000.json','["去年看梅南溪北，月作主人梅作客。", "今年看梅荆溪西，玉爲風骨雪爲衣。", "臘前欲雪竟未雪，梅花不慣人間熱。", "橫枝憔悴涴晴埃，端令羞面不肯開。", "縞裙夜訴玉皇殿，乞得天花來作伴。", "三更滕六駕海神，先遣東風吹玉塵。", "梅仙曉沐銀浦水，冰膚別放瑶林春。", "詩人莫作雪前看，雪後精神添一半。"]'),
('04f15994-fb26-4799-8ae3-e17327c4ef89','雪霽出城','楊萬里','宋','宋诗','song-poetry','','[]','梅於雪後較多花，草亦晴初忽幾芽。',32,'全唐诗/poet.song.139000.json','["梅於雪後較多花，草亦晴初忽幾芽。", "河凍落痕餘一寸，殘冰閣在柳根沙。"]'),
('e479184c-0b4d-4c0b-8843-103f55e4dca0','正月十九日五更詣天慶觀謝雪聞都下尺雪旬日而毗陵三四微雪而已','楊萬里','宋','宋诗','song-poetry','','[]','元宵風物又闌殘，閉閣何曾出一看。',64,'全唐诗/poet.song.139000.json','["元宵風物又闌殘，閉閣何曾出一看。", "尚覺燭光欺病眼，旋添衣著試春寒。", "中都尺雪逾旬許，此地飛花逐片乾。", "不待珠宮香火了，海風吹上紫金盤。"]'),
('9ac51670-b025-4c9e-a631-e4e39b747ceb','雪中看梅','楊萬里','宋','宋诗','song-poetry','','[]','犯雪尋梅雪滿衣，池邊梅映竹邊池。',32,'全唐诗/poet.song.139000.json','["犯雪尋梅雪滿衣，池邊梅映竹邊池。", "要尋疎影橫斜底，揀盡南枝與北枝。"]'),
('2f127fb1-d2b5-4205-b774-ab564d49382a','梅花','楊萬里','宋','宋诗','song-poetry','','[]','花早春何力，香寒曉儘吹。',24,'全唐诗/poet.song.139000.json','["花早春何力，香寒曉儘吹。", "月摇橫水影，雪带入瓶枝。"]'),
('4c750478-c40b-467c-b3ad-249730349354','春夢紛紜','楊萬里','宋','宋诗','song-poetry','','[]','燭花半作紫芝開，詩興頻遭白雨催。',32,'全唐诗/poet.song.139000.json','["燭花半作紫芝開，詩興頻遭白雨催。", "只有睡時愁可遣，春愁又向夢中來。"]'),
('4d350b61-1928-4c8a-9395-a930f8f9b108','二月一日郡圃尋春二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','中和節裏半春天，一拂清寒半點暄。',32,'全唐诗/poet.song.139000.json','["中和節裏半春天，一拂清寒半點暄。", "憔悴不勝梅欲落，嬌饒無對杏初繁。"]'),
('bfe25c0f-a9aa-4570-82d5-b47e448460ef','二月一日郡圃尋春二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','花遶朱簷柳遶欄，小亭面面錦團欒。',32,'全唐诗/poet.song.139000.json','["花遶朱簷柳遶欄，小亭面面錦團欒。", "春風橫欲欺詩瘦，且下東窗護嫩寒。"]'),
('e2b2cac9-73af-49b1-9870-9a7fae945c6b','梅殘','楊萬里','宋','宋诗','song-poetry','','[]','雪已都消去，梅能小住無。',24,'全唐诗/poet.song.139000.json','["雪已都消去，梅能小住無。", "雀爭飛落片，蜂獵未蔫鬚。"]'),
('19bf2b99-7e55-4c7b-b28f-ab2c0d316f19','寒夜不寐','楊萬里','宋','宋诗','song-poetry','','[]','雪入迎春鬢，茶醒學古胸。',24,'全唐诗/poet.song.139000.json','["雪入迎春鬢，茶醒學古胸。", "夢回霜滿屋，吟到月斜鐘。"]'),
('08bd3484-1394-4f7c-95d8-bfd5611117e5','新柳','楊萬里','宋','宋诗','song-poetry','','[]','輦路金絲半欲垂，外間玉爪未渠開。',32,'全唐诗/poet.song.139000.json','["輦路金絲半欲垂，外間玉爪未渠開。", "上林柳色休多憶，更趁春風看一回。"]'),
('de23ea9d-7910-4244-9d1b-b7674cacf5bc','小飲俎豆頗備江西淮浙之品戲題二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','滿盤山海眩芳珍，未借前籌已嚥津。',32,'全唐诗/poet.song.139000.json','["滿盤山海眩芳珍，未借前籌已嚥津。", "鱟醤子魚總佳客，玉狸黄雀是鄉人。"]'),
('dfde2dfe-aa25-4e6e-8695-885a07abd479','小飲俎豆頗備江西淮浙之品戲題二首  其二','楊萬里','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','味含霜氣洞庭柑，鮓带桃花楚水𧍧。',32,'全唐诗/poet.song.139000.json','["味含霜氣洞庭柑，鮓带桃花楚水𧍧。", "春暖著人君會否，不教淮白過江南。"]'),
('cab5272d-7960-4698-8f98-4a70a9512984','雨霽','楊萬里','宋','宋诗','song-poetry','','[]','雨爲梅花遣盡塵，柳勾日影自傳神。',32,'全唐诗/poet.song.139000.json','["雨爲梅花遣盡塵，柳勾日影自傳神。", "不須苦問春多少，暖幕晴簾總是春。"]'),
('e9217753-4065-45dc-ab20-bf654af6388e','蜜漬梅花','楊萬里','宋','宋诗','song-poetry','','[]','甕澄雪水釀春寒，蜜點梅花带露餐。',32,'全唐诗/poet.song.139000.json','["甕澄雪水釀春寒，蜜點梅花带露餐。", "句裏略無煙火氣，更教誰上少陵壇。"]'),
('d8e7e3d4-1438-4962-b969-a98be4b32156','感興','楊萬里','宋','宋诗','song-poetry','','[]','看書已怯短檠燈，覓句猶鏘澗水聲。',32,'全唐诗/poet.song.139000.json','["看書已怯短檠燈，覓句猶鏘澗水聲。", "詩瘦近來惟有骨，可憐辛苦爲虛名。"]'),
('02279f95-fa87-4931-8e10-597b61135df7','春暖郡圃散策三首  其一','楊萬里','宋','宋诗','song-poetry','','[]','已覺朝來退裌衣，日光風力軟如癡。',32,'全唐诗/poet.song.139000.json','["已覺朝來退裌衣，日光風力軟如癡。", "倩誰留許春寒著，更放梅花住少時。"]'),
('7303d1a2-73c0-4d43-9a97-c37c92b073d9','春暖郡圃散策三首  其二','楊萬里','宋','宋诗','song-poetry','','[]','萱草行間過履絇，杏花影裏散文書。',32,'全唐诗/poet.song.139000.json','["萱草行間過履絇，杏花影裏散文書。", "秋風遣我疎團扇，又被春風遣喚渠。"]'),
('28fb06f9-7fc1-4eb1-92b9-98851308ca59','春暖郡圃散策三首  其三','楊萬里','宋','宋诗','song-poetry','','[]','春禽處處講新聲，細草欣欣賀嫩晴。',32,'全唐诗/poet.song.139000.json','["春禽處處講新聲，細草欣欣賀嫩晴。", "曲折遍穿花底路，莫令一步作虛行。"]'),
('eb6c46b7-2855-4a4d-b1fe-9ae0cfee1160','休日登城','楊萬里','宋','宋诗','song-poetry','','[]','愛他休日更新晴，忍却春寒上古城。',32,'全唐诗/poet.song.139000.json','["愛他休日更新晴，忍却春寒上古城。", "廢壘荒蘆無一好，春來微徑總堪行。"]'),
('52c8739e-81b8-4d99-8daf-1394d6f25c08','浄遠亭午望二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','城外春光染遠山，池中嫩水漲微瀾。',32,'全唐诗/poet.song.139000.json','["城外春光染遠山，池中嫩水漲微瀾。", "回身小却深簷裏，野鴨雙浮欲近欄。"]'),
('938f4455-878e-4576-9873-9e1a997c778f','浄遠亭午望二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','竹逕殊疎欠補栽，蘭芽欲吐未全開。',32,'全唐诗/poet.song.139000.json','["竹逕殊疎欠補栽，蘭芽欲吐未全開。", "初暄乍冷飛猶倦，一蝶新從底處來。"]'),
('7c99e037-8242-48e9-ae41-2107133b8797','池亭雙樹梅花','楊萬里','宋','宋诗','song-poetry','','[]','開盡梅花半欲殘，兩株晴雪作雙寒。',32,'全唐诗/poet.song.139000.json','["開盡梅花半欲殘，兩株晴雪作雙寒。", "團欒遶樹元無見，只合池亭隔水看。"]'),
('52973aeb-4ce3-468a-a91d-b2a2b74fd188','多稼亭前小步','楊萬里','宋','宋诗','song-poetry','','[]','櫻桃拋過隔牆莟，芍藥叢抽刺土芽。',32,'全唐诗/poet.song.139000.json','["櫻桃拋過隔牆莟，芍藥叢抽刺土芽。", "最是蜜蜂無意思，忍將塵脚踏梅花。"]'),
('5b3b3d67-8704-437d-90d4-8a91d0b156e0','多稼亭宴客','楊萬里','宋','宋诗','song-poetry','','[]','歸來不省醉還醒，只怪譙門打一更。',32,'全唐诗/poet.song.139000.json','["歸來不省醉還醒，只怪譙門打一更。", "秉燭徑穿梅下過，此身真在雪中行。"]'),
('9be4ff19-5cfa-4981-b099-762b8a4f3c3d','燒香七言','楊萬里','宋','宋诗','song-poetry','','[]','琢瓷作鼎碧於水，削銀爲葉輕如紙。',96,'全唐诗/poet.song.139000.json','["琢瓷作鼎碧於水，削銀爲葉輕如紙。", "不文不武火力勻，閉閣下簾風不起。", "詩人自炷古龍涎，但令有香不見煙。", "素馨忽開抹利拆，低處龍麝和沉檀。", "平生飽識山林味，不奈此香殊娬媚。", "呼兒急取烝木犀，却作書生真富貴。"]'),
('a3dc5d0d-70cf-4619-a6cf-21a73c67b779','讀嚴子陵傳','楊萬里','宋','宋诗','song-poetry','','[]','客星何補漢中興，空有清風冷似冰。',32,'全唐诗/poet.song.139000.json','["客星何補漢中興，空有清風冷似冰。", "早遣阿瞞移漢鼎，人間何處有嚴陵。"]'),
('42337750-54c8-4617-81ca-0c4824daa4a0','題山莊小集','楊萬里','宋','宋诗','song-poetry','','[]','莫笑山莊小集休，篇篇字字爽於秋。',32,'全唐诗/poet.song.139000.json','["莫笑山莊小集休，篇篇字字爽於秋。", "向來楓落吳江冷，一句能銷萬古愁。"]'),
('8f63ddc0-88be-42db-8351-0bade9330532','春寒','楊萬里','宋','宋诗','song-poetry','','[]','春寒儘解粟人膚，敢傍吾儕酒盞無。',32,'全唐诗/poet.song.139000.json','["春寒儘解粟人膚，敢傍吾儕酒盞無。", "雨裏杏花如半醉，擡頭不起索人扶。"]'),
('dbdef512-45b2-480c-b28e-57cdaf14c210','瓶中梅杏二花','楊萬里','宋','宋诗','song-poetry','','[]','梅花耿耿冰玉姿，杏花淡淡注燕脂。',64,'全唐诗/poet.song.139000.json','["梅花耿耿冰玉姿，杏花淡淡注燕脂。", "兩花相嬌不相下，各向春風同索價。", "折來雙插一銅瓶，旋汲井花澆使醒。", "紅紅白白看不足，更遣山童燒蠟燭。"]'),
('988540c9-c52c-45f7-af25-b954a1214db7','書齋夜坐二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','棐几吹燈丈室虛，隔窗雨點響階除。',32,'全唐诗/poet.song.139000.json','["棐几吹燈丈室虛，隔窗雨點響階除。", "胡床枕手昏昏著，卧聽兒童讀漢書。"]'),
('bac6e95b-140e-4c09-b665-f4eefee87882','書齋夜坐二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','酒力欺人正作眠，夢中得句忽醒然。',32,'全唐诗/poet.song.139000.json','["酒力欺人正作眠，夢中得句忽醒然。", "寒生更點當當裏，雨在梅花蔌蔌邊。"]'),
('89caf2f3-590b-4fae-8851-189f727ba7ab','瑞香花二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','織錦天孫矮作機，紫茸翻出白花枝。',32,'全唐诗/poet.song.139000.json','["織錦天孫矮作機，紫茸翻出白花枝。", "更將沈水濃薰却，日淡風微欲午時。"]'),
('411f4d86-285d-44e7-bc9e-9d5894fcdd17','瑞香花二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','樹如巖桂不勝低，花比素馨幽更奇。',32,'全唐诗/poet.song.139000.json','["樹如巖桂不勝低，花比素馨幽更奇。", "要作團欒小窠錦，春風不長出叢枝。"]'),
('150a632c-dc58-462a-a51c-5fbd795a79f5','二月十四日梅花二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','雨打知無那，春暄絕不禁。',24,'全唐诗/poet.song.139000.json','["雨打知無那，春暄絕不禁。", "小風千點雪，落日一鬚金。"]');
